APP_NAME = "Jarvis"


def _is_frozen_app() -> bool:

    return bool(getattr(sys, "frozen", False))


def _app_source_base_dir() -> str:

    try:

        return os.path.dirname(os.path.abspath(__file__))

    except Exception:

        return os.getcwd()


def _app_resource_base_dir() -> str:

    bundle_base = str(getattr(sys, "_MEIPASS", "") or "").strip()

    if bundle_base:

        return os.path.normpath(bundle_base)

    return _app_source_base_dir()


def _app_resource_path(*parts: object) -> str:

    clean_parts = [str(part).strip().strip("\\/") for part in parts if str(part or "").strip()]

    return os.path.normpath(os.path.join(_app_resource_base_dir(), *clean_parts))


def _app_user_data_dir() -> str:

    if not _is_frozen_app():

        return _app_source_base_dir()

    base = str(os.getenv("APPDATA", "") or "").strip()

    if not base:

        base = os.path.join(os.path.expanduser("~"), "AppData", "Roaming")

    return os.path.normpath(os.path.join(base, APP_NAME))


def _ensure_app_user_data_dir() -> str:

    path = _app_user_data_dir()

    try:

        os.makedirs(path, exist_ok=True)

    except Exception:

        pass

    return path


def _app_user_data_path(*parts: object) -> str:

    clean_parts = [str(part).strip().strip("\\/") for part in parts if str(part or "").strip()]

    return os.path.normpath(os.path.join(_ensure_app_user_data_dir(), *clean_parts))


def _seed_user_file_from_resource(filename: str) -> str:

    target = _app_user_data_path(filename)

    if os.path.exists(target):

        return target

    source = _app_resource_path(filename)

    if os.path.exists(source) and os.path.abspath(source) != os.path.abspath(target):

        try:

            os.makedirs(os.path.dirname(target), exist_ok=True)

            shutil.copy2(source, target)

        except Exception:

            pass

    return target


def _app_mutable_data_path(filename: str, seed_from_resource: bool = True) -> str:

    if seed_from_resource:

        return _seed_user_file_from_resource(filename)

    return _app_user_data_path(filename)


def _seed_user_dir_from_resource(dirname: str) -> str:

    target = _app_user_data_path(dirname)

    if os.path.isdir(target):

        return target

    source = _app_resource_path(dirname)

    if os.path.isdir(source) and os.path.abspath(source) != os.path.abspath(target):

        try:

            shutil.copytree(source, target, dirs_exist_ok=True)

        except Exception:

            pass

    return target


def _app_mutable_dir_path(dirname: str, seed_from_resource: bool = True) -> str:

    if seed_from_resource:

        return _seed_user_dir_from_resource(dirname)

    return _app_user_data_path(dirname)




def _lazy_import_torch() -> object | None:

    global _torch, _torch_import_attempted

    if bool(_torch_import_attempted):

        return _torch

    with _torch_import_lock:

        if bool(_torch_import_attempted):

            return _torch

        try:

            import torch as _torch_mod  # type: ignore[import-not-found]


            _torch = _torch_mod

        except Exception:

            _torch = None

        _torch_import_attempted = True

    return _torch


