@dataclass(frozen=True)


class ThemePalette:


    name: str


    accent: str


    rings: tuple[str, str, str, str]


    logo_bg: str








def _mix(color_a: QColor, color_b: QColor, ratio: float) -> QColor:


    inv = 1.0 - ratio


    return QColor(


        int(color_a.red() * inv + color_b.red() * ratio),


        int(color_a.green() * inv + color_b.green() * ratio),


        int(color_a.blue() * inv + color_b.blue() * ratio),


    )








def _normalize_ui_text(value: object) -> str:


    text = str(value or "")


    base = text.strip()


    if not base:


        return base





    def _cyr_score(s: str) -> int:


        return sum(1 for ch in s if "\u0400" <= ch <= "\u04FF")

    def _mojibake_penalty(s: str) -> int:

        normal_cyr = set(
            "АБВГДЕЖЗИЙКЛМНОПРСТУФХЦЧШЩЪЫЬЭЮЯ"
            "абвгдежзийклмнопрстуфхцчшщъыьэюя"
            "ЁёІіЇїЄєҐґ"
        )

        penalty = 0

        for ch in s:

            code = ord(ch)

            if 0x80 <= code <= 0xBF:

                penalty += 2

            elif ch in {"Ð", "Ñ", "Â", "Ã"}:

                penalty += 2

            elif "\u0400" <= ch <= "\u04FF" and ch not in normal_cyr:

                penalty += 1

        return penalty




    best = base


    best_score = _cyr_score(best)

    best_penalty = _mojibake_penalty(best)


    for source_encoding in ("cp1251", "latin1"):


        try:


            candidate = base.encode(source_encoding).decode("utf-8").strip()


        except Exception:


            continue


        score = _cyr_score(candidate)


        penalty = _mojibake_penalty(candidate)

        shorter_and_cleaner = (
            score > 0
            and score >= max(1, int(best_score * 0.45))
            and penalty < best_penalty
            and len(candidate) <= max(1, int(len(best) * 0.82))
        )

        if score > best_score or shorter_and_cleaner:


            best = candidate


            best_score = score

            best_penalty = penalty


    return best








def palette_from_accent(name: str, accent: str) -> ThemePalette:


    base = QColor(accent)


    black = QColor(0, 0, 0)


    rings = (


        _mix(base, black, 0.86).name(),


        _mix(base, black, 0.72).name(),


        _mix(base, black, 0.58).name(),


        _mix(base, black, 0.42).name(),


    )


    logo_bg = _mix(base, black, 0.14).name()


    return ThemePalette(name=name, accent=base.name(), rings=rings, logo_bg=logo_bg)








