def set_active(widget: QWidget, active: bool) -> None:


    widget.setProperty("active", active)


    widget.style().unpolish(widget)


    widget.style().polish(widget)


    widget.update()








def _qt_object_alive(obj: object) -> bool:

    if obj is None:


        return False


    checker = _qt_is_valid


    if checker is not None:


        try:


            return bool(checker(obj))


        except Exception:


            return False


    try:


        getattr(obj, "thread")()


    except RuntimeError:


        return False


    except Exception:


        pass


    return True





def _is_interactive_drag_widget(widget: QWidget | None) -> bool:

    interactive_types = (

        QPushButton,

        QLineEdit,

        QComboBox,

        QTreeWidget,

        QTableWidget,

        QSlider,

        QCheckBox,

        QListWidget,

        QScrollArea,

    )

    current = widget

    while current is not None:

        if isinstance(current, interactive_types):

            return True

        current = current.parentWidget()

    return False





def _apply_rounded_window_mask(widget: QWidget, radius: int) -> None:

    if not _qt_object_alive(widget):

        return

    w = int(widget.width())

    h = int(widget.height())

    if w <= 0 or h <= 0:

        return

    r = max(0, int(radius))

    if r <= 0:

        widget.setMask(QRegion(0, 0, w, h))

        return

    path = QPainterPath()

    path.addRoundedRect(QRectF(0.0, 0.0, float(w), float(h)), float(r), float(r))

    widget.setMask(QRegion(path.toFillPolygon().toPolygon()))







class SpeechRecognitionWorker(QThread):

    text_recognized = Signal(str)


    status_changed = Signal(str)


    error_changed = Signal(str)


    _model_cache_lock = threading.Lock()


    _vosk_model_cache: dict[str, tuple[object, str]] = {}


    _faster_whisper_cache: dict[tuple[str, str, str], object] = {}


    _openai_whisper_cache: dict[str, object] = {}





    def __init__(

        self,

        language_key: str,

        model_name: str,

        sensitivity: int,

        microphone_model: str = "default",

        priority_words: list[str] | None = None,

    ) -> None:

        super().__init__()


        self.language_key = str(language_key or "").strip() or "Русский"


        self.model_name = str(model_name or "").strip() or "Средняя модель"

        self.microphone_model = str(microphone_model or "").strip() or "default"

        self.sensitivity = max(0, min(100, int(sensitivity)))


        self._fw_beam_size = 2

        self._fw_best_of = 1

        self._fw_patience = 1.0

        self._fw_no_speech_threshold = 0.62

        self._last_text_key = ""


        self._last_text_ts = 0.0


        self._priority_words = self._prepare_priority_words(priority_words)


        self._keyword_aliases = self._build_keyword_aliases()


        self._vosk_grammar = self._build_vosk_grammar()





    def _whisper_model(self) -> str:


        lowered = self.model_name.lower()


        if "мал" in lowered or "small" in lowered:


            return "small"


        if "сред" in lowered or "medium" in lowered:


            return "medium"


        if "больш" in lowered or "large" in lowered:


            return "large-v3"


        if "велика" in lowered:


            return "large-v3"


        # По умолчанию берем medium для более быстрого отклика.

        return "medium"




    def _openai_whisper_model(self) -> str:


        model = self._whisper_model()


        if model == "large-v3":


            return "large"


        return model





    def _cpu_is_weak(self) -> bool:


        try:


            # Для Python-ASR 6-8 потоков без GPU на ноутбуках часто всё ещё "слабый" профиль.


            return int(os.cpu_count() or 4) <= 8


        except Exception:


            return True





    def _load_faster_whisper_cached(self, model_name: str, device: str, compute_type: str) -> object:


        key = (str(model_name), str(device), str(compute_type))


        with self._model_cache_lock:


            cached = self._faster_whisper_cache.get(key)


        if cached is not None:


            return cached


        from faster_whisper import WhisperModel





        model = WhisperModel(model_name, device=device, compute_type=compute_type)


        with self._model_cache_lock:


            existing = self._faster_whisper_cache.get(key)


            if existing is not None:


                return existing


            self._faster_whisper_cache[key] = model


        return model





    def _load_openai_whisper_cached(self, model_name: str) -> object:


        key = str(model_name)


        with self._model_cache_lock:


            cached = self._openai_whisper_cache.get(key)


        if cached is not None:


            return cached


        import whisper





        model = whisper.load_model(model_name)


        with self._model_cache_lock:


            existing = self._openai_whisper_cache.get(key)


            if existing is not None:


                return existing


            self._openai_whisper_cache[key] = model


        return model





    def _forced_language_from_microphone_model(self) -> str:

        model = self._normalize_microphone_choice(self.microphone_model)

        if not model:

            return ""

        if model in {"en", "english", "английский", "англ"}:

            return "en"

        if model in {"uk", "ua", "українська", "украинский", "український"}:

            return "uk"

        if model in {"ru", "русский"}:

            return "ru"

        return ""



    def _normalize_microphone_choice(self, value: object) -> str:

        text = str(value or "").strip()

        if not text:

            return "default"

        lowered = text.lower()

        if lowered in {"default", "по умолчанию", "за замовчуванням"}:

            return "default"

        # Legacy values from old dropdown (language instead of device).

        if lowered in {"русский", "russian", "english", "українська", "ukrainian", "en", "ru", "uk", "ua"}:

            return lowered

        if lowered.startswith("sr:"):

            tail = lowered[3:].strip()

            if tail.isdigit():

                return f"sr:{int(tail)}"

            return "default"

        if lowered.startswith("sd:"):

            tail = lowered[3:].strip()

            if tail.isdigit():

                return f"sd:{int(tail)}"

            return "default"

        return text



    def _is_loopback_like_input_name(self, name: object) -> bool:

        low = str(name or "").strip().casefold()

        if not low:

            return False

        hard_tokens = (

            "stereo mix",

            "стерео микшер",

            "микшер стерео",

            "what u hear",

            "what-you-hear",

            "wave out mix",

            "loopback",

            "monitor of",

            "монитор",

            "что слышу",

            "mixage st",

        )

        if any(token in low for token in hard_tokens):

            return True

        if "vb-audio" in low and "output" in low:

            return True

        if "virtual cable" in low and "output" in low:

            return True

        if "cable output" in low:

            return True

        return False



    def _input_device_name_score(self, name: object) -> int:

        low = str(name or "").strip().casefold()

        if not low:

            return -10000

        score = 0

        if self._is_loopback_like_input_name(low):

            score -= 2000

        mic_tokens = (

            "микроф",

            "microphone",

            "mic",

            "input",

            "array",

            "headset",

            "гарнит",

            "capture",

            "record",

            "запис",

            "line in",

            "line-in",

            "linein",

            "webcam",

            "camera",

            "usb",

        )

        output_tokens = (

            "output",

            "speaker",

            "динам",

            "колонк",

            "playback",

            "render",

            "hdmi",

        )

        if any(token in low for token in mic_tokens):

            score += 220

        if any(token in low for token in ("mic", "микроф", "microphone")):

            score += 160

        if any(token in low for token in ("input", "capture", "record", "запис")):

            score += 110

        if any(token in low for token in ("array", "headset", "гарнит", "webcam", "camera")):

            score += 70

        if any(token in low for token in output_tokens):

            score -= 280

        return score



    def _best_sr_index_from_names(self, names: list[str]) -> tuple[int | None, str]:

        best_idx: int | None = None

        best_name = ""

        best_score = -100000

        for idx, raw_name in enumerate(names):

            name = str(raw_name or "").strip()

            if not name:

                continue

            if self._is_loopback_like_input_name(name):

                continue

            score = self._input_device_name_score(name)

            if score > best_score:

                best_idx = idx

                best_name = name

                best_score = score

        if best_idx is not None:

            return best_idx, best_name

        return None, ""



    def _pick_sr_input(self, sr: object) -> tuple[int | None, str]:

        choice = self._normalize_microphone_choice(self.microphone_model)

        try:

            names = list(sr.Microphone.list_microphone_names() or [])

        except Exception:

            names = []

        if not names:

            return None, ""

        if choice.startswith("sr:"):

            try:

                idx = int(choice.split(":", 1)[1])

                if 0 <= idx < len(names):

                    selected_name = str(names[idx] or "")

                    if not self._is_loopback_like_input_name(selected_name):

                        return idx, selected_name

            except Exception:

                pass

            return None, ""

        # For explicit sounddevice selection we do not force PyAudio index.

        if choice.startswith("sd:"):

            return None, ""

        # Legacy/compat: try match by name.

        lowered_choice = str(choice).casefold()

        if lowered_choice and lowered_choice not in {"default", "ru", "en", "uk", "ua", "english", "русский", "russian"}:

            for idx, raw_name in enumerate(names):

                name = str(raw_name or "").strip()

                if not name:

                    continue

                name_key = name.casefold()

                if lowered_choice == name_key or lowered_choice in name_key or name_key in lowered_choice:

                    if not self._is_loopback_like_input_name(name):

                        return idx, name

        # In converted/frozen builds Windows often exposes Stereo Mix or a
        # virtual endpoint as the default input. Prefer an obvious microphone
        # by name, but fall back to system default if the device list is vague.
        if lowered_choice in {"default", "ru", "en", "uk", "ua", "english", "русский", "russian"}:

            best_idx, best_name = self._best_sr_index_from_names(names)

            if best_idx is not None and self._input_device_name_score(best_name) >= 180:

                return best_idx, best_name

        return None, ""



    def _probe_sr_microphone_stream(self, recognizer: object, microphone: object) -> None:

        # speech_recognition<=3.10 has a known behavior where Microphone.__enter__()

        # may silently leave stream=None instead of raising; detect it proactively.

        try:

            with microphone as source:

                if getattr(source, "stream", None) is None:

                    raise RuntimeError("pyaudio_stream_none")

                try:

                    recognizer.adjust_for_ambient_noise(source, duration=0.05)

                except Exception:

                    # Non-fatal: only stream open health matters here.

                    pass

                if getattr(source, "stream", None) is None:

                    raise RuntimeError("pyaudio_stream_lost")

        except Exception:

            raise



    def _whisper_lang(self) -> str:

        forced = self._forced_language_from_microphone_model()

        if forced:

            return forced

        lowered = self.language_key.lower()


        if "english" in lowered:


            return "en"


        if "укра" in lowered:


            return "uk"


        return "ru"





    def _google_lang(self) -> str:


        forced = self._forced_language_from_microphone_model()


        if forced == "en":


            return "en-US"


        if forced == "uk":


            return "uk-UA"


        if forced == "ru":


            return "ru-RU"


        lowered = self.language_key.lower()


        if "english" in lowered:


            return "en-US"


        if "укра" in lowered:


            return "uk-UA"


        return "ru-RU"





    def _normalize_text(self, text: object) -> str:


        return " ".join(str(text or "").replace("\n", " ").split()).strip()





    def _prepare_priority_words(self, priority_words: list[str] | None) -> list[str]:


        prepared: list[str] = []


        raw = list(priority_words or [])


        for value in raw:


            text = self._normalize_text(value)


            if not text:


                continue


            prepared.append(text)


        unique: list[str] = []


        seen: set[str] = set()


        for item in prepared:


            key = item.casefold()


            if key in seen:


                continue


            seen.add(key)


            unique.append(item)


        return unique





    def _build_keyword_aliases(self) -> dict[str, set[str]]:

        aliases: dict[str, set[str]] = {

            "джарвис": {

                "джарвис",

                "джервис",

                "жарвис",


                "джарвиз",


                "дарвис",


                "джар вис",


                "джарвисс",


                "джавас",


                "джавис",


                "жар вис",


                "джарвес",


                "jarvis",

                "jervis",

                "javis",

                "jarviss",

                # Frequent ASR distortions for wake phrase.

                "джой",

                "джои",

                "джойс",

                "джовис",

                "джарис",

                "дярвис",

                "арави",

                "аравис",

                "арвис",

                "жарви",

                "джорис",

                "джави",

                "джа вис",

            },

            "курсив": {

                "курсив",

                "курс ив",

                "кур сив",


                "курсыв",


                "красив",


                "крусив",


                "курсива",


                "курсивом",


                "курсивы",


                "курсивчик",


                "cursive",


            },


        }


        for hint in self._priority_words:

            normalized = self._normalize_text(hint).casefold()

            if not normalized:

                continue

            aliases.setdefault(normalized, set()).add(normalized)

        return aliases



    def _build_vosk_grammar(self) -> str:

        # Custom Vosk grammar generated from aliases often introduces

        # "Ignoring word missing in vocabulary" spam and quality regressions.

        # Keep grammar disabled for stable recognition.

        return ""




    def _keyword_best_match(self, token: str) -> str:


        base = self._normalize_text(token).casefold()


        if not base or len(base) < 4:


            return ""


        best_canonical = ""


        best_score = 0.0


        for canonical, variants in self._keyword_aliases.items():


            candidates = set(variants)


            candidates.add(canonical)


            for candidate in candidates:


                cand = candidate.casefold()


                if not cand:


                    continue


                if abs(len(base) - len(cand)) > 3:


                    continue


                if base == cand:


                    return canonical


                if not base or not cand:


                    continue


                if base[0] != cand[0]:


                    continue


                if len(base) >= 5 and len(cand) >= 5 and base[-1] != cand[-1]:


                    continue


                score = difflib.SequenceMatcher(None, base, cand).ratio()


                if score > best_score:


                    best_score = score


                    best_canonical = canonical


        threshold = 0.86 if len(base) <= 6 else 0.82


        if best_canonical == "джарвис":


            # Wake word must be corrected even with stronger distortion.


            threshold = 0.74 if len(base) <= 8 else 0.72


        elif best_canonical == "курсив":


            threshold = min(threshold, 0.78)


        if best_score >= threshold:


            return best_canonical


        return ""





    def _apply_keyword_corrections(self, text: str) -> str:

        normalized = self._normalize_text(text)

        if not normalized:

            return ""



        corrected = normalized

        corrected = re.sub(r"\bджар\s*в(?:и|і)с\b", "джарвис", corrected, flags=re.IGNORECASE)

        corrected = re.sub(r"\bкурс\s*ив\b", "курсив", corrected, flags=re.IGNORECASE)

        corrected = re.sub(r"\bjar\s*vis\b", "джарвис", corrected, flags=re.IGNORECASE)

        corrected = re.sub(r"\bjav(?:i|e)s\b", "джарвис", corrected, flags=re.IGNORECASE)

        corrected = re.sub(r"\bджой(?:с)?\b", "джарвис", corrected, flags=re.IGNORECASE)

        corrected = re.sub(r"\bарави(?:с)?\b", "джарвис", corrected, flags=re.IGNORECASE)

        corrected = re.sub(r"\bарвис\b", "джарвис", corrected, flags=re.IGNORECASE)

        corrected = re.sub(r"\bджарис\b", "джарвис", corrected, flags=re.IGNORECASE)

        corrected = re.sub(r"\bжарви(?:с)?\b", "джарвис", corrected, flags=re.IGNORECASE)

        corrected = re.sub(r"\bджа\s*вис\b", "джарвис", corrected, flags=re.IGNORECASE)




        parts = corrected.split(" ")


        if not parts:


            return corrected





        fixed_parts: list[str] = []


        token_pattern = re.compile(r"^([^A-Za-zА-Яа-яЁёІіЇїЄєҐґ0-9]*)([A-Za-zА-Яа-яЁёІіЇїЄєҐґ0-9]+)([^A-Za-zА-Яа-яЁёІіЇїЄєҐґ0-9]*)$")


        for piece in parts:


            m = token_pattern.match(piece)


            if not m:


                fixed_parts.append(piece)


                continue


            left, word, right = m.groups()


            matched = self._keyword_best_match(word)


            if matched:


                fixed_parts.append(f"{left}{matched}{right}")


            else:


                fixed_parts.append(piece)


        return self._normalize_text(" ".join(fixed_parts))





    def _keyword_hit_count(self, text: str) -> int:


        corrected = self._apply_keyword_corrections(text).casefold()


        if not corrected:


            return 0


        hits = 0


        for canonical in self._keyword_aliases.keys():


            pattern = rf"(?<![A-Za-zА-Яа-яЁёІіЇїЄєҐґ0-9]){re.escape(canonical)}(?![A-Za-zА-Яа-яЁёІіЇїЄєҐґ0-9])"


            if re.search(pattern, corrected):


                hits += 1


        return hits





    def _pick_best_candidate_text(self, *candidates: str) -> str:

        normalized_candidates: list[str] = []

        for candidate in candidates:

            normalized = self._normalize_text(candidate)

            if not normalized:

                continue

            normalized_candidates.append(normalized)

        if not normalized_candidates:

            return ""



        # Keep backend order priority when candidates have no keyword signal.

        # This avoids replacing a primary backend result with longer garbage.

        best = normalized_candidates[0]

        best_hits = self._keyword_hit_count(best)

        best_words = len(best.split())

        for normalized in normalized_candidates[1:]:

            hits = self._keyword_hit_count(normalized)

            words = len(normalized.split())

            if hits > best_hits:

                best = normalized

                best_hits = hits

                best_words = words

                continue

            if hits > 0 and hits == best_hits:

                if words > best_words or (words == best_words and len(normalized) > len(best)):

                    best = normalized

                    best_words = words

        return best



    def _sanitize_google_wake_tail_for_small_vosk(self, text: str) -> str:

        normalized = self._apply_keyword_corrections(text)

        if not normalized:

            return ""

        words = [chunk for chunk in normalized.split(" ") if chunk]

        if len(words) != 2:

            return normalized

        first = re.sub(r"[^A-Za-zА-Яа-яЁёІіЇїЄєҐґ0-9]+", "", words[0]).casefold()

        second = re.sub(r"[^A-Za-zА-Яа-яЁёІіЇїЄєҐґ0-9]+", "", words[1]).casefold()

        if first != "джарвис" or not second:

            return normalized

        command_like_prefixes = (

            "включ",

            "выключ",

            "отк",

            "зак",

            "запус",

            "пауз",

            "ярк",

            "громк",

            "тише",

            "громче",

            "уменьш",

            "увелич",

            "найд",

            "ска",

            "пок",

            "перек",

            "пред",

            "след",

            "стоп",

            "назад",

            "вперед",

            "сдел",

            "open",

            "close",

            "run",

            "mute",

        )

        if any(second.startswith(prefix) for prefix in command_like_prefixes):

            return normalized

        # In small Vosk mode Google fallback can append random tail after wake word.

        # Keep clean wake phrase so command routing stays deterministic.

        return "джарвис"



    def _filter_repeated_text(self, text: str) -> str:

        normalized = self._apply_keyword_corrections(text)

        if not normalized or len(normalized) < 2:

            return ""

        key = normalized.casefold()

        now = datetime.now().timestamp()


        if key == self._last_text_key and (now - self._last_text_ts) < 2.0:


            return ""


        self._last_text_key = key


        self._last_text_ts = now


        return normalized





    def _transcribe_with_faster_whisper(self, model: object, audio_source: object) -> str:

        kwargs = {

            "language": self._whisper_lang(),

            "beam_size": int(self._fw_beam_size),

            "best_of": int(self._fw_best_of),

            "patience": float(self._fw_patience),

            "temperature": 0.0,

            "vad_filter": True,

            "condition_on_previous_text": False,

            "compression_ratio_threshold": 2.1,

            "log_prob_threshold": -1.0,

            "no_speech_threshold": float(self._fw_no_speech_threshold),

            "vad_parameters": {"min_silence_duration_ms": 180, "speech_pad_ms": 90},

        }

        try:

            segments, _ = model.transcribe(audio_source, **kwargs)

        except TypeError:

            segments, _ = model.transcribe(

                audio_source,

                language=self._whisper_lang(),

                beam_size=int(max(3, self._fw_beam_size - 1)),

                best_of=int(max(2, self._fw_best_of - 1)),

                temperature=0.0,

                vad_filter=True,

            )


        except Exception:


            return ""


        text_parts: list[str] = []


        try:


            for seg in segments:


                piece = str(getattr(seg, "text", "")).strip()


                if piece:


                    text_parts.append(piece)


        except Exception:


            return ""


        return " ".join(text_parts).strip()





    def _transcribe_with_openai_whisper(self, model: object, wav_path: str) -> str:


        try:


            result = model.transcribe(

                wav_path,

                language=self._whisper_lang(),

                beam_size=2,

                best_of=1,

                temperature=0.0,

                condition_on_previous_text=False,

                fp16=False,

                no_speech_threshold=0.62,

            )

        except TypeError:


            try:


                result = model.transcribe(wav_path, language=self._whisper_lang(), temperature=0.0)


            except Exception:


                return ""


        except Exception:


            return ""


        if isinstance(result, dict):


            return str(result.get("text", "")).strip()


        return ""





    def _wav_from_pcm(self, pcm_mono_16bit: bytes, sample_rate: int = 16000) -> bytes:

        wav_buffer = io.BytesIO()

        with wave.open(wav_buffer, "wb") as wf:

            wf.setnchannels(1)

            wf.setsampwidth(2)


            wf.setframerate(sample_rate)


            wf.writeframes(pcm_mono_16bit)

        return wav_buffer.getvalue()



    def _quiet_speech_gain(self) -> float:

        sens = max(0, min(100, int(self.sensitivity)))

        if sens >= 98:

            return 2.70

        if sens >= 95:

            return 2.35

        if sens >= 90:

            return 1.95

        if sens >= 86:

            return 1.45

        return 1.0



    def _enhance_wav_for_quiet_speech(self, wav_bytes: bytes) -> bytes:

        if not wav_bytes:

            return b""

        gain = float(self._quiet_speech_gain())

        if gain <= 1.01:

            return wav_bytes

        try:

            import audioop

            with wave.open(io.BytesIO(wav_bytes), "rb") as wf:

                channels = int(wf.getnchannels())

                sample_width = int(wf.getsampwidth())

                sample_rate = int(wf.getframerate())

                pcm = wf.readframes(wf.getnframes())

            if sample_width != 2 or not pcm:

                return wav_bytes

            boosted = audioop.mul(pcm, 2, gain)

            out = io.BytesIO()

            with wave.open(out, "wb") as wf:

                wf.setnchannels(channels)

                wf.setsampwidth(sample_width)

                wf.setframerate(sample_rate)

                wf.writeframes(boosted)

            return out.getvalue()

        except Exception:

            return wav_bytes



    def _pick_sounddevice_input(

        self,

        sd: object,

        preferred_device: int | None = None,

        preferred_name: str = "",

    ) -> tuple[int | None, str]:

        try:

            devices = sd.query_devices()

        except Exception:

            return None, ""



        try:

            pref_idx = int(preferred_device) if preferred_device is not None else None

        except Exception:

            pref_idx = None

        if pref_idx is not None and 0 <= pref_idx < len(devices):

            try:

                if int(devices[pref_idx].get("max_input_channels", 0)) > 0:

                    chosen_name = str(devices[pref_idx].get("name", ""))

                    if not self._is_loopback_like_input_name(chosen_name):

                        return pref_idx, chosen_name

            except Exception:

                pass



        passet_name = str(preferred_name or "").strip().casefold()

        if passet_name:

            for idx, dev in enumerate(devices):

                if int(dev.get("max_input_channels", 0)) <= 0:

                    continue

                name = str(dev.get("name", "")).strip()

                if not name:

                    continue

                name_key = name.casefold()

                if passet_name == name_key or passet_name in name_key or name_key in passet_name:

                    if not self._is_loopback_like_input_name(name):

                        return idx, name



        try:

            default_pair = getattr(sd, "default", None).device

            if isinstance(default_pair, (list, tuple)) and default_pair:

                idx = int(default_pair[0])

                if 0 <= idx < len(devices) and int(devices[idx].get("max_input_channels", 0)) > 0:

                    chosen_name = str(devices[idx].get("name", ""))

                    if not self._is_loopback_like_input_name(chosen_name):

                        return idx, chosen_name

        except Exception:

            pass



        best_idx: int | None = None

        best_name = ""

        best_score = -100000

        for idx, dev in enumerate(devices):

            if int(dev.get("max_input_channels", 0)) <= 0:

                continue

            name = str(dev.get("name", "")).strip()

            if not name:

                continue

            if self._is_loopback_like_input_name(name):

                continue

            score = self._input_device_name_score(name)

            if score > best_score:

                best_idx = idx

                best_name = name

                best_score = score

        if best_idx is not None:

            return best_idx, best_name



        for idx, dev in enumerate(devices):

            if int(dev.get("max_input_channels", 0)) > 0:

                name = str(dev.get("name", ""))

                if name and not self._is_loopback_like_input_name(name):

                    return idx, name

        for idx, dev in enumerate(devices):

            if int(dev.get("max_input_channels", 0)) > 0:

                return idx, str(dev.get("name", ""))

        return None, ""



    def _is_sounddevice_invalid_device_error(self, exc: Exception) -> bool:

        text = str(exc or "").strip().casefold()

        if not text:

            return False

        if "invalid device" in text:

            return True

        if "paerrorcode -9996" in text:

            return True

        return False



    def _sounddevice_rate_candidates(self, default_samplerate: object = None) -> tuple[int, ...]:

        rates: list[int] = [16000]

        try:

            default_sr = int(round(float(default_samplerate)))

        except Exception:

            default_sr = 0

        if default_sr >= 8000:

            rates.append(default_sr)

        rates.extend([48000, 44100, 32000, 22050])

        uniq: list[int] = []

        seen: set[int] = set()

        for value in rates:

            if value < 8000 or value > 192000:

                continue

            if value in seen:

                continue

            seen.add(value)

            uniq.append(value)

        return tuple(uniq)



    def _sounddevice_input_works(self, sd: object, device_index: int | None, sample_rate: int) -> bool:

        kwargs = {

            "channels": 1,

            "dtype": "int16",

            "samplerate": int(sample_rate),

        }

        if device_index is not None:

            kwargs["device"] = int(device_index)

        try:

            sd.check_input_settings(**kwargs)

            return True

        except Exception:

            return False



    def _pick_sounddevice_capture_config(

        self,

        sd: object,

        preferred_device: int | None = None,

        preferred_name: str = "",

    ) -> tuple[int | None, str, int]:

        try:

            devices = list(sd.query_devices() or [])

        except Exception:

            return None, "", 16000



        base_idx, base_name = self._pick_sounddevice_input(sd, preferred_device=preferred_device, preferred_name=preferred_name)



        candidates: list[tuple[int | None, str, int]] = []

        seen_idx: set[int] = set()

        if base_idx is not None and 0 <= int(base_idx) < len(devices):

            idx = int(base_idx)

            seen_idx.add(idx)

            name = str(devices[idx].get("name", "") or base_name or "").strip()

            score = self._input_device_name_score(name)

            candidates.append((idx, name, score))

        for idx, dev in enumerate(devices):

            try:

                if int(dev.get("max_input_channels", 0)) <= 0:

                    continue

            except Exception:

                continue

            if idx in seen_idx:

                continue

            name = str(dev.get("name", "") or "").strip()

            if not name:

                continue

            if self._is_loopback_like_input_name(name):

                continue

            seen_idx.add(idx)

            score = self._input_device_name_score(name)

            candidates.append((idx, name, score))



        candidates.sort(key=lambda item: item[2], reverse=True)

        for idx, name, _score in candidates:

            default_sr = None

            try:

                default_sr = devices[int(idx)].get("default_samplerate", None)

            except Exception:

                default_sr = None

            for rate in self._sounddevice_rate_candidates(default_sr):

                if self._sounddevice_input_works(sd, int(idx), int(rate)):

                    return int(idx), str(name), int(rate)



        # Last resort: system default input.

        for rate in self._sounddevice_rate_candidates(None):

            if self._sounddevice_input_works(sd, None, int(rate)):

                return None, "", int(rate)



        # Keep prior fallback semantics if probing is not possible.

        return base_idx, base_name, 16000



    def _record_chunk_with_sounddevice(

        self,

        sd: object,

        np: object,

        input_device: int | None = None,

        sample_rate: int = 16000,

    ) -> bytes:

        sample_rate = int(max(8000, min(192000, sample_rate)))

        # Keep chunks short to reduce decode latency and CPU spikes.

        chunk_seconds = 0.92 if self._cpu_is_weak() else 0.64

        frames = int(sample_rate * chunk_seconds)

        recording = sd.rec(frames, samplerate=sample_rate, channels=1, dtype="int16", device=input_device)

        sd.wait()

        if recording is None:


            return b""


        data = recording.reshape(-1)

        if int(data.size) <= 0:

            return b""

        data_f = data.astype(np.float32)

        gain = float(self._quiet_speech_gain())

        if gain > 1.01:

            data_f = np.clip(data_f * gain, -32768.0, 32767.0)

            data = data_f.astype(np.int16)

        rms = float(np.sqrt(np.mean(data_f * data_f)))

        peak = float(np.max(np.abs(data_f)))

        # Lower gate for normal speech volume on laptop microphones.

        gate = max(1.2, 17.0 - float(self.sensitivity) * 0.20)

        if int(self.sensitivity) >= 95:

            gate *= 0.45

        elif int(self.sensitivity) >= 88:

            gate *= 0.62

        if rms < gate and peak < gate * 2.4:

            return b""

        return self._wav_from_pcm(data.astype(np.int16).tobytes(), sample_rate=sample_rate)



    def _wav_bytes_to_float32_pcm(self, wav_bytes: bytes) -> object | None:

        if not wav_bytes:

            return None

        try:

            import audioop

            import numpy as np

        except Exception:

            return None

        try:

            with wave.open(io.BytesIO(wav_bytes), "rb") as wf:

                channels = int(wf.getnchannels())

                sample_width = int(wf.getsampwidth())

                sample_rate = int(wf.getframerate())

                pcm = wf.readframes(wf.getnframes())

        except Exception:

            return None

        if sample_width != 2 or not pcm:

            return None

        try:

            if channels > 1:

                pcm = audioop.tomono(pcm, 2, 0.5, 0.5)

            if sample_rate != 16000:

                pcm, _ = audioop.ratecv(pcm, 2, 1, sample_rate, 16000, None)

            samples = np.frombuffer(pcm, dtype=np.int16)

            if int(samples.size) <= 0:

                return None

            return samples.astype(np.float32) / 32768.0

        except Exception:

            return None



    def _chunk_has_voice_signal(self, wav_bytes: bytes) -> bool:

        if not wav_bytes:

            return False

        # For command-oriented realtime modes we keep gate very permissive,

        # otherwise short wake-phrases can be dropped before decoding.

        try:

            mode = self._recognition_mode()

        except Exception:

            mode = ""

        if int(self.sensitivity) >= 92:

            return True

        if mode in {"small_vosk", "medium_speechrecognition", "google_sr"} and int(self.sensitivity) >= 76:

            return True

        try:

            import audioop



            with wave.open(io.BytesIO(wav_bytes), "rb") as wf:

                channels = int(wf.getnchannels())

                sample_width = int(wf.getsampwidth())

                sample_rate = int(wf.getframerate())

                pcm = wf.readframes(wf.getnframes())

            if sample_width != 2 or not pcm:

                return True

            if channels > 1:

                pcm = audioop.tomono(pcm, 2, 0.5, 0.5)

            if sample_rate != 16000:

                pcm, _ = audioop.ratecv(pcm, 2, 1, sample_rate, 16000, None)

            if not pcm:

                return False

            rms = int(audioop.rms(pcm, 2))

            peak = int(audioop.max(pcm, 2))

            gate = max(1, 7 - int(self.sensitivity * 0.07))

            if int(self.sensitivity) >= 95:

                gate = max(1, gate - 2)

            elif int(self.sensitivity) >= 88:

                gate = max(1, gate - 1)

            return bool(rms >= gate or peak >= (gate * 3))

        except Exception:

            # If signal probing failed, do not drop chunk.

            return True



    def _transcribe_wav_bytes(self, wav_bytes: bytes, faster_model: object, openai_whisper_model: object) -> str:

        if not wav_bytes:

            return ""

        text = ""

        if faster_model is not None:

            in_memory_audio = self._wav_bytes_to_float32_pcm(wav_bytes)

            if in_memory_audio is not None:

                text = self._transcribe_with_faster_whisper(faster_model, in_memory_audio)

        if text:

            return self._normalize_text(text)



        # Fallback path for backends that require a file path.

        tmp_path = ""

        if faster_model is None and openai_whisper_model is None:

            return ""

        try:

            with tempfile.NamedTemporaryFile(delete=False, suffix=".wav") as tmp:

                tmp.write(wav_bytes)

                tmp_path = tmp.name

            if not text and faster_model is not None:

                text = self._transcribe_with_faster_whisper(faster_model, tmp_path)

            if not text and openai_whisper_model is not None:

                text = self._transcribe_with_openai_whisper(openai_whisper_model, tmp_path)

        except Exception:

            text = ""

        finally:

            if tmp_path and os.path.exists(tmp_path):

                try:

                    os.remove(tmp_path)

                except Exception:

                    pass

        return self._normalize_text(text)




    def _recognize_google_from_wav(self, recognizer: object, sr: object, wav_bytes: bytes) -> str:


        if not wav_bytes:


            return ""


        try:


            with sr.AudioFile(io.BytesIO(wav_bytes)) as source:


                audio = recognizer.record(source)


            return self._normalize_text(recognizer.recognize_google(audio, language=self._google_lang()))


        except Exception:


            return ""





    def _enqueue_audio_chunk(self, audio_queue: "queue.Queue[bytes]", wav_bytes: bytes) -> None:

        if not wav_bytes:

            return

        has_signal = self._chunk_has_voice_signal(wav_bytes)

        if (not has_signal) and int(self.sensitivity) < 90:

            return

        prepared = wav_bytes

        if float(self._quiet_speech_gain()) > 1.01 and int(self.sensitivity) >= 90:

            prepared = self._enhance_wav_for_quiet_speech(wav_bytes)

            if not self._chunk_has_voice_signal(prepared):

                return

        elif not has_signal:

            return

        try:

            audio_queue.put_nowait(prepared)

            return

        except Exception:

            pass

        try:


            _ = audio_queue.get_nowait()


        except Exception:

            pass

        try:

            audio_queue.put_nowait(prepared)

        except Exception:

            pass




    def _recognition_mode(self) -> str:

        lowered = self.model_name.lower()

        if any(token in lowered for token in ("google", "гугл", "speechrecognition")):

            return "google_sr"

        if any(token in lowered for token in ("vosk", "воск")):

            return "small_vosk"

        if any(token in lowered for token in ("мал", "мала", "small")):

            return "small_vosk"

        if any(token in lowered for token in ("сред", "серед", "medium")):

            return "medium_speechrecognition"

        if any(token in lowered for token in ("больш", "велика", "large")):

            return "large_whisper"


        return "medium_speechrecognition"





    def _vosk_prefixes(self) -> tuple[str, ...]:


        lang = self._whisper_lang()


        if lang == "en":


            return (


                "vosk-model-small-en-us",


                "vosk-model-en-us",


                "vosk-model-small-en",


                "vosk-model-en",


            )


        if lang == "uk":


            return (


                "vosk-model-small-uk-v3",


                "vosk-model-uk-v3",


                "vosk-model-small-uk",


                "vosk-model-uk",


            )


        return ("vosk-model-small-ru", "vosk-model-ru")





    def _to_windows_short_path(self, path: str) -> str:


        if os.name != "nt":


            return path


        try:


            import ctypes





            normalized = os.path.abspath(path)


            buf = ctypes.create_unicode_buffer(4096)


            length = int(ctypes.windll.kernel32.GetShortPathNameW(normalized, buf, len(buf)))


            if length > 0:


                short_path = str(buf.value or "").strip()


                if short_path:


                    return short_path


        except Exception:


            pass


        return path





    def _load_vosk_model(self) -> tuple[object | None, str]:


        try:


            import vosk


            try:


                vosk.SetLogLevel(-1)


            except Exception:


                pass


        except Exception as exc:


            return None, f"vosk не установлен: {exc}"





        lang_key = self._whisper_lang()


        with self._model_cache_lock:


            cached = self._vosk_model_cache.get(lang_key)


        if cached is not None:


            return cached[0], cached[1]





        roots: list[str] = []


        env_path = str(os.getenv("VOSK_MODEL_PATH", "")).strip().strip('"')


        if env_path:


            roots.append(env_path)





        script_dir = _app_resource_base_dir()


        roots.extend(


            [


                os.path.join(script_dir, "models"),


                script_dir,


                os.path.join(os.getcwd(), "models"),


                os.getcwd(),


            ]


        )





        prefixes = self._vosk_prefixes()


        candidates: list[str] = []


        seen: set[str] = set()





        def push_candidate(path: str) -> None:


            norm = os.path.normcase(os.path.normpath(path))


            if norm in seen:


                return


            seen.add(norm)


            candidates.append(path)





        for root in roots:


            root = str(root or "").strip().strip('"')


            if not root or not os.path.isdir(root):


                continue


            if os.path.isfile(os.path.join(root, "am", "final.mdl")):


                push_candidate(root)


            try:


                entries = os.listdir(root)


            except Exception:


                continue


            for name in entries:


                entry = os.path.join(root, name)


                if not os.path.isdir(entry):


                    continue


                lowered = name.lower()


                if any(prefix in lowered for prefix in prefixes):


                    push_candidate(entry)


            for name in entries:


                entry = os.path.join(root, name)


                if not os.path.isdir(entry):


                    continue


                lowered = name.lower()


                if "vosk-model" in lowered:


                    push_candidate(entry)





        if not candidates:


            return (


                None,


                "Модель Vosk не найдена. Положите модель в ./models или укажите путь через VOSK_MODEL_PATH.",


            )





        errors: list[str] = []


        for path in candidates:


            variants = [path]


            short_path = self._to_windows_short_path(path)


            if short_path and os.path.normcase(short_path) != os.path.normcase(path):


                variants.insert(0, short_path)





            for variant in variants:


                try:


                    model = vosk.Model(variant)


                    with self._model_cache_lock:


                        self._vosk_model_cache[lang_key] = (model, variant)


                    return model, variant


                except Exception as exc:


                    errors.append(f"{os.path.basename(path)} -> {variant}: {exc}")


        return None, "; ".join(errors) if errors else "Не удалось загрузить модель Vosk."





    def _transcribe_with_vosk(self, vosk_model: object, wav_bytes: bytes) -> str:


        if vosk_model is None or not wav_bytes:


            return ""


        try:


            import audioop


            import vosk


        except Exception:


            return ""





        try:


            with wave.open(io.BytesIO(wav_bytes), "rb") as wf:


                channels = int(wf.getnchannels())


                sample_width = int(wf.getsampwidth())


                sample_rate = int(wf.getframerate())


                pcm = wf.readframes(wf.getnframes())


        except Exception:


            return ""





        if sample_width != 2 or not pcm:


            return ""





        try:


            if channels > 1:


                pcm = audioop.tomono(pcm, 2, 0.5, 0.5)


            if sample_rate != 16000:


                pcm, _ = audioop.ratecv(pcm, 2, 1, sample_rate, 16000, None)


                sample_rate = 16000


            recognizer = None


            if self._vosk_grammar:


                try:


                    recognizer = vosk.KaldiRecognizer(vosk_model, float(sample_rate), self._vosk_grammar)


                except Exception:


                    recognizer = None


            if recognizer is None:


                recognizer = vosk.KaldiRecognizer(vosk_model, float(sample_rate))


            recognizer.SetWords(False)


            recognizer.AcceptWaveform(pcm)


            payload = recognizer.FinalResult()


            data = json.loads(payload) if payload else {}


            return self._normalize_text(data.get("text", ""))


        except Exception:


            return ""





    def run(self) -> None:

        try:


            import speech_recognition as sr


        except Exception as exc:


            self.error_changed.emit(f"speech_recognition не установлен: {exc}")


            return


        self.status_changed.emit("Инициализация распознавания речи...")


        mode = self._recognition_mode()

        mode_titles = {

            "small_vosk": "маленькая: Vosk + Google",

            "medium_speechrecognition": "средняя: Google",

            "google_sr": "средняя: Google",

            "large_whisper": "большая: Whisper",

        }

        self.status_changed.emit(f"Режим распознавания: {mode_titles.get(mode, mode)}")





        faster_model = None


        openai_whisper_model = None


        vosk_model = None


        backend_name = ""


        backend_errors: list[str] = []


        loaded_model_code = "medium"

        use_vosk_primary = False

        use_google_primary = False

        use_whisper_primary = False

        phrase_time_limit = 1.6

        weak_cpu = self._cpu_is_weak()

        next_google_allowed_at = 0.0

        if weak_cpu:

            google_cooldown_sec = 0.95

        else:

            google_cooldown_sec = 0.62



        if mode == "small_vosk":

            vosk_model, vosk_info = self._load_vosk_model()

            if vosk_model is not None:

                backend_name = f"vosk ({os.path.basename(str(vosk_info))}) + google-assist"

                use_vosk_primary = True

                phrase_time_limit = 1.28

            else:

                if vosk_info:

                    backend_errors.append(vosk_info)

                backend_name = "speech_recognition/google (small-hybrid)"

                use_google_primary = True

                phrase_time_limit = 1.30

        elif mode in {"medium_speechrecognition", "google_sr"}:

            vosk_model, vosk_info = self._load_vosk_model()

            if mode == "medium_speechrecognition" and vosk_model is not None:

                backend_name = f"vosk ({os.path.basename(str(vosk_info))}) + google-assist (realtime)"

                use_vosk_primary = True

                phrase_time_limit = 1.12 if weak_cpu else 1.00

            else:

                backend_name = "speech_recognition/google"

                use_google_primary = True

                phrase_time_limit = 1.35

                if vosk_model is not None:

                    backend_name += f" + vosk-fallback ({os.path.basename(str(vosk_info))})"

                elif vosk_info:

                    backend_errors.append(vosk_info)

        else:

            requested_model = "large-v3"

            cpu_model = "medium"

            loaded_model_code = requested_model

            try:

                if weak_cpu:

                    load_plan = (

                        ("cpu", "int8", "faster-whisper (CPU-int8, low-power)"),

                        ("cpu", "int8_float32", "faster-whisper (CPU-int8_float32, low-power)"),

                        ("cpu", "float32", "faster-whisper (CPU-float32, low-power)"),

                    )

                else:

                    load_plan = (

                        ("cuda", "float16", "faster-whisper (CUDA)"),

                        ("cpu", "int8", "faster-whisper (CPU-int8)"),

                        ("cpu", "int8_float32", "faster-whisper (CPU-int8_float32)"),

                        ("cpu", "float32", "faster-whisper (CPU-float32)"),

                    )

                for device, compute_type, title in load_plan:

                    try:

                        model_for_device = requested_model if device == "cuda" else cpu_model

                        faster_model = self._load_faster_whisper_cached(model_for_device, device=device, compute_type=compute_type)

                        loaded_model_code = model_for_device

                        backend_name = f"{title}, model={model_for_device}"

                        if device == "cpu" and requested_model != model_for_device:

                            self.status_changed.emit(

                                "CUDA недоступна: в большом режиме использую medium на CPU для стабильного realtime."

                            )

                        break

                    except Exception as exc:

                        backend_errors.append(f"{title}: {exc}")

            except Exception as exc:

                backend_errors.append(f"faster-whisper: {exc}")



            if faster_model is None:

                try:

                    openai_whisper_model = self._load_openai_whisper_cached(self._openai_whisper_model())

                    backend_name = "openai-whisper"

                except Exception as exc:

                    backend_errors.append(f"openai-whisper: {exc}")



            if faster_model is not None or openai_whisper_model is not None:

                use_whisper_primary = True

                if "CPU-int8" in backend_name and loaded_model_code == "large-v3":

                    self._fw_beam_size = 2

                    self._fw_best_of = 1

                    self._fw_patience = 1.0

                    self._fw_no_speech_threshold = 0.62

                elif "CPU-int8" in backend_name:

                    self._fw_beam_size = 2

                    self._fw_best_of = 1

                    self._fw_patience = 1.0

                    self._fw_no_speech_threshold = 0.62

                elif "CPU-float32" in backend_name:

                    self._fw_beam_size = 3

                    self._fw_best_of = 1

                    self._fw_patience = 1.0

                    self._fw_no_speech_threshold = 0.60

                else:

                    self._fw_beam_size = 4

                    self._fw_best_of = 2

                    self._fw_patience = 1.0

                    self._fw_no_speech_threshold = 0.58

                phrase_time_limit = 1.90

            else:

                vosk_model, vosk_info = self._load_vosk_model()

                if vosk_model is not None:

                    backend_name = f"vosk ({os.path.basename(str(vosk_info))}) (low-power fallback)"

                    use_vosk_primary = True

                    phrase_time_limit = 1.55

                    self.status_changed.emit("Whisper недоступен: использую Vosk low-power fallback.")

                else:

                    if vosk_info:

                        backend_errors.append(vosk_info)

                    backend_name = "speech_recognition/google (fallback)"

                    use_google_primary = True

                    phrase_time_limit = 1.45



            if use_whisper_primary:

                vosk_model, vosk_info = self._load_vosk_model()

                if vosk_model is not None:

                    backend_name += " + vosk-fallback"

                elif vosk_info:

                    backend_errors.append(vosk_info)




        if not backend_name:


            backend_name = "speech_recognition/google"


            use_google_primary = True


        if backend_errors and mode != "small_vosk":


            self.error_changed.emit("; ".join(backend_errors[:4]))





        if mode == "large_whisper":

            pause_threshold = 0.48

            non_speaking_duration = 0.20

            dyn_damping = 0.09

            dyn_ratio = 1.24

        elif mode in {"medium_speechrecognition", "google_sr"}:

            pause_threshold = 0.42

            non_speaking_duration = 0.18

            dyn_damping = 0.10

            dyn_ratio = 1.20

        elif mode == "small_vosk":

            pause_threshold = 0.38

            non_speaking_duration = 0.14

            dyn_damping = 0.09

            dyn_ratio = 1.18

        else:

            pause_threshold = 0.38

            non_speaking_duration = 0.18

            dyn_damping = 0.11

            dyn_ratio = 1.18



        if int(self.sensitivity) >= 95:

            pause_threshold = max(0.24, pause_threshold - 0.11)

            non_speaking_duration = max(0.08, non_speaking_duration - 0.08)

            dyn_damping = max(0.04, dyn_damping - 0.05)

            dyn_ratio = max(1.03, dyn_ratio - 0.18)

        elif int(self.sensitivity) >= 88:

            pause_threshold = max(0.28, pause_threshold - 0.07)

            non_speaking_duration = max(0.10, non_speaking_duration - 0.05)

            dyn_damping = max(0.05, dyn_damping - 0.03)

            dyn_ratio = max(1.05, dyn_ratio - 0.12)



        energy_base = 34 + int((100 - self.sensitivity) * (1.55 if weak_cpu else 1.82))

        if int(self.sensitivity) >= 95:

            energy_base = max(4, energy_base - 28)

        elif int(self.sensitivity) >= 85:

            energy_base = max(7, energy_base - 16)

        energy_value = int(max(4, min(1200, energy_base)))

        recognizer = sr.Recognizer()

        try:

            if use_google_primary and not use_vosk_primary:

                recognizer.operation_timeout = 2.0 if weak_cpu else 1.7

            else:

                recognizer.operation_timeout = 1.45 if weak_cpu else 1.15

        except Exception:

            pass


        recognizer.dynamic_energy_threshold = True


        recognizer.pause_threshold = pause_threshold


        recognizer.non_speaking_duration = non_speaking_duration


        recognizer.energy_threshold = energy_value


        recognizer.dynamic_energy_adjustment_damping = dyn_damping


        recognizer.dynamic_energy_ratio = dyn_ratio





        capture_backend = "pyaudio"

        sd_input_device = None

        sd_input_name = ""

        sd_sample_rate = 16000

        mic_exc: Exception | None = None

        selected_choice = self._normalize_microphone_choice(self.microphone_model)

        selected_sr_idx, selected_sr_name = self._pick_sr_input(sr)

        preferred_sd_idx: int | None = None

        if selected_choice.startswith("sd:"):

            try:

                preferred_sd_idx = int(selected_choice.split(":", 1)[1])

            except Exception:

                preferred_sd_idx = None

        force_sounddevice = selected_choice.startswith("sd:")

        try:

            if force_sounddevice:

                raise RuntimeError("selected_sounddevice")

            if selected_sr_idx is None:

                microphone = sr.Microphone()

            else:

                microphone = sr.Microphone(device_index=int(selected_sr_idx))

            # Validate that microphone stream can actually be opened.

            self._probe_sr_microphone_stream(recognizer, microphone)

            if selected_sr_name:

                capture_backend = f"pyaudio:{selected_sr_name}"

            sd = None

            np = None

        except Exception as exc:

            mic_exc = exc

            microphone = None

            try:

                import sounddevice as sd

                import numpy as np



                sd_input_device, sd_input_name, sd_sample_rate = self._pick_sounddevice_capture_config(

                    sd,

                    preferred_device=preferred_sd_idx,

                    preferred_name=selected_sr_name,

                )

                capture_backend = "sounddevice"

                if sd_input_name:

                    capture_backend = f"sounddevice:{sd_input_name}@{sd_sample_rate}"

                else:

                    capture_backend = f"sounddevice:default@{sd_sample_rate}"

                if force_sounddevice:

                    self.status_changed.emit("Использую выбранный микрофон sounddevice.")

                else:

                    self.status_changed.emit(f"PyAudio недоступен ({mic_exc}). Использую sounddevice.")

            except Exception as sd_exc:

                if force_sounddevice:

                    self.error_changed.emit(f"Не удалось открыть выбранный микрофон sounddevice: {sd_exc}")

                else:

                    self.error_changed.emit(f"Микрофон недоступен: {mic_exc}; fallback sounddevice: {sd_exc}")

                return




        def try_google_decode(wav_bytes: bytes, pending_chunks: int = 0, force: bool = False) -> str:

            nonlocal next_google_allowed_at

            if not wav_bytes:

                return ""

            if (not bool(force)) and pending_chunks > 0:

                return ""

            now = time.monotonic()

            if (not bool(force)) and now < float(next_google_allowed_at):

                return ""

            started = time.perf_counter()

            text_google = self._recognize_google_from_wav(recognizer, sr, wav_bytes)

            elapsed_ms = (time.perf_counter() - started) * 1000.0

            cooldown = float(google_cooldown_sec)

            if pending_chunks > 0:

                cooldown = max(cooldown, 1.10 if weak_cpu else 0.82)

            if elapsed_ms >= 1200.0:

                cooldown = max(cooldown, 1.45 if weak_cpu else 1.00)

            if text_google:

                next_google_allowed_at = time.monotonic() + cooldown

            else:

                next_google_allowed_at = time.monotonic() + min(0.55, cooldown * 0.65)

            return text_google



        def decode_chunk(wav_bytes: bytes, pending_chunks: int = 0) -> str:

            if not wav_bytes:

                return ""

            prev_params = (

                int(self._fw_beam_size),

                int(self._fw_best_of),

                float(self._fw_patience),


            )


            if use_whisper_primary and pending_chunks >= 2:


                self._fw_beam_size = max(2, prev_params[0] - 1)


                self._fw_best_of = 1


                self._fw_patience = 1.0


            try:


                text = ""

                if use_vosk_primary:

                    text_vosk = self._transcribe_with_vosk(vosk_model, wav_bytes)

                    text_google = ""

                    should_try_google = pending_chunks <= 0 and (not text_vosk)

                    if should_try_google:

                        text_google = try_google_decode(wav_bytes, pending_chunks, force=False)

                        if text_google:

                            text_google = self._sanitize_google_wake_tail_for_small_vosk(text_google)

                    if text_vosk and not text_google:

                        return text_vosk

                    text = self._pick_best_candidate_text(text_vosk, text_google)

                    return text



                if use_whisper_primary:

                    text = self._transcribe_wav_bytes(wav_bytes, faster_model, openai_whisper_model)

                    if not text and vosk_model is not None:

                        text = self._transcribe_with_vosk(vosk_model, wav_bytes)

                    if not text and pending_chunks <= 0:

                        text = try_google_decode(wav_bytes, pending_chunks, force=False)

                    return text



                if use_google_primary:

                    text_vosk = ""

                    if vosk_model is not None:

                        text_vosk = self._transcribe_with_vosk(vosk_model, wav_bytes)

                        if text_vosk:

                            words = len(text_vosk.split())

                            hits = self._keyword_hit_count(text_vosk)

                            if hits > 0 or words >= 3:

                                return text_vosk

                    text_google = try_google_decode(wav_bytes, pending_chunks, force=not bool(text_vosk))

                    if not text_google and text_vosk:

                        return text_vosk

                    text = self._pick_best_candidate_text(text_google, text_vosk)

                    if not text and (faster_model is not None or openai_whisper_model is not None):

                        text = self._transcribe_wav_bytes(wav_bytes, faster_model, openai_whisper_model)

                    return text



                text = try_google_decode(wav_bytes, pending_chunks, force=True)

                if not text:

                    text = self._transcribe_with_vosk(vosk_model, wav_bytes)

                return text

            finally:

                self._fw_beam_size, self._fw_best_of, self._fw_patience = prev_params



        decode_avg_ms = 0.0

        decode_count = 0

        next_perf_report_at = time.monotonic() + 30.0



        def note_decode_timing(elapsed_ms: float, pending_chunks: int = 0) -> None:

            nonlocal decode_avg_ms, decode_count, next_perf_report_at

            duration = float(max(0.0, elapsed_ms))

            decode_count += 1

            # EMA-like running average without storing history.

            decode_avg_ms += (duration - decode_avg_ms) / float(max(1, decode_count))

            now = time.monotonic()

            if decode_count >= 10 and now >= next_perf_report_at:

                self.status_changed.emit(

                    f"ASR perf: avg decode {decode_avg_ms:.0f} ms/chunk, backlog={max(0, int(pending_chunks))}"

                )

                next_perf_report_at = now + 30.0



        self.status_changed.emit(f"Распознавание речи активно ({backend_name}, {capture_backend})")

        try:

            if microphone is not None:

                audio_queue: "queue.Queue[bytes]" = queue.Queue(maxsize=2)




                def _bg_callback(_rec: object, audio: object) -> None:

                    if self.isInterruptionRequested():

                        return

                    try:

                        wav_bytes = audio.get_wav_data(convert_rate=16000, convert_width=2)

                    except Exception:


                        return

                    self._enqueue_audio_chunk(audio_queue, wav_bytes)



                stop_listening = recognizer.listen_in_background(

                    microphone,

                    _bg_callback,

                    phrase_time_limit=float(phrase_time_limit),

                )


                try:

                    while not self.isInterruptionRequested():

                        try:

                            wav_bytes = audio_queue.get(timeout=0.08)

                        except queue.Empty:

                            continue



                        pending = int(audio_queue.qsize())

                        if pending >= 1:

                            # Prefer most recent chunk when decoder lags:

                            # this reduces latency and avoids decoding stale audio.

                            latest = wav_bytes

                            drained = 0

                            while True:

                                try:

                                    latest = audio_queue.get_nowait()

                                    drained += 1

                                except queue.Empty:

                                    break

                            if drained > 0:

                                wav_bytes = latest

                                pending = 0

                        decode_started = time.perf_counter()

                        text = decode_chunk(wav_bytes, pending)

                        note_decode_timing((time.perf_counter() - decode_started) * 1000.0, pending)

                        filtered = self._filter_repeated_text(text)

                        if filtered:

                            self.text_recognized.emit(filtered)

                finally:

                    try:

                        stop_listening(wait_for_stop=False)


                    except TypeError:


                        stop_listening()


                    except Exception:


                        pass


            else:

                sd_last_error_text = ""

                sd_last_error_ts = 0.0

                sd_reconfigure_ts = 0.0

                while not self.isInterruptionRequested():

                    try:

                        wav_bytes = self._record_chunk_with_sounddevice(sd, np, sd_input_device, sd_sample_rate)

                    except Exception as exc:

                        now = time.monotonic()

                        err_text = str(exc or "").strip()

                        invalid_device = self._is_sounddevice_invalid_device_error(exc)

                        if invalid_device and (now - float(sd_reconfigure_ts)) >= 0.45:

                            old_idx = sd_input_device

                            old_name = sd_input_name

                            old_rate = sd_sample_rate

                            try:

                                new_idx, new_name, new_rate = self._pick_sounddevice_capture_config(

                                    sd,

                                    preferred_device=preferred_sd_idx,

                                    preferred_name=(sd_input_name or selected_sr_name),

                                )

                                sd_input_device = new_idx

                                sd_input_name = new_name

                                sd_sample_rate = int(max(8000, min(192000, int(new_rate))))

                                sd_reconfigure_ts = now

                                if (sd_input_device, sd_input_name, sd_sample_rate) != (old_idx, old_name, old_rate):

                                    if sd_input_name:

                                        self.status_changed.emit(

                                            f"Переключен микрофон: {sd_input_name}@{sd_sample_rate}Hz"

                                        )

                                    else:

                                        self.status_changed.emit(

                                            f"Переключен микрофон: default@{sd_sample_rate}Hz"

                                        )

                                    continue

                            except Exception:

                                sd_reconfigure_ts = now

                        # Throttle repetitive errors to keep logs readable.

                        if (err_text != sd_last_error_text) or ((now - float(sd_last_error_ts)) >= 2.8):

                            self.error_changed.emit(f"Ошибка записи с микрофона: {exc}")

                            sd_last_error_text = err_text

                            sd_last_error_ts = now

                        self.msleep(320 if invalid_device else 280)

                        continue

                    if not wav_bytes:

                        continue

                    decode_started = time.perf_counter()

                    text = decode_chunk(wav_bytes, 0)

                    note_decode_timing((time.perf_counter() - decode_started) * 1000.0, 0)

                    filtered = self._filter_repeated_text(text)

                    if filtered:

                        self.text_recognized.emit(filtered)

        finally:

            self.status_changed.emit("Распознавание речи остановлено")







class HoverCardFrame(QFrame):

    def __init__(self) -> None:

        super().__init__()

        self.setAttribute(Qt.WA_Hover, True)

        self.setMouseTracking(True)

        self.setProperty("hovered", False)




    def _set_hovered(self, value: bool) -> None:

        state = bool(value)

        if bool(self.property("hovered")) == state:

            return

        self.setProperty("hovered", state)

        st = self.style()

        if st is not None:

            st.unpolish(self)

            st.polish(self)

        self.update()




    def enterEvent(self, event) -> None:


        self._set_hovered(True)


        super().enterEvent(event)





    def leaveEvent(self, event) -> None:

        self._set_hovered(False)

        super().leaveEvent(event)





class EditableHomePanel(HoverCardFrame):

    geometry_changed = Signal()



    def __init__(self, panel_key: str) -> None:

        super().__init__()

        self._panel_key = str(panel_key or "").strip().lower() or "panel"

        self._edit_enabled = False

        self._drag_active = False

        self._resize_active = False

        self._drag_offset = QPoint()

        self._start_rect = QRect()

        self._start_global = QPoint()

        self._min_w = 260

        self._min_h = 170

        self._handle_size = 16

        self._drag_strip_h = 38

        self.setProperty("_drag_block", True)



    def set_edit_enabled(self, enabled: bool) -> None:

        self._edit_enabled = bool(enabled)

        self._drag_active = False

        self._resize_active = False

        self.setCursor(Qt.OpenHandCursor if self._edit_enabled else Qt.ArrowCursor)

        self.update()



    def set_min_panel_size(self, width: int, height: int) -> None:

        self._min_w = max(180, int(width))

        self._min_h = max(130, int(height))



    def panel_key(self) -> str:

        return self._panel_key



    def _resize_hit(self, pos: QPoint) -> bool:

        r = self.rect()

        hs = int(self._handle_size)

        return (r.right() - hs) <= pos.x() <= r.right() and (r.bottom() - hs) <= pos.y() <= r.bottom()



    def _clamp_top_left(self, x: int, y: int, w: int, h: int) -> tuple[int, int]:

        parent = self.parentWidget()

        if parent is None:

            return x, y

        bounds = parent.rect()

        max_x = max(bounds.left(), bounds.right() - w + 1)

        max_y = max(bounds.top(), bounds.bottom() - h + 1)

        return max(bounds.left(), min(max_x, x)), max(bounds.top(), min(max_y, y))



    def _clamp_size(self, w: int, h: int, x: int, y: int) -> tuple[int, int]:

        parent = self.parentWidget()

        if parent is None:

            return max(self._min_w, w), max(self._min_h, h)

        bounds = parent.rect()

        max_w = max(self._min_w, bounds.width() - x)

        max_h = max(self._min_h, bounds.height() - y)

        return max(self._min_w, min(max_w, w)), max(self._min_h, min(max_h, h))



    def mousePressEvent(self, event) -> None:

        if not self._edit_enabled or event.button() != Qt.LeftButton:

            super().mousePressEvent(event)

            return



        pos = event.position().toPoint()

        if self._resize_hit(pos):

            self._resize_active = True

            self._drag_active = False

            self._start_rect = self.geometry()

            self._start_global = event.globalPosition().toPoint()

            self.setCursor(Qt.SizeFDiagCursor)

            event.accept()

            return



        # In layout edit mode, move panel freely from any point.

        self._drag_active = True

        self._resize_active = False

        self._drag_offset = event.globalPosition().toPoint() - self.frameGeometry().topLeft()

        self.setCursor(Qt.ClosedHandCursor)

        event.accept()

        return



    def mouseMoveEvent(self, event) -> None:

        if not self._edit_enabled:

            super().mouseMoveEvent(event)

            return



        if self._resize_active and (event.buttons() & Qt.LeftButton):

            delta = event.globalPosition().toPoint() - self._start_global

            new_w = int(self._start_rect.width() + delta.x())

            new_h = int(self._start_rect.height() + delta.y())

            x = int(self._start_rect.x())

            y = int(self._start_rect.y())

            clamped_w, clamped_h = self._clamp_size(new_w, new_h, x, y)

            self.setGeometry(x, y, clamped_w, clamped_h)

            self.geometry_changed.emit()

            event.accept()

            return



        if self._drag_active and (event.buttons() & Qt.LeftButton):

            global_pos = event.globalPosition().toPoint()

            target = global_pos - self._drag_offset

            x, y = self._clamp_top_left(int(target.x()), int(target.y()), self.width(), self.height())

            self.move(x, y)

            self.geometry_changed.emit()

            event.accept()

            return



        if self._resize_hit(event.position().toPoint()):

            self.setCursor(Qt.SizeFDiagCursor)

        else:

            self.setCursor(Qt.OpenHandCursor)

        super().mouseMoveEvent(event)



    def mouseReleaseEvent(self, event) -> None:

        if self._edit_enabled:

            was_active = self._drag_active or self._resize_active

            self._drag_active = False

            self._resize_active = False

            self.setCursor(Qt.OpenHandCursor if self._edit_enabled else Qt.ArrowCursor)

            if was_active:

                self.geometry_changed.emit()

                event.accept()

                return

        super().mouseReleaseEvent(event)



    def leaveEvent(self, event) -> None:

        if self._edit_enabled and not (self._drag_active or self._resize_active):

            self.setCursor(Qt.OpenHandCursor)

        super().leaveEvent(event)



    def paintEvent(self, event) -> None:

        super().paintEvent(event)

        if not self._edit_enabled:

            return

        painter = QPainter(self)

        painter.setRenderHint(QPainter.Antialiasing, True)

        rect = QRectF(self.rect()).adjusted(1.0, 1.0, -1.0, -1.0)

        pen = QPen(QColor(173, 197, 255, 170), 1.2)

        pen.setStyle(Qt.DashLine)

        painter.setPen(pen)

        painter.setBrush(Qt.NoBrush)

        painter.drawRoundedRect(rect, 10.0, 10.0)



        hs = float(self._handle_size)

        handle_rect = QRectF(self.width() - hs - 2.0, self.height() - hs - 2.0, hs, hs)

        painter.setPen(QPen(QColor(226, 236, 255, 210), 1.0))

        painter.setBrush(QColor(124, 148, 205, 140))

        painter.drawEllipse(handle_rect)

        painter.end()





class EditableVisualBounds(QWidget):

    geometry_changed = Signal()



    def __init__(self, parent: QWidget | None = None) -> None:

        super().__init__(parent)

        self._edit_enabled = False

        self._drag_active = False

        self._resize_active = False

        self._drag_offset = QPoint()

        self._start_rect = QRect()

        self._start_global = QPoint()

        self._min_w = 160

        self._min_h = 140

        self._handle_size = 16

        self.setProperty("_drag_block", True)

        self.setAttribute(Qt.WA_NoSystemBackground, True)

        self.setAttribute(Qt.WA_StyledBackground, False)

        self.hide()



    def set_edit_enabled(self, enabled: bool) -> None:

        state = bool(enabled)

        self._edit_enabled = state

        if not state:

            self._drag_active = False

            self._resize_active = False

            self.unsetCursor()

            self.hide()

            return

        self.show()

        self.setCursor(Qt.OpenHandCursor)

        self.update()



    def set_min_size_bounds(self, width: int, height: int) -> None:

        self._min_w = max(96, int(width))

        self._min_h = max(96, int(height))



    def is_interacting(self) -> bool:

        return bool(self._drag_active or self._resize_active)



    def _resize_hit(self, pos: QPoint) -> bool:

        r = self.rect()

        hs = int(self._handle_size)

        return (r.right() - hs) <= pos.x() <= r.right() and (r.bottom() - hs) <= pos.y() <= r.bottom()



    def _clamp_top_left(self, x: int, y: int, w: int, h: int) -> tuple[int, int]:

        parent = self.parentWidget()

        if parent is None:

            return x, y

        bounds = parent.rect()

        max_x = max(bounds.left(), bounds.right() - w + 1)

        max_y = max(bounds.top(), bounds.bottom() - h + 1)

        return max(bounds.left(), min(max_x, x)), max(bounds.top(), min(max_y, y))



    def _clamp_size(self, w: int, h: int, x: int, y: int) -> tuple[int, int]:

        parent = self.parentWidget()

        if parent is None:

            return max(self._min_w, w), max(self._min_h, h)

        bounds = parent.rect()

        max_w = max(self._min_w, bounds.width() - x)

        max_h = max(self._min_h, bounds.height() - y)

        return max(self._min_w, min(max_w, w)), max(self._min_h, min(max_h, h))



    def mousePressEvent(self, event) -> None:

        if not self._edit_enabled or event.button() != Qt.LeftButton:

            super().mousePressEvent(event)

            return

        pos = event.position().toPoint()

        if self._resize_hit(pos):

            self._resize_active = True

            self._drag_active = False

            self._start_rect = self.geometry()

            self._start_global = event.globalPosition().toPoint()

            self.setCursor(Qt.SizeFDiagCursor)

            event.accept()

            return

        self._drag_active = True

        self._resize_active = False

        self._drag_offset = event.globalPosition().toPoint() - self.frameGeometry().topLeft()

        self.setCursor(Qt.ClosedHandCursor)

        event.accept()



    def mouseMoveEvent(self, event) -> None:

        if not self._edit_enabled:

            super().mouseMoveEvent(event)

            return

        if self._resize_active and (event.buttons() & Qt.LeftButton):

            delta = event.globalPosition().toPoint() - self._start_global

            new_w = int(self._start_rect.width() + delta.x())

            new_h = int(self._start_rect.height() + delta.y())

            x = int(self._start_rect.x())

            y = int(self._start_rect.y())

            clamped_w, clamped_h = self._clamp_size(new_w, new_h, x, y)

            self.setGeometry(x, y, clamped_w, clamped_h)

            self.geometry_changed.emit()

            event.accept()

            return

        if self._drag_active and (event.buttons() & Qt.LeftButton):

            global_pos = event.globalPosition().toPoint()

            target = global_pos - self._drag_offset

            x, y = self._clamp_top_left(int(target.x()), int(target.y()), self.width(), self.height())

            self.move(x, y)

            self.geometry_changed.emit()

            event.accept()

            return

        if self._resize_hit(event.position().toPoint()):

            self.setCursor(Qt.SizeFDiagCursor)

        else:

            self.setCursor(Qt.OpenHandCursor)

        super().mouseMoveEvent(event)



    def mouseReleaseEvent(self, event) -> None:

        if self._edit_enabled:

            was_active = bool(self._drag_active or self._resize_active)

            self._drag_active = False

            self._resize_active = False

            self.setCursor(Qt.OpenHandCursor if self._edit_enabled else Qt.ArrowCursor)

            if was_active:

                self.geometry_changed.emit()

                event.accept()

                return

        super().mouseReleaseEvent(event)



    def leaveEvent(self, event) -> None:

        if self._edit_enabled and not self.is_interacting():

            self.setCursor(Qt.OpenHandCursor)

        super().leaveEvent(event)



    def paintEvent(self, event) -> None:

        super().paintEvent(event)

        if not self._edit_enabled:

            return

        painter = QPainter(self)

        painter.setRenderHint(QPainter.Antialiasing, True)

        rect = QRectF(self.rect()).adjusted(1.0, 1.0, -1.0, -1.0)

        pen = QPen(QColor(198, 216, 255, 192), 1.2)

        pen.setStyle(Qt.DashLine)

        painter.setPen(pen)

        painter.setBrush(Qt.NoBrush)

        painter.drawRoundedRect(rect, 10.0, 10.0)

        hs = float(self._handle_size)

        handle_rect = QRectF(self.width() - hs - 2.0, self.height() - hs - 2.0, hs, hs)

        painter.setPen(QPen(QColor(234, 242, 255, 230), 1.0))

        painter.setBrush(QColor(132, 160, 230, 160))

        painter.drawEllipse(handle_rect)

        painter.end()





class BackgroundWidget(QWidget):

    def __init__(self, palette: ThemePalette) -> None:

        super().__init__()

        self._palette = palette

        self._base_color = QColor("#05070c")

        self._corner_radius = 0

        # Default background waves are generated procedurally.

        self._wave_profile = None

        self._animations_enabled = True

        self._waves_suppressed = False

        self._phase = 0.0

        self._wave_blur = 0

        self._local_blur_effect: QGraphicsBlurEffect | None = None

        self._window_transparency = 20

        self._native_backdrop_available = False

        self._visual_variant = "waves1"

        self._preview_wave_image_path = ""

        self._preview_wave_pixmap: QPixmap | None = None

        self._preview_wave_profile: dict[str, object] | None = None

        self._preview_wave_scaled_cache_key: tuple[int, int, str] | None = None

        self._preview_wave_scaled_cache: QPixmap | None = None

        self._section_profiles: dict[int, tuple[float, float, float, float]] = {

            0: (162.0, 1.06, -0.10, 0.78),  # Home

            1: (202.0, 1.02, -0.08, 0.82),  # Command editor

            2: (196.0, 1.04, -0.08, 0.82),  # Plugins

            3: (212.0, 1.00, -0.06, 0.82),  # Settings

            4: (220.0, 1.00, -0.05, 0.84),  # Profile

        }

        self._section_target_shift_x = 162.0

        self._section_target_width_scale = 1.06

        self._section_target_rotation_deg = -0.10

        self._section_target_guard_ratio = 0.78

        self._section_shift_x = 162.0

        self._section_width_scale = 1.06

        self._section_rotation_deg = -0.10

        self._section_guard_ratio = 0.78

        self._user_wave_shift_x = 0.0

        self._user_wave_shift_y = 0.0

        self._user_wave_scale = 1.0

        self._user_wave_rotation_deg = 0.0

        cpu_count = int(os.cpu_count() or 4)

        self._low_power_mode = cpu_count <= 4

        self._phase_speed = 1.62 if self._low_power_mode else 1.74

        self._path_sample_step = 30 if self._low_power_mode else 28

        self._clock = QElapsedTimer()

        self._clock.start()

        self._last_ms = self._clock.elapsed()

        # Keep animation smooth but reduce CPU pressure.

        self._active_frame_interval_ms = 24 if self._low_power_mode else 22

        self._idle_frame_interval_ms = 46 if self._low_power_mode else 38

        self._frame_interval_ms = int(self._active_frame_interval_ms)

        self._idle_frame_skip = 0

        self._idle_frame_counter = 0

        self._smooth_dt = 1.0 / 60.0

        self._timer = QTimer(self)

        self._timer.setTimerType(Qt.PreciseTimer)

        self._timer.timeout.connect(self._animate)

        self._timer.start(self._frame_interval_ms)

        self._backdrop_cache_key: tuple[int, int, int, int] | None = None

        self._backdrop_cache: QPixmap | None = None

        self._fallback_blur_cache_key: tuple[object, ...] | None = None

        self._fallback_blur_cache: QPixmap | None = None

        self._profile_dist_cache: dict[tuple[int, int], list[list[float]]] = {}

        self._stars_cache_key: tuple[int, int] | None = None

        self._stars_cache: list[tuple[float, float, float, int]] = []

        # Load wave profile once so "waves1" stays close to base shape

        # (right-side concentric, slightly S-deformed layers).

        self._load_default_wave_profile_base()

        if self._wave_profile is None:

            self._wave_profile = self._load_wave_profile()

        self._apply_local_wave_blur_effect()




    def _ensure_anim_timer(self) -> None:

        if self._waves_suppressed or not self._animations_enabled:

            return

        if self._timer.isActive():

            return

        self._frame_interval_ms = int(self._active_frame_interval_ms)

        self._last_ms = self._clock.elapsed()

        self._timer.start(self._frame_interval_ms)



    def _stop_anim_timer_if_idle(self) -> None:

        if self._animations_enabled and not self._waves_suppressed:

            return

        if self._timer.isActive():

            self._timer.stop()



    def showEvent(self, event) -> None:

        super().showEvent(event)

        if self._animations_enabled and not self._waves_suppressed:

            self._ensure_anim_timer()



    def hideEvent(self, event) -> None:

        if self._timer.isActive():

            self._timer.stop()

        super().hideEvent(event)




    def set_palette(self, palette: ThemePalette) -> None:


        self._palette = palette


        self._invalidate_backdrop_cache()


        self.update()





    def set_background_color(self, color_text: str) -> bool:


        color = QColor(color_text)


        if not color.isValid():


            return False


        self._base_color = color


        self._invalidate_backdrop_cache()


        self.update()


        return True





    def set_wave_blur_strength(self, value: int) -> None:

        strength = max(0, min(100, int(value)))

        if self._wave_blur == strength:

            return

        self._wave_blur = strength

        self._apply_local_wave_blur_effect()

        self._invalidate_backdrop_cache()

        self.update()



    def _apply_local_wave_blur_effect(self) -> None:

        # Never blur the app widgets themselves. Blur must stay in OS/native

        # backdrop only (desktop behind window), not on Jarvis UI content.

        if self.graphicsEffect() is not None:

            self.setGraphicsEffect(None)

        self._local_blur_effect = None




    def set_window_transparency(self, value: int) -> None:

        transparency = max(0, min(100, int(value)))

        if self._window_transparency == transparency:

            return

        self._window_transparency = transparency

        self._invalidate_backdrop_cache()

        self.update()



    def set_native_backdrop_available(self, enabled: bool) -> None:

        value = bool(enabled)

        if self._native_backdrop_available == value:

            return

        self._native_backdrop_available = value

        self._fallback_blur_cache_key = None

        self._fallback_blur_cache = None

        self.update()



    def set_user_wave_transform(

        self,

        shift_x: float = 0.0,

        shift_y: float = 0.0,

        scale: float = 1.0,

        rotation_deg: float = 0.0,

    ) -> None:

        sx = float(shift_x)

        sy = float(shift_y)

        sc = max(0.55, min(1.65, float(scale)))

        rot = max(-35.0, min(35.0, float(rotation_deg)))

        if (

            abs(self._user_wave_shift_x - sx) < 1e-6

            and abs(self._user_wave_shift_y - sy) < 1e-6

            and abs(self._user_wave_scale - sc) < 1e-6

            and abs(self._user_wave_rotation_deg - rot) < 1e-6

        ):

            return

        self._user_wave_shift_x = sx

        self._user_wave_shift_y = sy

        self._user_wave_scale = sc

        self._user_wave_rotation_deg = rot

        self._fallback_blur_cache_key = None

        self._fallback_blur_cache = None

        self.update()




    def set_corner_radius(self, value: int) -> None:

        radius = max(0, min(96, int(value)))

        if self._corner_radius == radius:

            return

        self._corner_radius = radius

        self._invalidate_backdrop_cache()


        self.update()





    def resizeEvent(self, event) -> None:


        self._invalidate_backdrop_cache()


        super().resizeEvent(event)





    def _invalidate_backdrop_cache(self) -> None:

        self._backdrop_cache_key = None

        self._backdrop_cache = None

        self._fallback_blur_cache_key = None

        self._fallback_blur_cache = None

        self._profile_dist_cache.clear()

        self._stars_cache_key = None

        self._stars_cache = []



    def _ensure_stars_cache(self, width: int, height: int) -> None:

        key = (max(1, int(width)), max(1, int(height)))

        if self._stars_cache_key == key and self._stars_cache:

            return

        w, h = key

        stars: list[tuple[float, float, float, int]] = []

        count = max(80, min(220, int((w * h) / 12000)))

        for i in range(count):

            # Deterministic pseudo-random distribution without importing random.

            sx = ((i * 127.13) + (i * i * 17.7)) % max(1.0, float(w))

            sy = ((i * 311.71) + (i * i * 9.9)) % max(1.0, float(h))

            # Keep the left sidebar region calmer.

            if sx < (w * 0.18):

                sx += (w * 0.20)

            twinkle = int((i * 73) % 100)

            alpha = 36 + int((twinkle / 100.0) * 138)

            radius = 0.8 + ((i * 19) % 100) / 100.0

            stars.append((sx, sy, radius, alpha))

        self._stars_cache_key = key

        self._stars_cache = stars



    def _draw_starfield(self, painter: QPainter, width: int, height: int) -> None:

        self._ensure_stars_cache(width, height)

        if not self._stars_cache:

            return

        phase = self._phase if self._animations_enabled else 0.0

        for idx, (sx, sy, radius, alpha) in enumerate(self._stars_cache):

            tw = 0.84 + 0.16 * math.sin(phase * 1.36 + idx * 0.21)

            a = max(12, min(220, int(alpha * tw)))

            painter.setPen(Qt.NoPen)

            painter.setBrush(QColor(236, 242, 255, a))

            painter.drawEllipse(QRectF(sx, sy, radius, radius))

        # Signature diagonal streak like Grok hero background.

        painter.setPen(QPen(QColor(210, 224, 255, 118), 1.6, Qt.SolidLine, Qt.RoundCap))

        x0 = width * 0.18

        y0 = height * 0.06

        painter.drawLine(QPointF(x0, y0 + 26), QPointF(x0 + 42, y0 - 16))



    def _draw_gradient_variant(self, painter: QPainter, width: int, height: int) -> None:

        gradient = QLinearGradient(0.0, 0.0, float(width), float(height))

        base = QColor(self._base_color)

        start = _mix(base, QColor(self._palette.accent), 0.11)

        mid = _mix(base, QColor("#08101a"), 0.40)

        end = _mix(base, QColor("#020307"), 0.68)

        start.setAlpha(180)

        mid.setAlpha(206)

        end.setAlpha(226)

        gradient.setColorAt(0.0, start)

        gradient.setColorAt(0.58, mid)

        gradient.setColorAt(1.0, end)

        painter.fillRect(self.rect(), gradient)



    def _draw_neon_variant(self, painter: QPainter, width: int, height: int, phase: float) -> None:

        self._draw_gradient_variant(painter, width, height)

        accent = QColor(self._palette.accent)

        scale_mul = max(0.55, min(1.65, float(self._user_wave_scale)))

        shift_x = float(self._user_wave_shift_x)

        shift_y = float(self._user_wave_shift_y)



        orb_a = QRadialGradient(

            (float(width) * 0.30) + shift_x + math.sin(phase * 0.63) * 14.0,

            (float(height) * 0.38) + shift_y + math.cos(phase * 0.72) * 10.0,

            max(120.0, float(min(width, height)) * 0.34) * scale_mul,

        )

        a0 = QColor(accent)

        a0.setAlpha(112)

        a1 = QColor(a0)

        a1.setAlpha(0)

        orb_a.setColorAt(0.0, a0)

        orb_a.setColorAt(1.0, a1)

        painter.fillRect(self.rect(), orb_a)



        orb_b = QRadialGradient(

            (float(width) * 0.74) + shift_x + math.cos(phase * 0.50) * 9.0,

            (float(height) * 0.64) + shift_y + math.sin(phase * 0.67) * 8.0,

            max(100.0, float(min(width, height)) * 0.27) * scale_mul,

        )

        b0 = _mix(accent, QColor(255, 255, 255), 0.32)

        b0.setAlpha(86)

        b1 = QColor(b0)

        b1.setAlpha(0)

        orb_b.setColorAt(0.0, b0)

        orb_b.setColorAt(1.0, b1)

        painter.fillRect(self.rect(), orb_b)




    def _build_backdrop_cache(self, width: int, height: int) -> QPixmap:

        pm = QPixmap(width, height)

        pm.fill(Qt.transparent)



        painter = QPainter(pm)

        painter.setRenderHint(QPainter.Antialiasing, True)


        rect = QRectF(0.5, 0.5, max(1.0, width - 1.0), max(1.0, height - 1.0))


        path = QPainterPath()


        radius = float(self._corner_radius)


        path.addRoundedRect(rect, radius, radius)


        # Base canvas tone stays close to sidebar. In native blur mode we keep

        # this layer neutral-dark (no accent tint), so desktop blur color is not

        # shifted to blue/cyan by app-side painting.

        base = QColor(self._base_color)

        if not base.isValid():

            base = QColor("#06080c")

        blur = max(0, min(100, int(self._wave_blur)))

        transparency = max(0, min(100, int(self._window_transparency)))

        if self._native_backdrop_available and blur > 0:

            top = QColor(base)

            mid = QColor(base)

            bot = QColor(_mix(base, QColor("#030406"), 0.48))

            # Blur strength should be visually stronger at high values:

            # add denser neutral glass layer (still without accent tint).

            alpha_base = 72 + int(blur * 0.38) - int(transparency * 0.22)

            alpha_base = max(46, min(176, alpha_base))

            top.setAlpha(max(48, min(188, alpha_base + 8)))

            mid.setAlpha(max(44, min(180, alpha_base)))

            bot.setAlpha(max(50, min(186, alpha_base + 6)))

            glass_grad = QLinearGradient(0.0, 0.0, 0.0, float(height))

            glass_grad.setColorAt(0.0, top)

            glass_grad.setColorAt(0.56, mid)

            glass_grad.setColorAt(1.0, bot)

            painter.fillPath(path, glass_grad)



            painter.save()

            painter.setClipPath(path)

            bloom = QRadialGradient(

                float(width) * 0.56,

                float(height) * 0.40,

                max(float(width), float(height)) * 0.66,

            )

            # Neutral soft highlight only (avoid color-casting to accent hue).

            b0 = QColor(232, 238, 255)

            b0.setAlpha(max(4, min(18, 6 + int(blur * 0.06))))

            b1 = QColor(b0)

            b1.setAlpha(0)

            bloom.setColorAt(0.0, b0)

            bloom.setColorAt(1.0, b1)

            painter.fillRect(QRectF(0.0, 0.0, float(width), float(height)), bloom)

            painter.restore()



            # Avoid visible frame seam on the right edge in translucent mode.

        else:

            if transparency <= 0 and blur <= 0:

                # 0% transparency with blur=0 must be fully opaque.

                base.setAlpha(255)

            else:

                alpha = 244 - int(transparency * 1.26) - int(blur * 1.62)

                base.setAlpha(max(18, min(255, alpha)))

            painter.fillPath(path, base)

        painter.end()

        return pm




    def set_animations_enabled(self, enabled: bool) -> None:

        self._animations_enabled = bool(enabled)

        if self._animations_enabled:

            self._ensure_anim_timer()

        else:

            self._section_shift_x = self._section_target_shift_x


            self._section_width_scale = self._section_target_width_scale


            self._section_rotation_deg = self._section_target_rotation_deg


            self._stop_anim_timer_if_idle()

        self.update()



    def set_waves_suppressed(self, suppressed: bool) -> None:

        value = bool(suppressed)

        if self._waves_suppressed == value:

            return

        self._waves_suppressed = value

        if self._waves_suppressed:

            self._stop_anim_timer_if_idle()

        elif self._animations_enabled and self.isVisible():

            self._ensure_anim_timer()

        self.update()



    def set_visual_variant(self, variant: str) -> None:

        raw = str(variant or "").strip().lower()

        if raw in {"reactor", "реактор", "react"}:

            normalized = "reactor"

        elif raw in {

            "waves1",

            "wave1",

            "волны1",

            "волны 1",

            "хвилі1",

            "хвилі 1",

            "waves",

            "волны",

            "хвилі",

        }:

            normalized = "waves1"

        elif raw in {"circles", "circle", "круги", "круг", "кола", "коло", "rings"}:

            normalized = "circles"

        elif raw in {"gradient", "градиент", "градієнт"}:

            normalized = "gradient"

        elif raw in {"neon", "glow", "неон", "свечение", "сяйво"}:

            normalized = "neon"

        elif raw in {"life", "симуляцияжизни", "симуляция жизни", "life_sim", "симуляция", "жизнь"}:

            normalized = "life"

        else:

            normalized = "waves1"

        if self._visual_variant == normalized:

            return

        self._visual_variant = normalized

        self.update()



    def visual_variant(self) -> str:

        return str(self._visual_variant)



    def _default_preview_wave_image_path(self) -> str:

        base_dir = _app_resource_base_dir()

        home_dir = os.path.expanduser("~")

        candidates = [

            os.path.join(base_dir, "_current_preview_blurcheck2", "home_bgblur_0.png"),

            os.path.join(base_dir, "_current_preview_blurcheck", "home_blur_0.png"),

            os.path.join(base_dir, "photo_2026-04-08_12-08-56.jpg"),

            os.path.join(base_dir, "photo_2026-04-07_21-04-25.jpg"),

            os.path.join(home_dir, "OneDrive", "Desktop", "photo_2026-04-08_12-08-56.jpg"),

            os.path.join(home_dir, "OneDrive", "Desktop", "photo_2026-04-07_21-04-25.jpg"),

        ]

        for candidate in candidates:

            if os.path.exists(candidate):

                return candidate

        return ""



    def _load_default_wave_profile_base(self) -> None:

        default_path = self._default_preview_wave_image_path()

        if not default_path:

            return

        img = QImage(default_path)

        if img.isNull():

            return

        profile = self._extract_wave_profile_from_qimage(img)

        if profile is None:

            return

        self._wave_profile = profile



    def set_preview_wave_image(self, path: object) -> bool:

        raw = str(path or "").strip().strip('"')

        target = os.path.normpath(raw) if raw else ""

        if target and os.path.exists(target):

            pix = QPixmap(target)

            if not pix.isNull():

                self._preview_wave_image_path = target

                self._preview_wave_pixmap = pix

                self._preview_wave_profile = self._extract_wave_profile_from_qimage(pix.toImage())

                self._preview_wave_scaled_cache_key = None

                self._preview_wave_scaled_cache = None

                self.update()

                return True

        self._preview_wave_image_path = ""

        self._preview_wave_pixmap = None

        self._preview_wave_profile = None

        self._preview_wave_scaled_cache_key = None

        self._preview_wave_scaled_cache = None

        self.update()

        return False



    def preview_wave_image(self) -> str:

        return str(self._preview_wave_image_path or "")



    def _draw_life_variant(self, painter: QPainter, width: int, height: int, phase: float) -> None:

        self._draw_gradient_variant(painter, width, height)

        cell = 12

        accent = QColor(self._palette.accent)

        alive = QColor(accent)

        alive.setAlpha(95)

        ghost = QColor(_mix(accent, QColor("#9fc3ff"), 0.36))

        ghost.setAlpha(48)

        pen = QPen(QColor(255, 255, 255, 10), 1.0)

        painter.setPen(pen)

        for gy in range(0, height, cell):

            for gx in range(0, width, cell):

                v = (

                    math.sin((gx * 0.082) + (gy * 0.061) + phase * 1.10)

                    + math.sin((gx * 0.033) - phase * 0.86)

                    + math.cos((gy * 0.047) + phase * 0.64)

                )

                rect = QRectF(float(gx), float(gy), float(cell - 1), float(cell - 1))

                if v > 1.34:

                    painter.fillRect(rect, alive)

                elif v > 1.06:

                    painter.fillRect(rect, ghost)



    def _ellipse_wave_boundary(

        self,

        width: int,

        height: int,

        cx: float,

        cy: float,

        rx: float,

        ry: float,

        s_amp: float,

        s_phase: float,

    ) -> list[float]:

        h = max(2, int(height))

        xs: list[float] = []

        for y in range(h):

            t = (float(y) - cy) / max(1.0, ry)

            inside = 1.0 - (t * t)

            if inside <= 0.0:

                base_x = float(width) - 2.0

            else:

                base_x = cx - (rx * math.sqrt(inside))

            n = y / max(1.0, h - 1.0)

            s_curve = (

                s_amp * math.sin((n * math.tau * 1.18) + s_phase)

                + (s_amp * 0.62) * math.sin((n * math.tau * 2.26) + (s_phase * 0.64))

                + (s_amp * 0.24) * ((n - 0.5) ** 3) * 18.0

            )

            xs.append(min(float(width) - 1.0, base_x + s_curve))

        return self._smooth_series(xs, radius=8)



    def _superellipse_wave_boundary(

        self,

        width: int,

        height: int,

        cx: float,

        cy: float,

        rx: float,

        ry: float,

        exponent: float,

        deform_amp: float,

        deform_phase: float,

    ) -> list[float]:

        h = max(2, int(height))

        exp_v = max(2.0, float(exponent))

        xs: list[float] = []

        for y in range(h):

            t = (float(y) - cy) / max(1.0, ry)

            at = abs(t)

            if at >= 1.0:

                base_x = float(width) - 1.0

            else:

                inside = max(0.0, 1.0 - (at ** exp_v))

                base_x = cx - (rx * (inside ** (1.0 / exp_v)))

            n = y / max(1.0, h - 1.0)

            # Asymmetric bend tuned to base: stronger lower-right body

            # with soft S-like drift on the inner edge.

            bend = deform_amp * (

                0.44 * math.sin((n * math.tau * 0.90) + deform_phase)

                + 0.24 * math.sin((n * math.tau * 1.76) - (deform_phase * 0.62))

                - 0.34 * ((n - 0.80) ** 2 - 0.045)

            )

            x = min(float(width) - 1.0, base_x + bend)

            xs.append(x)

        return self._smooth_series(xs, radius=8)



    def _wave_overlay_opacity_scale(self) -> float:

        transparency = max(0, min(100, int(self._window_transparency)))

        if transparency <= 0:

            return 1.0

        scale = 1.0 - ((transparency / 100.0) * 0.28)

        return max(0.70, min(1.0, scale))



    def _draw_base_tint_overlay(self, painter: QPainter, width: int, height: int) -> None:

        # Keep a consistent window tone (same direction as sidebar color) and

        # suppress excessive color-cast from animated layers.

        blur = max(0, min(100, int(self._wave_blur)))

        transparency = max(0, min(100, int(self._window_transparency)))

        if self._native_backdrop_available and blur > 0:

            alpha = int(6 + (blur * 0.12) + (transparency * 0.06))

            alpha = max(4, min(22, alpha))

        else:

            alpha = int(78 + (blur * 0.08) + (transparency * 0.24))

            alpha = max(62, min(128, alpha))

        tint = QColor(self._base_color)

        tint.setAlpha(alpha)

        painter.fillRect(QRectF(0.0, 0.0, float(width), float(height)), tint)



    def _wave_clip_rect(self, width: int, height: int) -> QRectF:

        start = float(width) * 0.50

        return QRectF(start, 0.0, max(1.0, float(width) - start), float(height))



    def _draw_wave_left_blend(self, painter: QPainter, width: int, height: int) -> None:

        base = QColor("#06080c")

        blend = QLinearGradient(float(width) * 0.44, 0.0, float(width) * 0.62, 0.0)

        c0 = QColor(base)

        c1 = QColor(base)

        c2 = QColor(base)

        c3 = QColor(base)

        blur = max(0, min(100, int(self._wave_blur)))

        native = bool(self._native_backdrop_available and blur > 0)

        alpha_scale = 0.62 if native else 1.0

        c0.setAlpha(int(255 * alpha_scale))

        c1.setAlpha(int(236 * alpha_scale))

        c2.setAlpha(int(92 * alpha_scale))

        c3.setAlpha(0)

        blend.setColorAt(0.0, c0)

        blend.setColorAt(0.34, c1)

        blend.setColorAt(0.76, c2)

        blend.setColorAt(1.0, c3)

        painter.fillRect(QRectF(0.0, 0.0, float(width), float(height)), blend)



    def _draw_concentric_waves(

        self,

        painter: QPainter,

        width: int,

        height: int,

        phase: float,

        motion_scale: float = 1.0,

        brightness_boost: float = 0.0,

    ) -> None:

        """base-style right-side concentric wave rings."""

        opacity_scale = self._wave_overlay_opacity_scale()

        accent = QColor(self._palette.accent)

        ring0 = QColor(self._palette.rings[0])

        ring1 = QColor(self._palette.rings[1])

        ring2 = QColor(self._palette.rings[2])

        ring3 = QColor(self._palette.rings[3])



        w = max(2, int(width))

        h = max(2, int(height))

        scale_mul = max(0.55, min(1.65, float(self._user_wave_scale)))

        # Match base: center pushed further to the right, rings open into

        # the scene from the right edge and sit slightly lower.

        cx = (w * 1.12) + self._user_wave_shift_x + math.sin(phase * 0.20) * (1.6 * motion_scale)

        cy = (h * 0.555) + self._user_wave_shift_y + math.cos(phase * 0.16) * (1.0 * motion_scale)



        # Closer to base: broader concentric arcs on the right with

        # minimal wobble and stable center.

        outer_rx = max(90.0, float(h) * 0.79) * scale_mul

        outer_ry = max(90.0, float(h) * 1.08) * scale_mul

        step_rx = max(20.0, float(h) * 0.095) * max(0.65, scale_mul)

        step_ry = max(18.0, float(h) * 0.104) * max(0.65, scale_mul)

        ring_count = 5



        colors = [

            _mix(ring0, QColor("#000000"), 0.40),

            _mix(ring1, QColor("#000000"), 0.32),

            _mix(ring2, QColor("#000000"), 0.24),

            _mix(ring3, QColor("#000000"), 0.16),

            _mix(accent, QColor("#ffffff"), 0.18),

        ]

        alphas = [230, 220, 208, 198, 188]

        if brightness_boost != 0.0:

            alphas = [int(max(0, min(255, a + brightness_boost * 26.0))) for a in alphas]



        steps = 176 if self._low_power_mode else 208



        def ring_path(cx_i: float, cy_i: float, rx_i: float, ry_i: float, warp: float, ring_phase: float) -> QPainterPath:

            path = QPainterPath()

            for i in range(steps + 1):

                t = (math.tau * float(i)) / float(steps)

                ct = math.cos(t)

                st = math.sin(t)

                x = cx_i + (rx_i * ct)

                y = cy_i + (ry_i * st)

                # Keep lines almost circular (no strong S-warps).

                left_bias = 0.30 + 0.70 * max(0.0, -ct)

                x += warp * (

                    (0.18 * left_bias) * math.sin((2.0 * t) + ring_phase)

                    + (0.09 * left_bias) * math.sin((4.0 * t) - (ring_phase * 0.62))

                    + (0.20 * left_bias) * (st ** 3)

                )

                y += (warp * 0.10 * left_bias) * math.sin((1.55 * t) + (ring_phase * 0.56))

                y += (warp * 0.04 * left_bias) * (ct ** 3)

                if i == 0:

                    path.moveTo(x, y)

                else:

                    path.lineTo(x, y)

            path.closeSubpath()

            return path



        painter.setPen(Qt.NoPen)

        for idx in range(ring_count):

            rx = outer_rx - (idx * step_rx)

            ry = outer_ry - (idx * step_ry)

            if rx <= 2.0 or ry <= 2.0:

                continue

            direction = 1.0 if (idx % 2 == 0) else -0.50

            drift_x = math.sin(phase * (0.20 + idx * 0.024) * direction + idx * 0.42) * (0.65 + idx * 0.08) * motion_scale

            drift_y = math.cos(phase * (0.18 + idx * 0.020) * direction + idx * 0.38) * (0.46 + idx * 0.06) * motion_scale

            ring_phase = (

                phase * (0.58 + idx * 0.082) * direction

                + (idx * 0.44)

                + math.radians(self._user_wave_rotation_deg) * 0.58

            )

            warp = max(1.2, float(h) * 0.0082) * (1.0 + idx * 0.08) * motion_scale



            c = QColor(colors[min(idx, len(colors) - 1)])

            a = int(alphas[min(idx, len(alphas) - 1)] * opacity_scale)

            c.setAlpha(max(0, min(255, a)))

            painter.setBrush(c)

            painter.drawPath(ring_path(cx + drift_x, cy + drift_y, rx, ry, warp, ring_phase))



    def _wave_band_path(self, outer_boundary: list[float], inner_boundary: list[float], height: int) -> QPainterPath:

        path = QPainterPath()

        path.setFillRule(Qt.WindingFill)

        if not outer_boundary or not inner_boundary:

            return path

        h = max(1, min(int(height), len(outer_boundary), len(inner_boundary)))

        if h <= 0:

            return path

        path.moveTo(outer_boundary[0], 0.0)

        for y in range(1, h):

            path.lineTo(outer_boundary[y], float(y))

        for y in range(h - 1, -1, -1):

            path.lineTo(inner_boundary[y], float(y))

        path.closeSubpath()

        return path



    def _draw_wave_style_one(self, painter: QPainter, width: int, height: int, phase: float) -> None:

        draw_waves1_background(
            painter,
            width,
            height,
            phase,
            self._palette,
            user_shift_x=float(self._user_wave_shift_x),
            user_shift_y=float(self._user_wave_shift_y),
            user_scale=float(self._user_wave_scale),
            user_rotation_deg=float(self._user_wave_rotation_deg),
            opacity_scale=float(self._wave_overlay_opacity_scale()),
            animations_enabled=bool(self._animations_enabled),
        )

        return



    def _draw_right_wave_fallback(self, painter: QPainter, width: int, height: int, phase: float) -> None:

        w = max(2, int(width))

        h = max(2, int(height))

        scale_mul = max(0.55, min(1.65, float(self._user_wave_scale)))

        cx = (w * 1.10) + float(self._user_wave_shift_x) + math.sin(phase * 0.25) * 1.4

        cy = (h * 0.545) + float(self._user_wave_shift_y) + math.cos(phase * 0.21) * 1.0



        outer_rx = max(86.0, float(h) * 0.84) * scale_mul

        outer_ry = max(94.0, float(h) * 1.08) * scale_mul

        step_rx = max(16.0, float(h) * 0.102) * scale_mul

        step_ry = max(15.0, float(h) * 0.108) * scale_mul



        accent = QColor(self._palette.accent)

        colors = [

            QColor(self._palette.rings[0]),

            QColor(self._palette.rings[1]),

            QColor(self._palette.rings[2]),

            QColor(self._palette.rings[3]),

            _mix(accent, QColor("#ffffff"), 0.12),

        ]

        alphas = [228, 222, 216, 210, 204]

        opacity_scale = self._wave_overlay_opacity_scale()



        painter.setPen(Qt.NoPen)

        for idx in range(5):

            rx = outer_rx - (idx * step_rx)

            ry = outer_ry - (idx * step_ry)

            if rx <= 4.0 or ry <= 4.0:

                continue

            s_amp = max(1.8, float(h) * (0.0065 + idx * 0.0013)) * max(0.75, scale_mul)

            drift_x = math.sin(phase * (0.42 + idx * 0.06) + idx * 0.38) * (1.0 + idx * 0.08)

            drift_y = math.cos(phase * (0.36 + idx * 0.05) + idx * 0.31) * (0.8 + idx * 0.06)

            boundary = self._ellipse_wave_boundary(

                w,

                h,

                cx + drift_x,

                cy + drift_y,

                rx,

                ry,

                s_amp,

                phase * (0.58 + idx * 0.08) + (idx * 0.34),

            )

            c = QColor(colors[idx])

            c.setAlpha(max(0, min(255, int(alphas[idx] * opacity_scale))))

            painter.setBrush(c)

            painter.drawPath(self._wave_fill_path(boundary, float(w), h))



    def _draw_reactor_variant(self, painter: QPainter, width: int, height: int, phase: float) -> None:

        opacity_scale = self._wave_overlay_opacity_scale()

        accent = QColor(self._palette.accent)

        ring_colors = [QColor(c) for c in self._palette.rings]

        base_grad = QLinearGradient(0.0, 0.0, 0.0, float(height))

        top_bg = _mix(QColor("#070a12"), accent, 0.12)

        mid_bg = _mix(QColor("#050911"), accent, 0.16)

        bot_bg = _mix(QColor("#03060c"), accent, 0.10)

        top_bg.setAlpha(max(0, min(255, int(252 * opacity_scale))))

        mid_bg.setAlpha(max(0, min(255, int(250 * opacity_scale))))

        bot_bg.setAlpha(max(0, min(255, int(252 * opacity_scale))))

        base_grad.setColorAt(0.0, top_bg)

        base_grad.setColorAt(0.52, mid_bg)

        base_grad.setColorAt(1.0, bot_bg)

        painter.fillRect(QRectF(0.0, 0.0, float(width), float(height)), base_grad)



        scale_mul = max(0.55, min(1.65, float(self._user_wave_scale)))

        cx = (float(width) * 0.84) + float(self._user_wave_shift_x) + math.sin(phase * 0.34) * 2.4

        cy = (float(height) * 0.52) + float(self._user_wave_shift_y) + math.cos(phase * 0.30) * 1.7

        radius = max(80.0, float(min(width, height)) * 0.44) * scale_mul



        core = QRadialGradient(cx, cy, radius * 0.24)

        core_a = _mix(accent, QColor("#ffffff"), 0.34)

        core_a.setAlpha(max(0, min(255, int(206 * opacity_scale))))

        core_b = _mix(accent, QColor("#00131f"), 0.46)

        core_b.setAlpha(max(0, min(255, int(116 * opacity_scale))))

        core_c = QColor(0, 0, 0, 0)

        core.setColorAt(0.0, core_a)

        core.setColorAt(0.46, core_b)

        core.setColorAt(1.0, core_c)

        painter.setPen(Qt.NoPen)

        painter.setBrush(core)

        painter.drawEllipse(QRectF(cx - radius * 0.34, cy - radius * 0.34, radius * 0.68, radius * 0.68))



        ring_pen_widths = (5.2, 4.2, 3.4, 2.8)

        for idx, col in enumerate((ring_colors[0], ring_colors[1], ring_colors[2], ring_colors[3])):

            ring_r = radius * (0.30 + idx * 0.12)

            alpha = max(0, min(255, int((188 - idx * 24) * opacity_scale)))

            c = _mix(col, accent, 0.18)

            c.setAlpha(alpha)

            pen = QPen(c, ring_pen_widths[idx], Qt.SolidLine, Qt.RoundCap)

            painter.setPen(pen)

            painter.setBrush(Qt.NoBrush)

            rect = QRectF(cx - ring_r, cy - ring_r, ring_r * 2.0, ring_r * 2.0)

            painter.drawEllipse(rect)

            start_angle = int(

                (

                    phase * (24.0 + idx * 6.0)

                    + idx * 58.0

                    + (self._user_wave_rotation_deg * 1.8)

                )

                * 16.0

            )

            span_angle = int((210.0 - idx * 22.0) * 16.0)

            painter.drawArc(rect.adjusted(-2.0, -2.0, 2.0, 2.0), start_angle, span_angle)



        left_fade = QLinearGradient(0.0, 0.0, float(width) * 0.72, 0.0)

        left_fade.setColorAt(0.0, QColor(0, 0, 0, 224))

        left_fade.setColorAt(0.48, QColor(0, 0, 0, 114))

        left_fade.setColorAt(1.0, QColor(0, 0, 0, 0))

        painter.fillRect(QRectF(0.0, 0.0, float(width), float(height)), left_fade)



    def _draw_circles_variant(self, painter: QPainter, width: int, height: int, phase: float) -> None:

        opacity_scale = self._wave_overlay_opacity_scale()

        w = max(2, int(width))

        h = max(2, int(height))

        motion = 1.0 if self._animations_enabled else 0.0

        scale_mul = max(0.55, min(1.65, float(self._user_wave_scale)))

        shift_x = float(self._user_wave_shift_x)

        shift_y = float(self._user_wave_shift_y)

        drift_x = math.sin(phase * 0.18) * 0.8 * motion

        drift_y = math.cos(phase * 0.15) * 0.6 * motion



        base_grad = QLinearGradient(0.0, 0.0, 0.0, float(h))

        top_bg = QColor(9, 11, 17, max(0, min(255, int(252 * opacity_scale))))

        mid_bg = QColor(6, 8, 13, max(0, min(255, int(250 * opacity_scale))))

        bot_bg = QColor(5, 7, 12, max(0, min(255, int(252 * opacity_scale))))

        base_grad.setColorAt(0.0, top_bg)

        base_grad.setColorAt(0.60, mid_bg)

        base_grad.setColorAt(1.0, bot_bg)

        painter.fillRect(QRectF(0.0, 0.0, float(w), float(h)), base_grad)



        accent = QColor(self._palette.accent)

        ring0 = QColor(self._palette.rings[0])

        ring1 = QColor(self._palette.rings[1])

        ring2 = QColor(self._palette.rings[2])

        ring3 = QColor(self._palette.rings[3])



        cx = (float(w) * 1.06) + shift_x + drift_x

        cy = (float(h) * 1.02) + shift_y + drift_y

        size_mul = 1.12

        outer_rx = max(112.0, float(w) * 0.52) * scale_mul * size_mul

        outer_ry = max(96.0, float(h) * 0.44) * scale_mul * size_mul

        step_rx = max(12.0, float(w) * 0.062) * scale_mul * size_mul

        step_ry = max(10.0, float(h) * 0.056) * scale_mul * size_mul

        motion_bias = 0.24 + (0.76 * motion)



        ring_colors = [

            _mix(ring0, QColor("#000000"), 0.38),

            _mix(ring1, QColor("#000000"), 0.31),

            _mix(ring2, QColor("#000000"), 0.24),

            _mix(ring3, QColor("#000000"), 0.16),

            _mix(accent, QColor("#8fb4ff"), 0.22),

        ]

        ring_alpha = [236, 230, 224, 218, 212]



        painter.setPen(Qt.NoPen)

        right_inset = max(0.8, float(w) * 0.0012)

        edge_x = float(w) - 1.0 - right_inset

        phase_base = (phase * 0.30) + (math.radians(self._user_wave_rotation_deg) * 0.56)

        boundaries: list[list[float]] = []



        for idx in range(len(ring_colors)):

            rx = outer_rx - (idx * step_rx)

            ry = outer_ry - (idx * step_ry)

            if rx <= 8.0 or ry <= 8.0:

                continue

            deform_amp = max(1.1, float(h) * 0.0064) * (1.0 + idx * 0.09) * motion_bias

            layer_cx = cx + (idx * max(6.0, float(w) * 0.010))

            boundary = self._superellipse_wave_boundary(

                w,

                h,

                layer_cx,

                cy,

                rx,

                ry,

                2.20 + idx * 0.05,

                deform_amp,

                phase_base + idx * 0.46,

            )

            top_guard = min(len(boundary), max(8, int(h * 0.028)))

            if top_guard > 2:

                anchor = float(boundary[top_guard - 1])

                cap_x = max(anchor, edge_x - (0.75 + idx * 0.17))

                for y in range(top_guard):

                    u = y / max(1.0, float(top_guard - 1))

                    boundary[y] = (cap_x * (1.0 - u)) + (boundary[y] * u)

            boundaries.append([max(0.0, min(edge_x, x)) for x in boundary])



        if boundaries:

            rows = min(len(b) for b in boundaries)

            min_gap = max(0.55, float(h) * 0.0009)

            for _ in range(2):

                for y in range(rows):

                    prev = boundaries[0][y]

                    for idx in range(1, len(boundaries)):

                        cur = boundaries[idx][y]

                        need = prev + min_gap

                        if cur < need:

                            cur = need

                        boundaries[idx][y] = min(edge_x, cur)

                        prev = boundaries[idx][y]

                for idx in range(len(boundaries)):

                    boundaries[idx] = self._smooth_series(boundaries[idx], radius=2)



            seam_overlap = max(1.8, float(h) * 0.0030)

            for idx, boundary in enumerate(boundaries):

                c = QColor(ring_colors[min(idx, len(ring_colors) - 1)])

                c.setAlpha(max(0, min(255, int(ring_alpha[min(idx, len(ring_alpha) - 1)] * opacity_scale))))

                painter.setBrush(c)

                overlap = 0.0 if idx == 0 else seam_overlap

                layer_boundary = [max(0.0, min(edge_x, x - overlap)) for x in boundary[:rows]]

                painter.drawPath(self._wave_fill_path(layer_boundary, edge_x, rows))



            # Suppress a thin vertical seam on the brightest inner boundary.

            inner = boundaries[-1]

            if inner:

                seam_x = float(inner[min(len(inner) - 1, len(inner) // 2)])

                if seam_x > float(w) * 0.72:

                    seam_half_w = max(2.0, float(w) * 0.0034)

                    seam = QLinearGradient(seam_x - seam_half_w, 0.0, seam_x + seam_half_w, 0.0)

                    seam.setColorAt(0.0, QColor(0, 0, 0, 0))

                    seam.setColorAt(0.48, QColor(5, 8, 14, max(0, min(255, int(188 * opacity_scale)))))

                    seam.setColorAt(0.52, QColor(5, 8, 14, max(0, min(255, int(188 * opacity_scale)))))

                    seam.setColorAt(1.0, QColor(0, 0, 0, 0))

                    painter.fillRect(QRectF(seam_x - seam_half_w, 0.0, seam_half_w * 2.0, float(h)), seam)



        left_fade = QLinearGradient(0.0, 0.0, float(w) * 0.74, 0.0)

        left_fade.setColorAt(0.0, QColor(0, 0, 0, 246))

        left_fade.setColorAt(0.12, QColor(0, 0, 0, 232))

        left_fade.setColorAt(0.52, QColor(0, 0, 0, 120))

        left_fade.setColorAt(1.0, QColor(0, 0, 0, 0))

        painter.fillRect(QRectF(0.0, 0.0, float(w), float(h)), left_fade)



    def _draw_visual_variant(self, painter: QPainter, width: int, height: int, phase: float, variant: str) -> None:

        if variant in {"waves", "waves1"}:

            self._draw_wave_style_one(painter, width, height, phase)

        elif variant == "circles":

            self._draw_circles_variant(painter, width, height, phase)

        elif variant == "reactor":

            self._draw_reactor_variant(painter, width, height, phase)

        elif variant == "gradient":

            self._draw_gradient_variant(painter, width, height)

        elif variant == "neon":

            self._draw_neon_variant(painter, width, height, phase)

        elif variant == "life":

            self._draw_life_variant(painter, width, height, phase)

        else:

            self._draw_wave_style_one(painter, width, height, phase)



    def _soften_pixmap(self, source: QPixmap, blur_strength: int) -> QPixmap:

        if source.isNull():

            return source

        strength = max(0, min(100, int(blur_strength)))

        if strength <= 0:

            return source

        w = max(1, source.width())

        h = max(1, source.height())

        scale = max(0.22, 1.0 - (strength / 125.0))

        sw = max(1, int(w * scale))

        sh = max(1, int(h * scale))

        down = source.scaled(sw, sh, Qt.IgnoreAspectRatio, Qt.SmoothTransformation)

        return down.scaled(w, h, Qt.IgnoreAspectRatio, Qt.SmoothTransformation)



    def _draw_preview_wave_variant(self, painter: QPainter, width: int, height: int, phase: float) -> None:

        opacity_scale = self._wave_overlay_opacity_scale()

        base_grad = QLinearGradient(0.0, 0.0, 0.0, float(height))

        base_grad.setColorAt(0.0, QColor(4, 6, 10, max(0, min(255, int(252 * opacity_scale)))))

        base_grad.setColorAt(0.56, QColor(3, 5, 8, max(0, min(255, int(250 * opacity_scale)))))

        base_grad.setColorAt(1.0, QColor(2, 3, 5, max(0, min(255, int(252 * opacity_scale)))))

        painter.fillRect(QRectF(0.0, 0.0, float(width), float(height)), base_grad)

        if self._preview_wave_profile is None:

            if not self.set_preview_wave_image(self._preview_wave_image_path):

                profile = self._wave_profile

            else:

                profile = self._preview_wave_profile

        else:

            profile = self._preview_wave_profile



        self._draw_vector_waves_from_profile(

            painter,

            width,

            height,

            phase,

            profile,

            preview_mode=True,

            use_style_palette=True,

        )



        # Smooth left fade so base waves blend into black background.

        fade = QLinearGradient(float(width) * 0.22, 0.0, float(width) * 0.74, 0.0)

        fade.setColorAt(0.0, QColor(0, 0, 0, 210))

        fade.setColorAt(0.35, QColor(0, 0, 0, 136))

        fade.setColorAt(0.70, QColor(0, 0, 0, 54))

        fade.setColorAt(1.0, QColor(0, 0, 0, 0))

        painter.fillRect(QRectF(0.0, 0.0, float(width), float(height)), fade)

        vfade = QLinearGradient(0.0, 0.0, 0.0, float(height))

        vfade.setColorAt(0.0, QColor(0, 0, 0, 132))

        vfade.setColorAt(0.20, QColor(0, 0, 0, 76))

        vfade.setColorAt(0.58, QColor(0, 0, 0, 28))

        vfade.setColorAt(1.0, QColor(0, 0, 0, 0))

        painter.fillRect(QRectF(0.0, 0.0, float(width), float(height)), vfade)



    def set_section_context(self, section_index: int) -> None:

        shift_x, width_scale, rotation_deg, guard_ratio = self._section_profiles.get(

            int(section_index),

            self._section_profiles[0],

        )

        self._section_target_shift_x = float(shift_x)


        self._section_target_width_scale = float(width_scale)


        self._section_target_rotation_deg = float(rotation_deg)


        self._section_target_guard_ratio = float(guard_ratio)


        if not self._animations_enabled:


            self._section_shift_x = self._section_target_shift_x


            self._section_width_scale = self._section_target_width_scale


            self._section_rotation_deg = self._section_target_rotation_deg


            self._section_guard_ratio = self._section_target_guard_ratio


            self._stop_anim_timer_if_idle()


        else:


            self._ensure_anim_timer()


        self.update()





    def _animate(self) -> None:

        if self._waves_suppressed:

            self._stop_anim_timer_if_idle()

            return

        if not self._animations_enabled:

            self._stop_anim_timer_if_idle()

            return

        if not self.isVisible():

            if self._timer.isActive():

                self._timer.stop()

            return

        now_ms = self._clock.elapsed()

        dt = max(0.0, min(0.08, (now_ms - self._last_ms) / 1000.0))

        self._last_ms = now_ms

        self._smooth_dt = (self._smooth_dt * 0.66) + (dt * 0.34)

        dt_anim = self._smooth_dt

        # Keep phase continuous to avoid periodic jump in reactor/waves motion.

        self._phase += dt_anim * self._phase_speed

        if self._phase > 1_000_000.0:

            self._phase -= 1_000_000.0



        # Smooth context transition between pages.

        blend = min(1.0, dt_anim * 4.4)

        self._section_shift_x += (self._section_target_shift_x - self._section_shift_x) * blend

        self._section_width_scale += (self._section_target_width_scale - self._section_width_scale) * blend

        self._section_rotation_deg += (self._section_target_rotation_deg - self._section_rotation_deg) * blend

        self._section_guard_ratio += (self._section_target_guard_ratio - self._section_guard_ratio) * blend

        transition_gap = (

            abs(self._section_target_shift_x - self._section_shift_x)

            + abs(self._section_target_width_scale - self._section_width_scale) * 180.0

            + abs(self._section_target_rotation_deg - self._section_rotation_deg) * 2.0

            + abs(self._section_target_guard_ratio - self._section_guard_ratio) * 260.0

        )

        target_interval = self._idle_frame_interval_ms if transition_gap < 0.32 else self._active_frame_interval_ms

        if int(target_interval) != int(self._frame_interval_ms):

            self._frame_interval_ms = int(target_interval)

            if self._timer.isActive():

                self._timer.start(self._frame_interval_ms)

        if transition_gap < 0.32 and self._idle_frame_skip > 0:

            self._idle_frame_counter = (self._idle_frame_counter + 1) % (self._idle_frame_skip + 1)

            if self._idle_frame_counter != 0:

                return

        self.update()




    def _profile_distances_for_height(


        self,


        distance_layers: list[list[float]],


        ref_h: float,


        h_cur: int,


        trim_ref: float,


        usable_h: float,


    ) -> list[list[float]]:


        cache_key = (h_cur, int(ref_h))


        cached = self._profile_dist_cache.get(cache_key)


        if cached is not None:


            return cached





        prepared: list[list[float]] = []


        for dist_series in distance_layers:


            if not isinstance(dist_series, list) or not dist_series:


                continue


            sampled: list[float] = []


            for y in range(h_cur):


                u = y / max(1.0, h_cur - 1)


                y_ref = trim_ref + u * usable_h


                sampled.append(self._sample_series(dist_series, y_ref))


            prepared.append(self._smooth_series(sampled, radius=8))


        self._profile_dist_cache[cache_key] = prepared


        return prepared





    def _fill_missing_series(self, values: list[float | None]) -> list[float]:


        if not values:


            return []


        out: list[float | None] = [float(v) if v is not None else None for v in values]


        first_idx = None


        for i, v in enumerate(out):


            if v is not None:


                first_idx = i


                break


        if first_idx is None:


            return [0.0] * len(values)





        first_val = out[first_idx]


        for i in range(first_idx):


            out[i] = first_val





        prev_idx = first_idx


        for i in range(first_idx + 1, len(out)):


            if out[i] is None:


                continue


            gap = i - prev_idx


            if gap > 1:


                start = out[prev_idx]


                end = out[i]


                for j in range(1, gap):


                    out[prev_idx + j] = start + (end - start) * (j / gap)


            prev_idx = i





        tail = out[prev_idx]


        for i in range(prev_idx + 1, len(out)):


            out[i] = tail


        return [float(v) for v in out]





    def _smooth_series(self, values: list[float], radius: int = 6) -> list[float]:


        if not values:


            return []


        smoothed: list[float] = []


        n = len(values)


        for i in range(n):


            a = max(0, i - radius)


            b = min(n, i + radius + 1)


            smoothed.append(sum(values[a:b]) / (b - a))


        return smoothed





    def _sample_series(self, values: list[float], pos: float) -> float:


        if not values:


            return 0.0


        if pos <= 0:


            return values[0]


        last = len(values) - 1


        if pos >= last:


            return values[last]


        i = int(pos)


        t = pos - i


        return values[i] * (1.0 - t) + values[i + 1] * t




    def _wave_fill_path(self, boundary_x: list[float], width: float, height: int) -> QPainterPath:

        path = QPainterPath()

        path.setFillRule(Qt.WindingFill)

        if not boundary_x:

            return path

        h = max(1, min(int(height), len(boundary_x)))

        edge_x = float(width)

        clipped: list[float] = []

        for y in range(h):

            x = boundary_x[y]

            if not math.isfinite(x):

                x = edge_x

            clipped.append(max(0.0, min(edge_x, float(x))))



        # Trim rows where boundary lies on the right edge: such degenerate

        # zero-width segments can render as a 1px vertical seam.

        edge_eps = 0.55

        start = 0

        while start < h and clipped[start] >= edge_x - edge_eps:

            start += 1

        end = h - 1

        while end >= start and clipped[end] >= edge_x - edge_eps:

            end -= 1

        if start >= h or end < start:

            return path



        path.moveTo(clipped[start], float(start))

        # Keep path monotonic by Y with plain segments; this avoids occasional

        # self-intersections from cubic smoothing that can create black cracks.

        for y in range(start + 1, end + 1):

            path.lineTo(clipped[y], float(y))

        path.lineTo(edge_x, float(end))

        path.lineTo(edge_x, float(start))

        path.closeSubpath()

        return path



    def _draw_vector_waves_from_profile(

        self,

        painter: QPainter,

        width: int,

        height: int,

        phase: float,

        profile: dict[str, object] | None,

        preview_mode: bool = False,

        use_style_palette: bool = False,

    ) -> bool:

        if profile is None:

            return False

        ref_w = float(profile.get("ref_w", 0.0))

        ref_h = float(profile.get("ref_h", 0.0))

        distance_layers = profile.get("distances", [])

        if ref_w <= 0.0 or ref_h <= 1.0 or not isinstance(distance_layers, list) or not distance_layers:

            return False



        h_cur = max(2, int(height))

        w_cur = float(width)

        scale = min(float(height) / ref_h, float(width) / ref_w)

        if preview_mode:

            wave_shift_x = max(8.0, width * 0.012) + (self._section_shift_x * 0.62)

            breathe = 1.0 + (0.030 * math.sin(phase * 0.92))

            wave_width_scale = (self._section_width_scale * 1.07) * breathe

            drift_x = 12.2 * math.sin(phase * 0.96)

            rotation_deg = (self._section_rotation_deg * 0.42) + (1.65 * math.sin(phase * 0.88))

            guard_ratio = max(0.70, min(0.90, self._section_guard_ratio))

        else:

            wave_shift_x = max(10.0, width * 0.016) + self._section_shift_x

            breathe = 1.0 + (0.046 * math.sin(phase * 0.94))

            wave_width_scale = (self._section_width_scale * 1.085) * breathe

            drift_x = 24.4 * math.sin(phase * 1.02)

            rotation_deg = self._section_rotation_deg + (2.35 * math.sin(phase * 1.05) if self._animations_enabled else 0.0)

            guard_ratio = float(self._section_guard_ratio)

        wave_shift_x += float(self._user_wave_shift_x)

        wave_width_scale *= max(0.55, min(1.65, float(self._user_wave_scale)))

        rotation_deg += float(self._user_wave_rotation_deg)



        tilt_ratio = math.tan(math.radians(rotation_deg))

        center_y = ((h_cur - 1) * 0.52) + float(self._user_wave_shift_y)

        trim_ref = max(6.0, ref_h * 0.06)

        usable_h = max(8.0, (ref_h - 1.0) - (trim_ref * 2.0))

        dist_layers = self._profile_distances_for_height(distance_layers, ref_h, h_cur, trim_ref, usable_h)

        boundaries_x: list[list[float]] = []

        for idx, dist_series in enumerate(dist_layers):

            direction = 1.0 if (idx % 2 == 0) else -1.0

            layer_phase = (phase * direction) + (idx * 0.44)

            layer_dx = (drift_x * (1.0 - idx * 0.10) * direction) + (2.8 * math.sin(layer_phase * 1.02))

            layer_tilt = tilt_ratio * (1.0 - idx * 0.08)

            xs: list[float] = []

            for y, d_ref in enumerate(dist_series):

                rotation_dx = (y - center_y) * layer_tilt

                x = w_cur - (d_ref * scale * wave_width_scale) + layer_dx + wave_shift_x + rotation_dx

                xs.append(x)

            boundaries_x.append(xs)

        if not boundaries_x:

            return False



        if len(boundaries_x) >= 4:

            boundaries_x = boundaries_x[:4]

        inner_boundary: list[float] = []

        last_boundary = boundaries_x[-1]

        for x in last_boundary:

            dist = max(8.0, w_cur - x)

            # Smaller center zone to match base.

            inner_dist = max(5.0, dist * (0.56 if preview_mode else 0.42))

            inner_boundary.append(w_cur - inner_dist + drift_x * 0.20 + wave_shift_x)

        inner_boundary = self._smooth_series(inner_boundary, radius=9)

        boundaries_x.append(inner_boundary)



        mid_y = h_cur // 2

        guard_x = w_cur * guard_ratio

        sample_rows = [max(0, min(h_cur - 1, int(h_cur * t))) for t in (0.18, 0.50, 0.82)]

        need_right_shift = 0.0

        outer_boundary = boundaries_x[0]

        for row in sample_rows:

            need_right_shift = max(need_right_shift, guard_x - outer_boundary[row])

        if need_right_shift > 0.0:

            boundaries_x = [[x + need_right_shift for x in boundary] for boundary in boundaries_x]



        visible_outer_x = w_cur - max(20.0, w_cur * (0.048 if preview_mode else 0.045))

        outer_mid_x = boundaries_x[0][mid_y]

        if outer_mid_x > visible_outer_x:

            dx = outer_mid_x - visible_outer_x

            boundaries_x = [[x - dx for x in boundary] for boundary in boundaries_x]



        edge_x = w_cur - 1.0

        boundaries_x = [[min(edge_x, x) for x in boundary] for boundary in boundaries_x]



        if use_style_palette:

            colors = [

                QColor("#0b132f"),

                QColor("#162a62"),

                QColor("#213f8f"),

                QColor("#3259c3"),

                QColor("#4970f4"),

            ]

        else:

            accent = QColor(self._palette.accent)

            colors = [

                QColor(self._palette.rings[0]),

                QColor(self._palette.rings[1]),

                QColor(self._palette.rings[2]),

                QColor(self._palette.rings[3]),

                _mix(accent, QColor("#000000"), 0.06),

            ]

        alphas = [232, 226, 220, 214, 210] if preview_mode else [228, 222, 216, 210, 206]

        painter.setPen(Qt.NoPen)

        for idx, boundary_x in enumerate(boundaries_x):

            if idx >= len(colors):

                break

            c = QColor(colors[idx])

            c.setAlpha(alphas[idx])

            path = self._wave_fill_path(boundary_x, w_cur, h_cur)

            painter.setBrush(c)

            painter.drawPath(path)

        return True



    def _extract_wave_profile_from_qimage(self, image: QImage) -> dict[str, object] | None:

        if image.isNull():

            return None

        if image.format() != QImage.Format_RGB32:

            image = image.convertToFormat(QImage.Format_RGB32)

        w = int(image.width())

        h = int(image.height())

        if w < 64 or h < 64:

            return None

        palette = (

            (12, 12, 20),

            (22, 28, 66),

            (33, 42, 102),

            (44, 62, 150),

            (58, 86, 212),

            (68, 101, 254),

        )



        def classify(r: int, g: int, b: int) -> int:

            best_i = 0

            best_d = 10**9

            for i, (pr, pg, pb) in enumerate(palette):

                d = (r - pr) * (r - pr) + (g - pg) * (g - pg) + (b - pb) * (b - pb)

                if d < best_d:

                    best_d = d

                    best_i = i

            return best_i



        boundaries: list[list[float | None]] = [[None] * h for _ in range(5)]

        for y in range(h):

            classes = [0] * w

            for x in range(w):

                c = image.pixelColor(x, y)

                classes[x] = classify(c.red(), c.green(), c.blue())

            smoothed = [0] * w

            for x in range(w):

                counts = [0] * 6

                a = max(0, x - 2)

                b = min(w, x + 3)

                for j in range(a, b):

                    counts[classes[j]] += 1

                best_cls = 0

                best_count = -1

                for cls_id, count in enumerate(counts):

                    if count > best_count:

                        best_count = count

                        best_cls = cls_id

                smoothed[x] = best_cls

            for layer in range(1, 6):

                x_pos = None

                for x, cls_id in enumerate(smoothed):

                    if cls_id >= layer:

                        x_pos = x

                        break

                boundaries[layer - 1][y] = float(x_pos) if x_pos is not None else None



        profile_distances: list[list[float]] = []

        for series in boundaries:

            filled = self._fill_missing_series(series)

            filtered = self._smooth_series(filled, radius=10)

            profile_distances.append([float(w) - x for x in filtered])

        return {"ref_w": float(w), "ref_h": float(h), "distances": profile_distances}




    def _load_wave_profile(self) -> dict[str, object] | None:


        try:


            from PIL import Image


        except Exception:


            return None





        base_dir = _app_resource_base_dir()


        candidates = [


            os.path.join(base_dir, "photo_2026-03-17_16-27-52.jpg"),


            os.path.join(base_dir, "photo_2025-12-27_04-03-01.jpg"),


        ]


        source = next((p for p in candidates if os.path.exists(p)), "")


        if not source:


            return None





        try:


            img = Image.open(source).convert("RGB")


        except Exception:


            return None





        w, h = img.size


        if w < 64 or h < 64:


            return None


        pix = img.load()





        palette = (


            (12, 12, 20),


            (22, 28, 66),


            (33, 42, 102),


            (44, 62, 150),


            (58, 86, 212),


            (68, 101, 254),


        )





        def classify(rgb: tuple[int, int, int]) -> int:


            r, g, b = rgb


            best_i = 0


            best_d = 10**9


            for i, (pr, pg, pb) in enumerate(palette):


                d = (r - pr) * (r - pr) + (g - pg) * (g - pg) + (b - pb) * (b - pb)


                if d < best_d:


                    best_d = d


                    best_i = i


            return best_i





        boundaries: list[list[float | None]] = [[None] * h for _ in range(5)]


        for y in range(h):


            classes = [classify(pix[x, y]) for x in range(w)]


            # Majority smoothing for class noise suppression.


            smoothed = [0] * w


            for x in range(w):


                counts = [0] * 6


                a = max(0, x - 2)


                b = min(w, x + 3)


                for j in range(a, b):


                    counts[classes[j]] += 1


                best_cls = 0


                best_count = -1


                for cls_id, count in enumerate(counts):


                    if count > best_count:


                        best_count = count


                        best_cls = cls_id


                smoothed[x] = best_cls





            for layer in range(1, 6):


                x_pos = None


                for x, cls_id in enumerate(smoothed):


                    if cls_id >= layer:


                        x_pos = x


                        break


                boundaries[layer - 1][y] = float(x_pos) if x_pos is not None else None





        profile_distances: list[list[float]] = []


        for series in boundaries:


            filled = self._fill_missing_series(series)


            filtered = self._smooth_series(filled, radius=10)


            profile_distances.append([float(w) - x for x in filtered])





        return {"ref_w": float(w), "ref_h": float(h), "distances": profile_distances}





    def paintEvent(self, event) -> None:


        painter = QPainter(self)


        try:


            painter.setRenderHint(QPainter.Antialiasing, True)


            painter.fillRect(self.rect(), Qt.transparent)





            w = max(1, self.width())


            h = max(1, self.height())


            key = (


                w,


                h,


                int(self._base_color.rgba()),


                int(self._wave_blur),


                int(self._window_transparency),


            )


            if self._backdrop_cache is None or self._backdrop_cache_key != key:


                self._backdrop_cache = self._build_backdrop_cache(w, h)


                self._backdrop_cache_key = key


            if self._backdrop_cache is not None and not self._backdrop_cache.isNull():


                painter.drawPixmap(0, 0, self._backdrop_cache)





            frame_rect = QRectF(self.rect()).adjusted(0.5, 0.5, -0.5, -0.5)


            frame_path = QPainterPath()

            radius = float(self._corner_radius)

            frame_path.addRoundedRect(frame_rect, radius, radius)

            painter.setClipPath(frame_path)

            # Star field disabled by user request.

            phase = self._phase if self._animations_enabled else 0.0

            variant = str(self._visual_variant or "waves1").strip().lower()

            if self._waves_suppressed:

                painter.setClipping(False)

                return

            blur_strength = max(0, min(100, int(self._wave_blur)))

            # Do not blur Jarvis visuals directly. Blur is expected on desktop

            # backdrop (native OS effect), not on in-app waves/reactor.

            fallback_soft_blur = False

            if fallback_soft_blur:

                phase_bucket = int((phase % math.tau) * 3.0) if self._animations_enabled else 0

                accent_rgba = int(QColor(self._palette.accent).rgba())

                blur_key = (

                    w,

                    h,

                    variant,

                    int(blur_strength),

                    phase_bucket,

                    int(self._base_color.rgba()),

                    accent_rgba,

                )

                if self._fallback_blur_cache is None or self._fallback_blur_cache_key != blur_key:

                    layer = QPixmap(w, h)

                    layer.fill(Qt.transparent)

                    layer_painter = QPainter(layer)

                    layer_painter.setRenderHint(QPainter.Antialiasing, True)

                    layer_painter.setClipPath(frame_path)

                    self._draw_visual_variant(layer_painter, w, h, phase, variant)

                    if variant not in {"waves", "waves1", "circles"}:

                        self._draw_base_tint_overlay(layer_painter, w, h)

                    layer_painter.setClipping(False)

                    layer_painter.end()

                    self._fallback_blur_cache = self._soften_pixmap(layer, blur_strength)

                    self._fallback_blur_cache_key = blur_key

                if self._fallback_blur_cache is not None and not self._fallback_blur_cache.isNull():

                    painter.drawPixmap(0, 0, self._fallback_blur_cache)

            else:

                self._draw_visual_variant(painter, w, h, phase, variant)

                if variant not in {"waves", "waves1", "circles"}:

                    self._draw_base_tint_overlay(painter, w, h)

            painter.setClipping(False)

            # Hide translucent AA seam on right edge of frameless window.

            edge_cover = QColor(self._base_color)

            edge_cover.setAlpha(255)

            painter.fillRect(QRectF(float(w) - 2.0, 0.0, 2.0, float(h)), edge_cover)

        finally:

            painter.end()







class LogoButton(QPushButton):

    def __init__(self, palette: ThemePalette) -> None:


        super().__init__()


        self._palette = palette


        self.setFixedSize(54, 54)


        self.setCursor(Qt.PointingHandCursor)


        self.setFlat(True)





    def set_palette(self, palette: ThemePalette) -> None:


        self._palette = palette


        self.update()





    def paintEvent(self, event) -> None:

        painter = QPainter(self)

        painter.setRenderHint(QPainter.Antialiasing, True)

        rect = QRectF(self.rect()).adjusted(1.2, 1.2, -1.2, -1.2)
        accent = QColor(self._palette.accent)
        fill = _mix(accent, QColor("#000000"), 0.72)
        border = _mix(accent, QColor("#ffffff"), 0.26)

        painter.setPen(QPen(QColor(border.red(), border.green(), border.blue(), 220), 1.2))
        painter.setBrush(QColor(fill.red(), fill.green(), fill.blue(), 228))
        painter.drawRoundedRect(rect, 11.0, 11.0)

        painter.setPen(QColor("#f4f8ff"))
        font = QFont("Segoe UI")
        font.setPointSize(max(12, int(min(self.width(), self.height()) * 0.44)))
        font.setWeight(QFont.Weight.Black)
        painter.setFont(font)
        painter.drawText(rect, Qt.AlignCenter, "J")







class SideIconButton(QPushButton):

    def __init__(self, icon_name: str) -> None:

        super().__init__()

        self.icon_name = icon_name

        self.setCheckable(True)

        self.setCursor(Qt.PointingHandCursor)

        self.setFixedSize(46, 46)

        self._accent = QColor(BLUE_THEME.accent)

        self._label_text = ""

        self._forced_hover = False



    def set_palette(self, palette: ThemePalette) -> None:

        self._accent = QColor(palette.accent)

        self.update()



    def set_label_text(self, text: object) -> None:

        self._label_text = str(text or "").strip()

        self.update()



    def set_forced_hover(self, value: bool) -> None:

        state = bool(value)

        if self._forced_hover == state:

            return

        self._forced_hover = state

        self.update()



    def paintEvent(self, event) -> None:

        painter = QPainter(self)

        painter.setRenderHint(QPainter.Antialiasing, True)

        rect = self.rect().adjusted(1, 1, -1, -1)

        icon_color = QColor("#d8e0ef")

        is_text_mode = bool(self._label_text)

        is_hovered = bool(self.underMouse() or self._forced_hover)

        radius = 11 if is_text_mode else 12

        if self.isChecked():

            painter.setPen(QPen(QColor(130, 157, 220, 210), 1.2))

            painter.setBrush(QColor(16, 24, 38, 236))

            painter.drawRoundedRect(rect, radius, radius)

            painter.setPen(Qt.NoPen)

            painter.setBrush(QColor(255, 255, 255, 16))

            painter.drawRoundedRect(rect.adjusted(1, 1, -1, -1), max(8, radius - 1), max(8, radius - 1))

            painter.setBrush(QColor(160, 188, 244, 220))

            if is_text_mode:

                painter.drawRoundedRect(QRectF(rect.left() + 4.0, rect.top() + 5.0, 2.4, rect.height() - 10.0), 1.2, 1.2)

            else:

                painter.drawRoundedRect(QRectF(rect.right() - 2.6, rect.top() + 9.0, 2.2, rect.height() - 18.0), 1.0, 1.0)

            icon_color = QColor("#f4f8ff")

        elif self.isDown():

            painter.setPen(QPen(QColor(112, 128, 156, 170), 1.0))

            painter.setBrush(QColor(18, 24, 35, 180))

            painter.drawRoundedRect(rect, radius, radius)

        elif is_hovered:

            painter.setPen(QPen(QColor(92, 108, 136, 156), 1.0))

            painter.setBrush(QColor(14, 20, 31, 156))

            painter.drawRoundedRect(rect, radius, radius)



        icon_cx = 24 if is_text_mode else (self.width() // 2)

        icon_cy = self.height() // 2

        painter.translate(icon_cx, icon_cy)

        pen = QPen(icon_color, 2.4, Qt.SolidLine, Qt.RoundCap, Qt.RoundJoin)

        painter.setPen(pen)

        painter.setBrush(Qt.NoBrush)




        if self.icon_name == "home":

            painter.drawLine(QPoint(-9, 2), QPoint(-9, -2))

            painter.drawLine(QPoint(-9, -2), QPoint(0, -10))

            painter.drawLine(QPoint(0, -10), QPoint(9, -2))

            painter.drawLine(QPoint(9, -2), QPoint(9, 2))

            painter.drawRoundedRect(QRect(-6, -1, 12, 10), 2, 2)

        elif self.icon_name == "command":

            # Document-only icon (no pencil).

            painter.drawRoundedRect(QRect(-8, -10, 16, 18), 2, 2)

            painter.drawLine(QPoint(4, -10), QPoint(8, -6))

            painter.drawLine(QPoint(8, -6), QPoint(4, -6))

            painter.drawLine(QPoint(-4, -2), QPoint(4, -2))

            painter.drawLine(QPoint(-4, 2), QPoint(4, 2))

            painter.drawLine(QPoint(-4, 6), QPoint(2, 6))

        elif self.icon_name == "plugins":


            painter.drawRoundedRect(QRect(-10, -7, 20, 14), 3, 3)


            painter.drawLine(QPoint(-10, -2), QPoint(10, -2))


            painter.drawLine(QPoint(-4, -10), QPoint(4, -10))


        elif self.icon_name == "settings":


            gear = QPainterPath()


            for i in range(16):


                angle = (math.pi * 2.0) * (i / 16.0)


                radius = 10.2 if i % 2 == 0 else 7.8


                p = QPointF(math.cos(angle) * radius, math.sin(angle) * radius)


                if i == 0:


                    gear.moveTo(p)


                else:


                    gear.lineTo(p)


            gear.closeSubpath()


            painter.drawPath(gear)


            painter.drawEllipse(QPoint(0, 0), 3, 3)


        elif self.icon_name == "profile":

            painter.drawEllipse(QPoint(0, -6), 4, 4)

            painter.drawArc(QRect(-10, 0, 20, 14), 25 * 16, 130 * 16)



        if is_text_mode:

            painter.resetTransform()

            text_rect = QRectF(44.0, 0.0, max(1.0, self.width() - 50.0), float(self.height()))

            f = painter.font()

            f.setPixelSize(24 if self.height() >= 52 else 13)

            f.setWeight(QFont.Weight.DemiBold)

            painter.setFont(f)

            painter.setPen(QColor("#f4f8ff") if self.isChecked() else QColor("#d9e2f3"))

            painter.drawText(text_rect, Qt.AlignVCenter | Qt.AlignLeft, self._label_text)







class CommandToolButton(QPushButton):

    def __init__(self, icon_name: str) -> None:

        super().__init__()

        self.icon_name = icon_name

        self.setCursor(Qt.PointingHandCursor)

        self.setFixedSize(36, 36)

        self.setFlat(True)

        self._forced_hover = False



    def set_forced_hover(self, value: bool) -> None:

        state = bool(value)

        if self._forced_hover == state:

            return

        self._forced_hover = state

        self.update()



    def paintEvent(self, event) -> None:

        painter = QPainter(self)

        painter.setRenderHint(QPainter.Antialiasing, True)

        rect = self.rect().adjusted(1, 1, -1, -1)

        top_mic = bool(self.property("top_mic"))

        is_hovered = bool(self.underMouse() or self._forced_hover)

        radius = 11 if top_mic else 10

        border = QColor(20, 28, 42, 232)

        fill = QColor(4, 7, 12, 244)

        is_checked = bool(self.isCheckable() and self.isChecked())

        if is_checked:

            border = QColor(230, 238, 252, 196)

            fill = QColor(9, 13, 19, 250)

        if top_mic:

            border = QColor(62, 74, 102, 220) if not is_checked else QColor(230, 238, 252, 210)

            fill = QColor(10, 14, 22, 248) if not is_checked else QColor(12, 16, 24, 252)

        if is_hovered:

            border = QColor(193, 206, 232, 132)

            fill = QColor(7, 10, 16, 248)

        if self.isDown():

            border = QColor(233, 240, 252, 190)

            fill = QColor(9, 13, 19, 252)




        painter.setPen(QPen(border, 1.1))

        painter.setBrush(fill)

        painter.drawRoundedRect(rect, radius, radius)



        painter.translate(self.width() // 2, self.height() // 2)

        icon_scale = 1.0

        if top_mic:

            icon_scale = max(1.18, min(1.58, min(self.width(), self.height()) / 28.0))

        if icon_scale != 1.0:

            painter.scale(icon_scale, icon_scale)

        icon_color = QColor("#f6f9ff") if (is_hovered or self.isDown() or is_checked) else QColor("#e4ebf8")

        pen_width = 1.75 if icon_scale <= 1.0 else max(1.35, 1.75 / icon_scale)

        painter.setPen(QPen(icon_color, pen_width, Qt.SolidLine, Qt.RoundCap, Qt.RoundJoin))

        painter.setBrush(Qt.NoBrush)




        if self.icon_name == "list":


            for y in (-4, 0, 4):


                painter.drawLine(QPoint(-6, y), QPoint(6, y))


            painter.drawPoint(QPoint(-8, -4))


        elif self.icon_name == "folder":


            painter.drawLine(QPoint(-8, -3), QPoint(-1, -3))


            painter.drawLine(QPoint(-1, -3), QPoint(1, -6))


            painter.drawLine(QPoint(1, -6), QPoint(8, -6))


            painter.drawLine(QPoint(-8, -3), QPoint(-8, 6))


            painter.drawLine(QPoint(-8, 6), QPoint(8, 6))


            painter.drawLine(QPoint(8, 6), QPoint(8, -3))


        elif self.icon_name == "doc":


            painter.drawRoundedRect(QRect(-6, -8, 12, 16), 2, 2)


            painter.drawLine(QPoint(2, -8), QPoint(6, -4))


            painter.drawLine(QPoint(6, -4), QPoint(2, -4))


        elif self.icon_name == "mic":


            painter.drawRoundedRect(QRect(-3, -7, 6, 10), 3, 3)


            painter.drawLine(QPoint(0, 3), QPoint(0, 8))


            painter.drawArc(QRect(-6, -1, 12, 10), 180 * 16, 180 * 16)


            if self.isCheckable() and not self.isChecked():


                slash_color = QColor("#ff8b93") if (is_hovered or self.isDown()) else QColor("#e9707b")

                painter.setPen(QPen(slash_color, 2.0, Qt.SolidLine, Qt.RoundCap, Qt.RoundJoin))


                painter.drawLine(QPoint(-8, -8), QPoint(8, 8))


        elif self.icon_name == "flag":


            painter.drawLine(QPoint(-4, -8), QPoint(-4, 8))


            painter.drawLine(QPoint(-4, -8), QPoint(6, -5))


            painter.drawLine(QPoint(6, -5), QPoint(-4, -1))


        elif self.icon_name == "insta":


            painter.drawRoundedRect(QRect(-7, -7, 14, 14), 4, 4)


            painter.drawEllipse(QPoint(0, 0), 3, 3)


            painter.drawEllipse(QPoint(4, -4), 1, 1)


        elif self.icon_name == "export":


            painter.drawRoundedRect(QRect(-7, -7, 11, 11), 2, 2)


            painter.drawLine(QPoint(0, 0), QPoint(7, -7))


            painter.drawLine(QPoint(4, -7), QPoint(7, -7))


            painter.drawLine(QPoint(7, -7), QPoint(7, -4))








class RefreshIconChipButton(QPushButton):


    def __init__(self) -> None:


        super().__init__("↻")


        self.setCursor(Qt.PointingHandCursor)


        self.setProperty("ui", "icon_chip")


        self.setProperty("_tr_skip", True)


        self._frames = ("↻", "↺")


        self._frame_index = 0


        self._spin_timer = QTimer(self)


        self._spin_timer.setInterval(120)


        self._spin_timer.timeout.connect(self._spin_tick)


        self._pulse_timer = QTimer(self)


        self._pulse_timer.setSingleShot(True)


        self._pulse_timer.timeout.connect(self._pulse_done)


        self.clicked.connect(self._pulse)





    def _spin_tick(self) -> None:


        self._frame_index = (self._frame_index + 1) % len(self._frames)


        self.setText(self._frames[self._frame_index])





    def _start_spin(self) -> None:


        if not self._spin_timer.isActive():


            self._spin_timer.start()


        set_active(self, True)





    def _stop_spin(self) -> None:


        if self._spin_timer.isActive():


            self._spin_timer.stop()


        self._frame_index = 0


        self.setText(self._frames[0])


        set_active(self, False)





    def _pulse(self) -> None:


        self._start_spin()


        self._pulse_timer.start(520)





    def _pulse_done(self) -> None:


        if self.underMouse():


            return


        self._stop_spin()





    def enterEvent(self, event) -> None:


        self._start_spin()


        super().enterEvent(event)





    def leaveEvent(self, event) -> None:


        if not self._pulse_timer.isActive():


            self._stop_spin()


        super().leaveEvent(event)








