class ToggleSwitch(QCheckBox):

    def __init__(self, checked: bool = False) -> None:

        super().__init__()

        self._accent = QColor(BLUE_THEME.accent)

        self.setCursor(Qt.PointingHandCursor)

        self.setChecked(checked)

        self.setFixedSize(52, 24)




    def set_palette(self, palette: ThemePalette) -> None:


        self._accent = QColor(palette.accent)


        self.update()

    def hitButton(self, pos: QPoint) -> bool:

        # Make the whole switch body clickable; default QCheckBox hit testing
        # may shrink click area depending on style/indicator metrics.
        return self.rect().contains(pos)





    def paintEvent(self, event) -> None:

        painter = QPainter(self)

        painter.setRenderHint(QPainter.Antialiasing, True)

        groove = QRectF(1, 1, self.width() - 2, self.height() - 2)




        if self.isChecked():


            bg = QColor(self._accent)


            border = QColor(self._accent)


            knob = QColor("#f4f6ff")


        else:


            bg = QColor("#080a10")


            border = QColor("#1d222b")


            knob = QColor("#4f5665")





        painter.setBrush(bg)


        painter.setPen(QPen(border, 1.2))


        painter.drawRoundedRect(groove, groove.height() / 2, groove.height() / 2)





        knob_d = groove.height() - 4

        x = groove.right() - knob_d - 2 if self.isChecked() else groove.left() + 2

        knob_rect = QRectF(x, groove.top() + 2.0, knob_d, knob_d)

        painter.setBrush(knob)

        painter.setPen(Qt.NoPen)

        painter.drawEllipse(knob_rect)







class ColorSwatchButton(QPushButton):


    clicked_color = Signal(str)





    def __init__(self, color_hex: str, selected: bool = False) -> None:


        super().__init__()


        self.color_hex = color_hex


        self._selected = selected


        self.setFixedSize(72, 72)


        self.setCursor(Qt.PointingHandCursor)


        self.setFlat(True)


        self.clicked.connect(lambda: self.clicked_color.emit(self.color_hex))





    def set_selected(self, selected: bool) -> None:


        self._selected = selected


        self.update()





    def paintEvent(self, event) -> None:


        painter = QPainter(self)


        painter.setRenderHint(QPainter.Antialiasing, True)


        rect = self.rect().adjusted(5, 5, -5, -5)


        painter.setBrush(QColor(self.color_hex))


        painter.setPen(QPen(QColor("#171a20"), 1.3))


        painter.drawRoundedRect(rect, 16, 16)


        if self._selected:


            painter.setPen(QPen(QColor("#d9dde5"), 3, Qt.SolidLine, Qt.RoundCap, Qt.RoundJoin))


            x0 = rect.left() + rect.width() * 0.30


            y0 = rect.center().y() + rect.height() * 0.10


            x1 = rect.left() + rect.width() * 0.44


            y1 = rect.bottom() - rect.height() * 0.22


            x2 = rect.right() - rect.width() * 0.22


            y2 = rect.top() + rect.height() * 0.24


            painter.drawLine(QPoint(int(x0), int(y0)), QPoint(int(x1), int(y1)))


            painter.drawLine(QPoint(int(x1), int(y1)), QPoint(int(x2), int(y2)))








class OverlayPositionButton(QPushButton):


    def __init__(self, position_key: str) -> None:


        super().__init__()


        self.position_key = position_key


        self.setCheckable(True)


        self.setCursor(Qt.PointingHandCursor)


        self.setFocusPolicy(Qt.NoFocus)


        self.setFlat(True)


        self.setFixedSize(30, 20)





    def paintEvent(self, event) -> None:


        _ = event


        painter = QPainter(self)


        painter.setRenderHint(QPainter.Antialiasing, True)


        is_active = self.isChecked()


        frame = QRectF(self.rect()).adjusted(1.0, 1.0, -1.0, -1.0)


        icon = QColor(244, 249, 255, 240) if is_active else QColor(180, 191, 214, 175)

        painter.setPen(QPen(icon, 1.6, Qt.SolidLine, Qt.RoundCap, Qt.RoundJoin))


        left = frame.left() + 6.5


        right = frame.right() - 6.5


        top = frame.top() + 4.5


        bottom = frame.bottom() - 4.5


        if self.position_key == "left":


            x = left


            painter.drawLine(QPointF(x, top), QPointF(x, bottom))


        elif self.position_key == "right":


            x = right


            painter.drawLine(QPointF(x, top), QPointF(x, bottom))


        elif self.position_key == "top":


            y = top


            painter.drawLine(QPointF(left, y), QPointF(right, y))


        else:


            y = bottom


            painter.drawLine(QPointF(left, y), QPointF(right, y))








