class TimeToastBubble(QFrame):

    def __init__(self, parent: QWidget | None = None) -> None:

        super().__init__(parent)

        self.setProperty("ui", "time_toast")

        self.setWindowFlags(Qt.Tool | Qt.FramelessWindowHint | Qt.WindowStaysOnTopHint)

        self.setAttribute(Qt.WA_ShowWithoutActivating, True)

        self.setAttribute(Qt.WA_TranslucentBackground, True)

        self.setAttribute(Qt.WA_TransparentForMouseEvents, True)

        self._margin = 14

        self._visible_ms = 5000

        self._max_width = 320

        self._layout = QVBoxLayout(self)

        self._layout.setContentsMargins(20, 12, 20, 12)

        self._layout.setSpacing(0)

        self._label = QLabel("", self)

        self._label.setProperty("role", "time_toast_text")

        self._label.setAlignment(Qt.AlignCenter)

        self._layout.addWidget(self._label)

        self._opacity_effect = QGraphicsOpacityEffect(self)

        self._opacity_effect.setOpacity(0.0)

        self.setGraphicsEffect(self._opacity_effect)

        self._anim = QVariantAnimation(self)

        self._anim.setStartValue(0.0)

        self._anim.setEndValue(1.0)

        self._anim.setEasingCurve(QEasingCurve.OutCubic)

        self._anim.valueChanged.connect(self._on_anim_value_changed)

        self._anim.finished.connect(self._on_anim_finished)

        self._anim_phase = ""

        self._from_rect = QRect()

        self._to_rect = QRect()

        self._from_opacity = 0.0

        self._to_opacity = 0.0

        self._hide_timer = QTimer(self)

        self._hide_timer.setSingleShot(True)

        self._hide_timer.timeout.connect(self._start_hide_animation)

        self.setStyleSheet(
            "QFrame[ui=\"time_toast\"] {"
            "background-color: rgba(8, 14, 24, 244);"
            "border: 1px solid rgba(198, 218, 255, 176);"
            "border-radius: 14px;"
            "}"
            "QLabel[role=\"time_toast_text\"] {"
            "color: rgba(247, 252, 255, 252);"
            "font-size: 28px;"
            "font-weight: 700;"
            "}"
        )

        self.hide()

    def _available_geometry(self) -> QRect:

        app = QApplication.instance()

        screen = None

        if app is not None:

            try:

                screen = app.screenAt(QCursor.pos())

            except Exception:

                screen = None

            if screen is None:

                try:

                    screen = app.primaryScreen()

                except Exception:

                    screen = None

        if screen is not None:

            try:

                geom = screen.availableGeometry()

                if geom.isValid():

                    return QRect(geom)

            except Exception:

                pass

        return QRect(0, 0, 1920, 1080)

    def _target_rect(self) -> QRect:

        width = max(1, int(self.width()))

        height = max(1, int(self.height()))

        area = self._available_geometry()

        x = max(int(area.x()) + self._margin, int(area.x() + area.width()) - width - self._margin)

        y = int(area.y()) + self._margin

        return QRect(int(x), int(y), width, height)

    def _recalculate_size(self) -> None:

        text = str(self._label.text() or "").strip() or "00:00"

        metrics = QFontMetrics(self._label.font())

        width = int(max(168, min(self._max_width, metrics.horizontalAdvance(text) + 56)))

        self._label.setFixedWidth(max(1, width - 40))

        height = int(max(56, self._label.sizeHint().height() + 24))

        self.setFixedSize(width, height)

    def _start_transition(
        self,
        phase: str,
        from_rect: QRect,
        to_rect: QRect,
        from_opacity: float,
        to_opacity: float,
        duration_ms: int,
    ) -> None:

        self._anim.stop()

        self._anim_phase = str(phase or "")

        self._from_rect = QRect(from_rect)

        self._to_rect = QRect(to_rect)

        self._from_opacity = float(max(0.0, min(1.0, from_opacity)))

        self._to_opacity = float(max(0.0, min(1.0, to_opacity)))

        self._anim.setDuration(max(1, int(duration_ms)))

        self._anim.start()

    def _on_anim_value_changed(self, value: object) -> None:

        try:

            t = float(value)

        except Exception:

            t = 1.0

        t = max(0.0, min(1.0, t))

        inv = 1.0 - t

        x = int(round((self._from_rect.x() * inv) + (self._to_rect.x() * t)))

        y = int(round((self._from_rect.y() * inv) + (self._to_rect.y() * t)))

        w = int(round((self._from_rect.width() * inv) + (self._to_rect.width() * t)))

        h = int(round((self._from_rect.height() * inv) + (self._to_rect.height() * t)))

        self.setGeometry(QRect(x, y, max(1, w), max(1, h)))

        opacity = (self._from_opacity * inv) + (self._to_opacity * t)

        self._opacity_effect.setOpacity(max(0.0, min(1.0, opacity)))

    def _on_anim_finished(self) -> None:

        if self._anim_phase == "show":

            self._hide_timer.start(max(1, int(self._visible_ms)))

            return

        if self._anim_phase == "hide":

            self._hide_timer.stop()

            self._opacity_effect.setOpacity(0.0)

            self.hide()

    def _start_hide_animation(self) -> None:

        if not self.isVisible():

            return

        target = self._target_rect()

        end_rect = QRect(target)

        end_rect.moveLeft(target.left() + 18)

        self._start_transition(
            "hide",
            QRect(self.geometry()),
            end_rect,
            float(self._opacity_effect.opacity()),
            0.0,
            220,
        )

    def reposition(self) -> None:

        if not self.isVisible():

            return

        target = self._target_rect()

        if self._anim.state() == QVariantAnimation.Running:

            if self._anim_phase == "show":

                self._to_rect = QRect(target)

            elif self._anim_phase == "hide":

                end_rect = QRect(target)

                end_rect.moveLeft(target.left() + 18)

                self._to_rect = end_rect

            return

        self.setGeometry(target)

    def show_time(self, text: str, visible_ms: int = 5000) -> None:

        value = str(text or "").strip()

        if not value:

            return

        self._visible_ms = max(600, int(visible_ms))

        self._hide_timer.stop()

        self._label.setText(value)

        self._recalculate_size()

        target = self._target_rect()

        if not self.isVisible():

            start_rect = QRect(target)

            start_rect.moveLeft(target.left() + 28)

            self.setGeometry(start_rect)

            self._opacity_effect.setOpacity(0.0)

            self.show()

            self.raise_()

            self._start_transition("show", start_rect, target, 0.0, 1.0, 180)

            return

        self.raise_()

        self._start_transition(
            "show",
            QRect(self.geometry()),
            target,
            float(self._opacity_effect.opacity()),
            1.0,
            140,
        )


class CodexPostToastBubble(QFrame):
    clicked = Signal()

    def __init__(self, parent: QWidget | None = None) -> None:

        super().__init__(parent)

        self.setProperty("ui", "codex_post_toast")

        self.setAttribute(Qt.WA_ShowWithoutActivating, True)

        self.setCursor(Qt.PointingHandCursor)

        self._margin = 14

        self._top_margin = 62

        self._visible_ms = 5000

        self._max_width = 420

        self._layout = QVBoxLayout(self)

        self._layout.setContentsMargins(14, 10, 14, 10)

        self._layout.setSpacing(2)

        self._title_lbl = QLabel("", self)

        self._title_lbl.setProperty("role", "codex_toast_title")

        self._title_lbl.setWordWrap(True)

        self._layout.addWidget(self._title_lbl)

        self._body_lbl = QLabel("", self)

        self._body_lbl.setProperty("role", "codex_toast_body")

        self._body_lbl.setWordWrap(True)

        self._layout.addWidget(self._body_lbl)

        self._opacity_effect = QGraphicsOpacityEffect(self)

        self._opacity_effect.setOpacity(0.0)

        self.setGraphicsEffect(self._opacity_effect)

        self._anim = QVariantAnimation(self)

        self._anim.setStartValue(0.0)

        self._anim.setEndValue(1.0)

        self._anim.setEasingCurve(QEasingCurve.OutCubic)

        self._anim.valueChanged.connect(self._on_anim_value_changed)

        self._anim.finished.connect(self._on_anim_finished)

        self._anim_phase = ""

        self._from_rect = QRect()

        self._to_rect = QRect()

        self._from_opacity = 0.0

        self._to_opacity = 0.0

        self._hide_timer = QTimer(self)

        self._hide_timer.setSingleShot(True)

        self._hide_timer.timeout.connect(self._start_hide_animation)

        self.setStyleSheet(
            "QFrame[ui=\"codex_post_toast\"] {"
            "background: qlineargradient(x1:0, y1:0, x2:1, y2:1,"
            " stop:0 rgba(20, 34, 68, 246), stop:1 rgba(9, 15, 30, 246));"
            "border: 1px solid rgba(142, 176, 255, 0.72);"
            "border-radius: 14px;"
            "}"
            "QLabel[role=\"codex_toast_title\"] {"
            "color: rgba(242, 248, 255, 250);"
            "font-size: 13px;"
            "font-weight: 700;"
            "}"
            "QLabel[role=\"codex_toast_body\"] {"
            "color: rgba(210, 224, 250, 242);"
            "font-size: 12px;"
            "font-weight: 500;"
            "}"
        )

        self.hide()

    def mousePressEvent(self, event) -> None:

        if event.button() == Qt.LeftButton:

            self.clicked.emit()

            event.accept()

            return

        super().mousePressEvent(event)

    def _target_rect(self) -> QRect:

        width = max(1, int(self.width()))

        height = max(1, int(self.height()))

        parent = self.parentWidget()

        if parent is None:

            area = QRect(0, 0, 1280, 720)

        else:

            area = QRect(parent.rect())

        max_x = max(int(self._margin), int(area.width()) - width - int(self._margin))

        max_y = max(int(self._margin), int(area.height()) - height - int(self._margin))

        x = max_x

        y = max(int(self._margin), min(int(self._top_margin), max_y))

        return QRect(int(x), int(y), width, height)

    def _recalculate_size(self) -> None:

        title = str(self._title_lbl.text() or "").strip() or "CodeX"

        body = str(self._body_lbl.text() or "").strip() or "Новый пост"

        title_metrics = QFontMetrics(self._title_lbl.font())

        body_metrics = QFontMetrics(self._body_lbl.font())

        width = max(
            286,
            min(
                self._max_width,
                max(
                    int(title_metrics.horizontalAdvance(title) + 44),
                    int(body_metrics.horizontalAdvance(body) + 44),
                ),
            ),
        )

        text_w = max(140, width - 28)

        self._title_lbl.setFixedWidth(text_w)

        self._body_lbl.setFixedWidth(text_w)

        height = max(68, self._title_lbl.sizeHint().height() + self._body_lbl.sizeHint().height() + 22)

        self.setFixedSize(width, int(height))

    def _start_transition(
        self,
        phase: str,
        from_rect: QRect,
        to_rect: QRect,
        from_opacity: float,
        to_opacity: float,
        duration_ms: int,
    ) -> None:

        self._anim.stop()

        self._anim_phase = str(phase or "")

        self._from_rect = QRect(from_rect)

        self._to_rect = QRect(to_rect)

        self._from_opacity = float(max(0.0, min(1.0, from_opacity)))

        self._to_opacity = float(max(0.0, min(1.0, to_opacity)))

        self._anim.setDuration(max(1, int(duration_ms)))

        self._anim.start()

    def _on_anim_value_changed(self, value: object) -> None:

        try:

            t = float(value)

        except Exception:

            t = 1.0

        t = max(0.0, min(1.0, t))

        inv = 1.0 - t

        x = int(round((self._from_rect.x() * inv) + (self._to_rect.x() * t)))

        y = int(round((self._from_rect.y() * inv) + (self._to_rect.y() * t)))

        w = int(round((self._from_rect.width() * inv) + (self._to_rect.width() * t)))

        h = int(round((self._from_rect.height() * inv) + (self._to_rect.height() * t)))

        self.setGeometry(QRect(x, y, max(1, w), max(1, h)))

        opacity = (self._from_opacity * inv) + (self._to_opacity * t)

        self._opacity_effect.setOpacity(max(0.0, min(1.0, opacity)))

    def _on_anim_finished(self) -> None:

        if self._anim_phase == "show":

            self._hide_timer.start(max(1, int(self._visible_ms)))

            return

        if self._anim_phase == "hide":

            self._hide_timer.stop()

            self._opacity_effect.setOpacity(0.0)

            self.hide()

    def _start_hide_animation(self) -> None:

        if not self.isVisible():

            return

        target = self._target_rect()

        end_rect = QRect(target)

        end_rect.moveLeft(target.left() + 22)

        self._start_transition("hide", QRect(self.geometry()), end_rect, float(self._opacity_effect.opacity()), 0.0, 220)

    def dismiss(self) -> None:

        self._hide_timer.stop()

        self._start_hide_animation()

    def reposition(self) -> None:

        if not self.isVisible():

            return

        target = self._target_rect()

        if self._anim.state() == QVariantAnimation.Running:

            if self._anim_phase == "show":

                self._to_rect = QRect(target)

            elif self._anim_phase == "hide":

                end_rect = QRect(target)

                end_rect.moveLeft(target.left() + 22)

                self._to_rect = end_rect

            return

        self.setGeometry(target)

    def show_post_notice(self, title: str, visible_ms: int = 5000) -> None:

        clean_title = re.sub(r"\s+", " ", str(title or "").strip())

        if len(clean_title) > 72:

            clean_title = f"{clean_title[:69].rstrip()}..."

        self._visible_ms = max(800, int(visible_ms))

        self._hide_timer.stop()

        self._title_lbl.setText("Новый пост у официального канала CodeX")

        if clean_title:

            self._body_lbl.setText(f"{clean_title}  •  Открыть канал ↗")

        else:

            self._body_lbl.setText("Открыть канал CodeX ↗")

        self._recalculate_size()

        target = self._target_rect()

        if not self.isVisible():

            start_rect = QRect(target)

            start_rect.moveLeft(target.left() + 28)

            self.setGeometry(start_rect)

            self._opacity_effect.setOpacity(0.0)

            self.show()

            self.raise_()

            self._start_transition("show", start_rect, target, 0.0, 1.0, 190)

            return

        self.raise_()

        self._start_transition("show", QRect(self.geometry()), target, float(self._opacity_effect.opacity()), 1.0, 140)


class ConsolePromptEdit(QPlainTextEdit):
    command_submitted = Signal(str)



    def __init__(self, prompt: str = "", parent: QWidget | None = None) -> None:

        super().__init__(parent)

        self._prompt = str(prompt)

        self._input_start = 0

        self.setLineWrapMode(QPlainTextEdit.NoWrap)

        self.setWordWrapMode(QTextOption.NoWrap)

        self.setUndoRedoEnabled(False)

        self.setTabChangesFocus(False)

        try:

            mono = QFontDatabase.systemFont(QFontDatabase.FixedFont)

            mono.setPointSize(max(10, min(12, mono.pointSize())))

            mono.setStyle(QFont.Style.StyleNormal)

            mono.setItalic(False)

            mono.setWeight(QFont.Weight.Normal)

            self.setFont(mono)

        except Exception:

            pass



    def _move_cursor_to_end(self) -> None:

        cursor = self.textCursor()

        cursor.movePosition(QTextCursor.End)

        self.setTextCursor(cursor)



    def set_boot_text(self, lines: list[str]) -> None:

        parts = [str(line) for line in lines if str(line).strip() or str(line) == ""]

        boot = "\n".join(parts).rstrip()

        if boot:

            text = f"{boot}\n\n{self._prompt}"

        else:

            text = self._prompt

        self.setPlainText(text)

        self._input_start = len(self.toPlainText())

        self._move_cursor_to_end()



    def append_output_line(self, text: str) -> None:

        line = str(text or "").rstrip()

        if not line:

            return

        full = self.toPlainText()

        start = max(0, min(self._input_start, len(full)))

        current_input = full[start:]

        prefix = full[:start]

        if prefix and not prefix.endswith("\n"):

            prefix += "\n"

        prefix += f"{line}\n"

        merged = f"{prefix}{self._prompt}{current_input}"

        self.setPlainText(merged)

        self._input_start = len(prefix) + len(self._prompt)

        self._move_cursor_to_end()



    def keyPressEvent(self, event) -> None:

        key = event.key()

        if key in (Qt.Key_Return, Qt.Key_Enter):

            full = self.toPlainText()

            start = max(0, min(self._input_start, len(full)))

            command = str(full[start:] or "").strip()

            self._move_cursor_to_end()

            self.insertPlainText("\n")

            self.insertPlainText(self._prompt)

            self._input_start = len(self.toPlainText())

            if command:

                self.command_submitted.emit(command)

            return



        cursor = self.textCursor()

        if key == Qt.Key_Backspace and cursor.position() <= self._input_start:

            return

        if key == Qt.Key_Left and cursor.position() <= self._input_start:

            return

        if key == Qt.Key_Home:

            cursor.setPosition(self._input_start)

            self.setTextCursor(cursor)

            return

        if cursor.position() < self._input_start:

            self._move_cursor_to_end()



        super().keyPressEvent(event)

        if len(self.toPlainText()) < self._input_start:

            self._input_start = len(self.toPlainText())





class OutputTextWindow(QWidget):

    command_entered = Signal(str)

