def location_label(location: str) -> str:


    location = str(location).strip()


    if not location:


        return "Раздел"


    return location.split("/")[-1].strip() or location








def _is_disabled_command_name(name: object) -> bool:


    normalized = _normalize_ui_text(name).strip().lower().replace("ё", "е")


    return normalized in DISABLED_COMMAND_NAMES








def _resolve_shortcut_target(shortcut_path: str) -> tuple[str, str]:


    path = str(shortcut_path).strip()


    if not path or not os.path.exists(path):


        return "", ""


    escaped = path.replace("'", "''")


    script = (


        "$ErrorActionPreference='Stop'; "


        "$sc=(New-Object -ComObject WScript.Shell).CreateShortcut('{0}'); "


        "[Console]::OutputEncoding=[System.Text.Encoding]::UTF8; "


        "Write-Output $sc.TargetPath; "


        "Write-Output $sc.WorkingDirectory"


    ).format(escaped)


    try:


        proc = subprocess.run(


            ["powershell", "-NoProfile", "-Command", script],


            capture_output=True,


            text=True,


            encoding="utf-8",


            errors="ignore",


            timeout=3,


            check=False,


        )


    except Exception:


        return "", ""


    if proc.returncode != 0:


        return "", ""


    lines = [line.strip() for line in proc.stdout.splitlines() if line.strip()]


    target_path = lines[0] if len(lines) > 0 else ""


    working_dir = lines[1] if len(lines) > 1 else ""


    return target_path, working_dir








def _resolve_jarvis_xml_path(xml_path: str | None = None) -> str:


    direct = str(xml_path or "").strip()


    if direct:


        return direct





    candidates = [JARVIS_XML_PATH]


    target_path, working_dir = _resolve_shortcut_target(JARVIS_SHORTCUT_PATH)


    if working_dir:


        candidates.append(os.path.join(working_dir, "voicecommands.xml"))


        candidates.append(os.path.join(working_dir, "voicecommands.bak"))


    if target_path:


        base = os.path.dirname(target_path)


        candidates.append(os.path.join(base, "voicecommands.xml"))


        candidates.append(os.path.join(base, "voicecommands.bak"))





    seen: set[str] = set()


    for candidate in candidates:


        normalized = os.path.normpath(candidate)


        if normalized in seen:


            continue


        seen.add(normalized)


        if os.path.exists(normalized):


            return normalized


    return JARVIS_XML_PATH








def _parse_xml_root(xml_path: str) -> ET.Element | None:


    try:


        return ET.parse(xml_path).getroot()


    except Exception:


        pass





    try:


        with open(xml_path, "rb") as handle:


            raw = handle.read()


    except Exception:


        return None





    for encoding in ("utf-8", "cp1251", "windows-1251", "utf-16"):


        try:


            text = raw.decode(encoding)


            return ET.fromstring(text)


        except Exception:


            continue


    return None








def load_jarvis_command_model(


    xml_path: str | None = None,


) -> tuple[dict[str, list[dict[str, object]]], dict[str, bool], list[str]]:


    resolved_path = _resolve_jarvis_xml_path(xml_path)


    if not os.path.exists(resolved_path):


        return {}, {}, []





    root = _parse_xml_root(resolved_path)


    if root is None:


        return {}, {}, []





    commands_by_location: dict[str, list[dict[str, object]]] = {}


    open_states: dict[str, bool] = {}


    ordered_locations: list[str] = []





    def _register_location(location: str, is_open: bool = True) -> None:


        key = location.strip()


        if not key:


            return


        if key not in commands_by_location:


            commands_by_location[key] = []


            ordered_locations.append(key)


        if key not in open_states:


            open_states[key] = bool(is_open)


        else:


            open_states[key] = bool(is_open)





    def _parse_command(cmd_elem: ET.Element, location: str) -> dict[str, object] | None:


        cmd_name = _normalize_ui_text(cmd_elem.attrib.get("name") or "") or "Новая команда"


        if _is_disabled_command_name(cmd_name):


            return None


        cmd_id = (cmd_elem.attrib.get("id") or "").strip()


        confirm = str(cmd_elem.attrib.get("confirm", "False")).lower() == "true"





        actions: list[dict[str, object]] = []


        for action_elem in cmd_elem.findall("action"):


            cmd_type = (action_elem.findtext("cmdType") or "").strip() or "Action"


            param = _normalize_ui_text(action_elem.findtext("./params/param") or "")


            actions.append(


                {


                    "id": cmd_type.lower().replace(".", "_"),


                    "name": cmd_type,


                    "value": param,


                    "description": "",


                }


            )


        if not actions:


            actions.append({"id": "none", "name": "Action.None", "value": "", "description": ""})





        phrase_main = ""


        phrase_optional = ""


        for phrase_elem in cmd_elem.findall("phrase"):


            text = _normalize_ui_text(phrase_elem.text or "")


            if not text:


                continue


            optional = str(phrase_elem.attrib.get("optional", "false")).lower() == "true"


            if optional:


                phrase_optional = f"{phrase_optional}, {text}".strip(", ") if phrase_optional else text


            else:


                phrase_main = f"{phrase_main}, {text}".strip(", ") if phrase_main else text





        return {


            "id": cmd_id,


            "name": cmd_name,


            "location": location,


            "confirm": confirm,


            "actions": actions,


            "phrase": phrase_main,


            "optional_phrase": phrase_optional,


        }





    def _walk_group_collection(collection_elem: ET.Element, prefix: list[str]) -> None:


        collection_name = _normalize_ui_text(collection_elem.attrib.get("name") or "")


        base_prefix = prefix + ([collection_name] if collection_name else [])


        if collection_name:


            collection_path = "/".join(base_prefix)


            _register_location(


                collection_path,


                str(collection_elem.attrib.get("open", "true")).lower() == "true",


            )





        def _walk_command_group(group_elem: ET.Element, group_prefix: list[str]) -> None:


            group_name = _normalize_ui_text(group_elem.attrib.get("name") or "") or "Группа"


            location = "/".join(group_prefix + [group_name])


            _register_location(


                location,


                str(group_elem.attrib.get("open", "true")).lower() == "true",


            )





            for cmd_elem in group_elem.findall("command"):


                enabled = str(cmd_elem.attrib.get("enabled", "true")).lower() == "true"


                if not enabled:


                    continue


                parsed = _parse_command(cmd_elem, location)


                if parsed is None:


                    continue


                commands_by_location[location].append(parsed)





            for nested_group in group_elem.findall("commandGroup"):


                _walk_command_group(nested_group, group_prefix + [group_name])





        for command_group in collection_elem.findall("commandGroup"):


            _walk_command_group(command_group, base_prefix)





        for nested_collection in collection_elem.findall("groupCollection"):


            _walk_group_collection(nested_collection, base_prefix)





    for collection in root.findall("groupCollection"):


        _walk_group_collection(collection, [])





    return commands_by_location, open_states, ordered_locations








def load_jarvis_commands_from_xml(xml_path: str | None = None) -> dict[str, list[dict[str, object]]]:


    commands_by_location, _, _ = load_jarvis_command_model(xml_path)


    return commands_by_location





