class StructurePickerDialog(QDialog):

    def __init__(


        self,


        commands: dict[str, list[dict[str, object]]],


        current_location: str,


        parent: QWidget | None = None,


        language_key: object = "Русский",


    ) -> None:

        super().__init__(parent)

        self._language_key = str(language_key).strip() or "Русский"

        self._drag_offset: QPoint | None = None

        self.setProperty("ui", "action_dialog")

        self.setWindowFlags(Qt.Dialog | Qt.FramelessWindowHint)

        self.setAttribute(Qt.WA_TranslucentBackground, False)

        self.setAttribute(Qt.WA_StyledBackground, True)

        self.setWindowTitle("Выбор места сохранения")

        self.setModal(True)

        self.resize(680, 500)




        self._commands = commands


        self._result: str | None = None


        self._path_items: dict[str, QTreeWidgetItem] = {}





        root = QVBoxLayout(self)


        root.setContentsMargins(14, 12, 14, 12)


        root.setSpacing(10)





        header = QHBoxLayout()


        header.addWidget(make_label("ВЫБОР МЕСТА СОХРАНЕНИЯ", "title"))


        header.addStretch()


        close_btn = QPushButton("×")


        close_btn.setProperty("ui", "dialog_close")


        close_btn.setFixedSize(38, 30)


        close_btn.clicked.connect(self.reject)


        header.addWidget(close_btn)


        root.addLayout(header)





        self.tree = QTreeWidget()


        self.tree.setProperty("ui", "command_tree")


        self.tree.setHeaderHidden(True)


        self.tree.setIndentation(18)


        root.addWidget(self.tree, 1)





        controls = QHBoxLayout()


        controls.addStretch()


        cancel_btn = QPushButton("Отмена")


        cancel_btn.setProperty("ui", "action")


        cancel_btn.setFixedSize(124, 38)


        pick_btn = QPushButton("Выбрать")


        pick_btn.setProperty("ui", "action")


        set_active(pick_btn, True)


        pick_btn.setFixedSize(124, 38)


        controls.addWidget(cancel_btn)


        controls.addWidget(pick_btn)


        root.addLayout(controls)





        cancel_btn.clicked.connect(self.reject)


        pick_btn.clicked.connect(self._accept_selected)


        self.tree.itemDoubleClicked.connect(lambda *_: self._accept_selected())


        self._build_tree()


        self._select_current(current_location)


        self.apply_language(self._language_key)





    def _ensure_path_item(self, location: str) -> QTreeWidgetItem:


        parts = [part.strip() for part in location.split("/") if part.strip()]


        current_path = ""


        parent_item: QTreeWidgetItem | None = None


        for part in parts:


            current_path = part if not current_path else f"{current_path}/{part}"


            existing = self._path_items.get(current_path)


            if existing is not None:


                parent_item = existing


                continue


            item = QTreeWidgetItem([part])


            item.setData(0, Qt.UserRole, current_path)


            if parent_item is None:


                self.tree.addTopLevelItem(item)


            else:


                parent_item.addChild(item)


            self._path_items[current_path] = item


            parent_item = item


        if parent_item is None:


            parent_item = QTreeWidgetItem([location_label(location)])


            parent_item.setData(0, Qt.UserRole, location)


            self.tree.addTopLevelItem(parent_item)


            self._path_items[location] = parent_item


        return parent_item





    def _build_tree(self) -> None:


        self.tree.clear()


        self._path_items.clear()





        for location in self._commands.keys():


            if not isinstance(location, str) or not location.strip():


                continue


            path_item = self._ensure_path_item(location)


            for cmd in self._commands.get(location, []):


                if not isinstance(cmd, dict):


                    continue


                label = str(cmd.get("name", "")).strip() or _pick_language_text(


                    self._language_key,


                    "Новая команда",


                    "New command",


                    "Нова команда",


                )


                leaf = QTreeWidgetItem([f"  • {label}"])


                leaf.setData(0, Qt.UserRole, None)


                leaf.setFlags(leaf.flags() & ~Qt.ItemIsSelectable)


                path_item.addChild(leaf)





        for i in range(self.tree.topLevelItemCount()):


            self.tree.topLevelItem(i).setExpanded(True)





    def _select_current(self, location: str) -> None:


        target = location.strip()


        if not target:


            return





        def _walk(item: QTreeWidgetItem) -> QTreeWidgetItem | None:


            data = item.data(0, Qt.UserRole)


            if isinstance(data, str) and data == target:


                return item


            for i in range(item.childCount()):


                found = _walk(item.child(i))


                if found is not None:


                    return found


            return None





        for i in range(self.tree.topLevelItemCount()):


            found = _walk(self.tree.topLevelItem(i))


            if found is not None:


                self.tree.setCurrentItem(found)


                break





    def _accept_selected(self) -> None:


        item = self.tree.currentItem()


        if item is None:


            return


        value = item.data(0, Qt.UserRole)


        if not isinstance(value, str):


            return


        self._result = value


        self.accept()





    def selected_location(self) -> str | None:


        return self._result





    def apply_language(self, language_key: object) -> None:


        self._language_key = str(language_key).strip() or "Русский"


        text_map = {


            "ВЫБОР МЕСТА СОХРАНЕНИЯ": "SAVE LOCATION",


            "Отмена": "Cancel",


            "Выбрать": "Select",


        }


        text_map_uk = {


            "ВЫБОР МЕСТА СОХРАНЕНИЯ": "ВИБІР МІСЦЯ ЗБЕРЕЖЕННЯ",


            "Отмена": "Скасувати",


            "Выбрать": "Вибрати",


        }


        _translate_widget_tree(self, self._language_key, text_map, None, None, text_map_uk)

        self.setWindowTitle(

            _pick_language_text(self._language_key, "Выбор места сохранения", "Save location", "Вибір місця збереження")

        )



    def mousePressEvent(self, event) -> None:

        if event.button() == Qt.LeftButton:

            pos = event.position().toPoint()

            if pos.y() <= 56 and not _is_interactive_drag_widget(self.childAt(pos)):

                self._drag_offset = event.globalPosition().toPoint() - self.frameGeometry().topLeft()

                event.accept()

                return

        self._drag_offset = None

        super().mousePressEvent(event)



    def mouseMoveEvent(self, event) -> None:

        if self._drag_offset is not None and (event.buttons() & Qt.LeftButton):

            self.move(event.globalPosition().toPoint() - self._drag_offset)

            event.accept()

            return

        super().mouseMoveEvent(event)



    def mouseReleaseEvent(self, event) -> None:

        self._drag_offset = None

        super().mouseReleaseEvent(event)



    def resizeEvent(self, event) -> None:

        super().resizeEvent(event)

        _apply_rounded_window_mask(self, 14)



    def paintEvent(self, event) -> None:

        painter = QPainter(self)

        painter.setRenderHint(QPainter.Antialiasing, True)

        rect = QRectF(self.rect()).adjusted(0.5, 0.5, -0.5, -0.5)

        path = QPainterPath()

        path.addRoundedRect(rect, 14.0, 14.0)

        painter.fillPath(path, QColor(2, 4, 8, 236))

        painter.setPen(QPen(QColor(24, 34, 48, 242), 1.0))

        painter.drawPath(path)

        painter.end()

        super().paintEvent(event)





class ConfirmSideSquares(QWidget):

    def __init__(self, parent: QWidget | None = None) -> None:

        super().__init__(parent)

        self.setAttribute(Qt.WA_TransparentForMouseEvents, True)

        self.setAttribute(Qt.WA_NoSystemBackground, True)

        self.setFixedSize(96, 112)



    def paintEvent(self, event) -> None:

        painter = QPainter(self)

        painter.setRenderHint(QPainter.Antialiasing, True)

        painter.setPen(Qt.NoPen)

        layers = [

            (QColor(41, 61, 138, 52), QRectF(-36, 6, 84, 98), 18.0),

            (QColor(53, 80, 176, 62), QRectF(-26, 16, 74, 84), 16.0),

            (QColor(70, 104, 214, 74), QRectF(-17, 27, 64, 64), 14.0),

            (QColor(88, 128, 252, 86), QRectF(-8, 38, 54, 44), 12.0),

        ]

        for color, rect, radius in layers:

            painter.setBrush(color)

            painter.drawRoundedRect(rect, radius, radius)

        painter.end()





class CommandConfirmDialog(QDialog):

    def __init__(

        self,

        command: dict[str, object],

        phrase: str,

        language_key: object = "Русский",

        timeout_sec: int = 30,

        parent: QWidget | None = None,

    ) -> None:

        super().__init__(parent)

        self._language_key = str(language_key).strip() or "Русский"

        self._command = dict(command or {})

        self._phrase = str(phrase or "").strip()

        self._timeout_sec = max(1, int(timeout_sec))

        self._deadline_ts = time.monotonic() + float(self._timeout_sec)

        self._drag_offset: QPoint | None = None

        self.setProperty("ui", "confirm_dialog")

        self.setWindowFlags(Qt.Dialog | Qt.FramelessWindowHint)

        self.setAttribute(Qt.WA_TranslucentBackground, False)

        self.setAttribute(Qt.WA_StyledBackground, True)

        self.setWindowTitle("Подтверждение команды")

        self.setModal(True)

        self.resize(790, 138)



        self._left_squares = ConfirmSideSquares(self)

        self._left_squares.lower()



        root = QVBoxLayout(self)

