def _apply_first_launch_backdrop(widget: QWidget, blur_value: int = 78) -> None:

    if os.name != "nt":

        return

    try:

        hwnd = int(widget.winId())

    except Exception:

        return

    if hwnd <= 0:

        return

    value = max(0, min(100, int(blur_value)))

    try:

        import ctypes

        from ctypes import wintypes



        set_comp = getattr(ctypes.windll.user32, "SetWindowCompositionAttribute", None)

        if set_comp is not None:

            class ACCENT_POLICY(ctypes.Structure):

                _fields_ = [

                    ("AccentState", ctypes.c_int),

                    ("AccentFlags", ctypes.c_int),

                    ("GradientColor", ctypes.c_uint),

                    ("AnimationId", ctypes.c_int),

                ]



            class WINDOWCOMPOSITIONATTRIBDATA(ctypes.Structure):

                _fields_ = [

                    ("Attribute", ctypes.c_int),

                    ("Data", ctypes.c_void_p),

                    ("SizeOfData", ctypes.c_size_t),

                ]



            WCA_ACCENT_POLICY = 19

            ACCENT_DISABLED = 0

            ACCENT_ENABLE_BLURBEHIND = 3

            ACCENT_ENABLE_ACRYLICBLURBEHIND = 4

            policy = ACCENT_POLICY()

            if value <= 0:

                policy.AccentState = ACCENT_DISABLED

                policy.GradientColor = 0

            else:

                policy.AccentState = ACCENT_ENABLE_ACRYLICBLURBEHIND if value >= 1 else ACCENT_ENABLE_BLURBEHIND

                policy.AccentFlags = 2

                tint = QColor("#06080d")

                tint_alpha = max(10, min(180, 176 - int(value * 1.50)))

                policy.GradientColor = (

                    (tint_alpha << 24)

                    | (tint.blue() << 16)

                    | (tint.green() << 8)

                    | tint.red()

                )

            data = WINDOWCOMPOSITIONATTRIBDATA(

                WCA_ACCENT_POLICY,

                ctypes.addressof(policy),

                ctypes.sizeof(policy),

            )

            set_comp.argtypes = [wintypes.HWND, ctypes.POINTER(WINDOWCOMPOSITIONATTRIBDATA)]

            set_comp.restype = wintypes.BOOL

            set_comp(wintypes.HWND(hwnd), ctypes.byref(data))



        # Use rounded corners on Windows 11 when available.

        try:

            DWMWA_WINDOW_CORNER_PREFERENCE = 33

            DWMWCP_ROUND = 2

            pref = ctypes.c_int(DWMWCP_ROUND)

            ctypes.windll.dwmapi.DwmSetWindowAttribute(

                wintypes.HWND(hwnd),

                ctypes.c_uint(DWMWA_WINDOW_CORNER_PREFERENCE),

                ctypes.byref(pref),

                ctypes.sizeof(pref),

            )

        except Exception:

            pass

    except Exception:

        pass





class QwenInstallWorker(QThread):

    progress_changed = Signal(int, str)

    finished_install = Signal(bool, str)



    def __init__(self, install_qwen: bool) -> None:

        super().__init__()

        self._install_qwen = bool(install_qwen)



    def run(self) -> None:

        if not self._install_qwen:

            self.progress_changed.emit(100, "Установка компонентов Qwen пропущена.")

            self.finished_install.emit(True, "Компоненты не устанавливались.")

            return



        npm = shutil.which("npm.cmd") or shutil.which("npm")

        if not npm:

            self.finished_install.emit(False, "Не найден npm. Установите Node.js и повторите.")

            return



        cmd = [npm, "install", "-g", "@qwen-code/qwen-code@latest"]

        creation_flags = int(getattr(subprocess, "CREATE_NO_WINDOW", 0))

        self.progress_changed.emit(3, "Подготовка установки Qwen Code...")



        output_tail: list[str] = []

        try:

            process = subprocess.Popen(

                cmd,

                stdout=subprocess.PIPE,

                stderr=subprocess.STDOUT,

                text=True,

                encoding="utf-8",

                errors="ignore",

                creationflags=creation_flags,

            )

        except Exception as exc:

            self.finished_install.emit(False, f"Ошибка запуска установки: {exc}")

            return



        progress = 6

        try:

            while True:

                if self.isInterruptionRequested():

                    try:

                        process.terminate()

                    except Exception:

                        pass

                    self.finished_install.emit(False, "Установка прервана пользователем.")

                    return



                line = process.stdout.readline() if process.stdout is not None else ""

                if not line:

                    if process.poll() is not None:

                        break

                    self.msleep(80)

                    continue



                text = _normalize_ui_text(line).strip()

                if text:

                    output_tail.append(text)

                    if len(output_tail) > 10:

                        output_tail.pop(0)

                    progress = min(95, progress + 1)

                    self.progress_changed.emit(progress, text)

        except Exception:

            pass



        try:

            return_code = int(process.wait(timeout=20))

        except Exception:

            return_code = -1



        if return_code == 0:

            self.progress_changed.emit(100, "Qwen Code успешно установлен.")

            self.finished_install.emit(True, "Установка завершена.")

            return



        tail = " | ".join(output_tail[-3:]).strip()

        if tail:

            self.finished_install.emit(False, f"Установка завершилась с ошибкой: {tail}")

        else:

            self.finished_install.emit(False, "Установка завершилась с ошибкой. Повторите позже.")





