    @staticmethod
    def _normalize_presentation_style(value: object) -> str:

        raw = str(value or "").strip().lower()

        if raw in {"style1", "style_1", "modern", "modern_dark", "dark", "темный", "темний"}:

            return "modern_dark"

        if raw in {"style2", "style_2", "light", "clean_light", "corporate", "корпоративный", "корпоративний"}:

            return "clean_light"

        if raw in {"style3", "style_3", "infographic", "infographics", "infographic_focus", "инфографика", "інфографіка"}:

            return "infographic_focus"

        if raw in {"style4", "style_4", "aqua", "aqua_cards", "aqua_minimal", "mint"}:

            return "aqua_cards"

        if raw in {"style5", "style_5", "green", "green_grid", "green_corporate"}:

            return "green_grid"

        return "modern_dark"


