            ("clean_light", _pick_language_text(self._language_key, "Стиль 2: Бело-оранжевый", "Style 2: White-orange", "Стиль 2: Біло-помаранчевий")),

            ("infographic_focus", _pick_language_text(self._language_key, "Стиль 3: Темный инфографика", "Style 3: Dark infographic", "Стиль 3: Темна інфографіка")),

            ("aqua_cards", _pick_language_text(self._language_key, "Стиль 4: Светлый аква", "Style 4: Aqua cards", "Стиль 4: Світлий аква")),

            ("green_grid", _pick_language_text(self._language_key, "Стиль 5: Серо-зеленый", "Style 5: Gray-green", "Стиль 5: Сіро-зелений")),

