    def _try_execute_builtin_keyboard_command(self, phrase: str) -> str:

        candidates = self._builtin_phrase_candidates(phrase)

        if not candidates:

            return ""

        enter_triggers = {
            "энтер",
            "энтэр",
            "ентер",
            "enter",
            "return",
            "ввод",
            "клавиша ввод",
            "клавиша enter",
            "клавиша энтер",
            "нажми enter",
            "нажми энтер",
            "нажми энтэр",
            "нажми ввод",
            "нажать enter",
            "нажать энтер",
            "нажать ввод",
            "нажми клавишу enter",
            "нажми клавишу энтер",
            "нажми клавишу ввод",
            "press enter",
            "press return",
            "send enter",
        }

        enter_action_tokens = {"нажми", "нажать", "жми", "клавиша", "кнопка", "press", "send", "hit"}
        enter_key_tokens = {"энтер", "энтэр", "ентер", "enter", "return", "ввод"}

        for candidate in candidates:

            text = str(candidate or "").strip()

            if not text:

                continue

            tokens = {token for token in text.split() if token}

            is_enter = text in enter_triggers

            if not is_enter and tokens.intersection(enter_key_tokens):

                if len(tokens) <= 4 and (
                    tokens.intersection(enter_action_tokens)
                    or tokens.issubset(enter_key_tokens)
                ):

                    is_enter = True

            if not is_enter:

                continue

            ok = self._send_keys("{ENTER}")

            if not ok:

                return _pick_language_text(
                    self._settings.get("interface_language", "Русский"),
                    "Не удалось нажать Enter.",
                    "Failed to press Enter.",
                    "Не вдалося натиснути Enter.",
                )

            return _pick_language_text(
                self._settings.get("interface_language", "Русский"),
                "Нажимаю Enter.",
                "Pressing Enter.",
                "Натискаю Enter.",
            )

        return ""



    @staticmethod
    def _presentation_ole_rgb(r: int, g: int, b: int) -> int:
        rr = max(0, min(255, int(r)))
        gg = max(0, min(255, int(g)))
        bb = max(0, min(255, int(b)))
        return rr + (gg << 8) + (bb << 16)


    @staticmethod
    def _presentation_safe_filename(raw_value: object, fallback: str = "presentation") -> str:
        text = _normalize_ui_text(raw_value).strip()
        clean = re.sub(r"[\\/:*?\"<>|]+", " ", text)
        clean = re.sub(r"\s+", " ", clean).strip(" .-_")
        if not clean:
            clean = fallback
        clean = clean[:96].strip(" .-_")
        return clean or fallback

    @staticmethod
    def _presentation_text_quality_score(value: str) -> float:
        text = str(value or "").strip()
        if not text:
            return -10_000.0
        letters = sum(1 for ch in text if ch.isalpha())
        digits = sum(1 for ch in text if ch.isdigit())
        spaces = sum(1 for ch in text if ch.isspace())
        cyr = sum(1 for ch in text if "\u0400" <= ch <= "\u04FF")
        latin = sum(1 for ch in text if ("a" <= ch.lower() <= "z"))
        vowels = sum(
            1
            for ch in text.casefold()
            if ch in {"а", "е", "ё", "и", "о", "у", "ы", "э", "ю", "я", "і", "ї", "є", "a", "e", "i", "o", "u", "y"}
        )
        mojibake_pairs = len(re.findall(r"[РС][\u0400-\u04ff]", text))
        bad_marks = text.count("�")
        odd_question_runs = len(re.findall(r"\?{3,}", text))
        quality = (letters * 1.35) + (digits * 0.25) + (spaces * 0.1) + (vowels * 0.3)
        quality += (cyr * 0.25) + (latin * 0.18)
        quality -= (mojibake_pairs * 2.2) + (bad_marks * 4.0) + (odd_question_runs * 3.5)
        return float(quality)

    def _presentation_fix_text(self, value: object, max_len: int = 0) -> str:
        base = html.unescape(str(value or "")).replace("\xa0", " ")
        base = re.sub(r"\s+", " ", base).strip()
        if not base:
            return ""
        variants: list[str] = [base]
        seen: set[str] = {base}
        decode_pairs = (
            ("cp1251", "utf-8"),
            ("cp866", "utf-8"),
            ("latin1", "utf-8"),
            ("cp1251", "cp866"),
            ("cp866", "cp1251"),
        )
        for _ in range(2):
            snapshot = list(variants)
            for candidate in snapshot:
                for src_enc, dst_enc in decode_pairs:
                    try:
                        fixed = candidate.encode(src_enc, errors="ignore").decode(dst_enc, errors="ignore")
                    except Exception:
                        continue
                    fixed = re.sub(r"\s+", " ", fixed).strip()
                    if not fixed or fixed in seen:
                        continue
                    seen.add(fixed)
                    variants.append(fixed)
        best = max(variants, key=self._presentation_text_quality_score)
        best = re.sub(r"\s+", " ", best).strip()
        if int(max_len) > 0 and len(best) > int(max_len):
            best = best[: max(16, int(max_len) - 1)].rstrip(" ,;:-") + "…"
        return best


    def _extract_presentation_topic_from_phrase(self, phrase: str) -> tuple[bool, str]:
        variants: list[str] = []
        raw_text = self._presentation_fix_text(phrase)
        if raw_text:
            variants.append(raw_text)
        for candidate in self._builtin_phrase_candidates(phrase):
            item = self._presentation_fix_text(candidate)
            if item and item not in variants:
                variants.append(item)
        if not variants:
            return False, ""

        patterns = (
            r"^/?(?:презентац(?:ия|ию)|presentation)\s*(?:\+|:|-)?\s*(.*)$",
            r"^/?(?:презентац(?:ию|ия)|presentation)\s+(?:на\s+тему|про|about|on)\s*(.*)$",
            r"^/?(?:сделай|создай|подготовь|сгенерируй|make|create|generate)\s+(?:мне\s+)?(?:презентац(?:ию|ия)|presentation)\s*(?:на\s+тему|про|about|on)?\s*(.*)$",
        )
        for text in variants:
            stripped = text.strip()
            for pattern in patterns:
                match = re.match(pattern, stripped, flags=re.IGNORECASE)
                if match is None:
                    continue
                topic = self._presentation_fix_text(match.group(1), max_len=140).strip(" .,!?:;+-")
                topic = re.sub(r"\s+", " ", topic).strip()
                if topic:
                    return True, topic
                return True, ""
            lowered = stripped.casefold()
            if lowered in {
                "презентация",
                "presentation",
                "презентацию",
                "презентация+",
                "/презентация",
                "/presentation",
                "/презентацию",
                "/презентация+",
            }:
                return True, ""
        return False, ""


