    def _presentation_query_variants(self, topic: str) -> list[str]:
        topic = self._presentation_fix_text(topic, max_len=140) or str(topic or "").strip()
        lang = self._ui_language_family()
        topic_roots = self._presentation_topic_roots(topic)

        if lang == "en":
            variants = [
                topic,
                f"{topic} overview",
                f"{topic} history",
                f"{topic} applications",
                f"{topic} advantages",
                f"{topic} risks",
                f"{topic} future trends",
            ]
        elif lang == "uk":
            variants = [
                topic,
                f"{topic} огляд",
                f"{topic} історія",
                f"{topic} застосування",
                f"{topic} переваги",
                f"{topic} ризики",
                f"{topic} майбутні тренди",
            ]
        else:
            variants = [
                topic,
                f"{topic} обзор",
                f"{topic} история",
                f"{topic} применение",
                f"{topic} преимущества",
                f"{topic} риски",
                f"{topic} тренды",
            ]

        if "квант" in topic_roots or "quant" in topic_roots:
            variants.extend(
                [
                    "квантовый компьютер",
                    "квантовые вычисления",
                    "quantum computing",
                    "quantum computer",
                ]
            )
        if "ветер" in topic or "ветр" in topic or "wind" in topic_roots:
            variants.extend(
                [
                    "ветроэнергетика",
                    "ветровая турбина",
                    "ветроэлектростанция",
                    "wind power",
                    "wind turbine",
                    "wind farm",
                ]
            )
        if "кибер" in topic_roots or "cyber" in topic_roots or "secur" in topic_roots:
            variants.extend(
                [
                    "информационная безопасность банков",
                    "компьютерная безопасность банков",
                    "банковская кибербезопасность",
                    "banking cybersecurity",
                    "bank information security",
                    "financial cybersecurity",
                ]
            )
        if "банк" in topic_roots or "bank" in topic_roots:
            variants.extend(
                [
                    "банковская безопасность",
                    "безопасность платежных систем",
                    "payment security in banking",
                ]
            )

        deduped: list[str] = []
        seen: set[str] = set()
        for item in variants:
            q = self._presentation_fix_text(item, max_len=140).strip()
            if not q:
                continue
            key = q.casefold()
            if key in seen:
                continue
            seen.add(key)
            deduped.append(q)
            if len(deduped) >= 14:
                break
        return deduped


    @staticmethod
    def _presentation_stop_words() -> set[str]:
        return {
            "about",
            "also",
            "because",
            "from",
            "that",
            "this",
            "with",
            "what",
            "when",
            "where",
            "which",
            "will",
            "have",
            "как",
            "или",
            "для",
            "про",
            "что",
            "это",
            "эта",
            "эти",
            "темы",
            "тема",
            "обзор",
            "история",
            "пример",
            "примеры",
            "чому",
            "огляд",
            "історія",
            "теми",
            "на",
            "the",
            "and",
            "for",
        }

    def _presentation_topic_parts(self, value: object) -> list[str]:
        text = _normalize_ui_text(value).casefold()
        text = re.sub(r"[^a-zа-яіїєґ0-9\s]+", " ", text)
        tokens = [tok.strip() for tok in text.split() if len(tok.strip()) >= 2]
        if not tokens:
            return []
        stop_words = self._presentation_stop_words()
        base_parts = [tok for tok in tokens if tok not in stop_words]
        enriched: list[str] = []
        for token in base_parts:
            if token not in enriched:
                enriched.append(token)
            if "безопас" in token and "безопасность" not in enriched:
                enriched.append("безопасность")
            if token.startswith("кибер") and "кибер" not in enriched:
                enriched.append("кибер")
            if token.startswith("ветро") and "ветер" not in enriched:
                enriched.append("ветер")
            if token.startswith("компьют") and "компьютер" not in enriched:
                enriched.append("компьютер")
            if token.startswith("бан") and "банк" not in enriched:
                enriched.append("банк")
        return enriched

    @staticmethod
    def _presentation_token_root(token: str) -> str:
        normalized = re.sub(r"[^a-zа-яіїєґ0-9]+", "", str(token or "").casefold())
        if not normalized:
            return ""
        if len(normalized) <= 5:
            return normalized
        return normalized[:5]

    def _presentation_topic_roots(self, value: object) -> set[str]:
        parts = self._presentation_topic_parts(value)
        roots = {self._presentation_token_root(tok) for tok in parts}
        roots = {root for root in roots if root}
        text = " ".join(parts)
        if "квант" in text:
            roots.add("quant")
        if "компьют" in text:
            roots.add("compu")
        if "ветр" in text:
            roots.add("wind")
        if "энерг" in text:
            roots.add("energ")
        if "кибер" in text:
            roots.add("cyber")
        if "безопас" in text or "security" in text:
            roots.add("secur")
        if "банк" in text:
            roots.add("bank")
        if "искус" in text and "интел" in text:
            roots.add("artif")
            roots.add("intel")
        if "медиц" in text:
            roots.add("medic")
        return roots

    def _presentation_topic_tokens(self, value: object) -> set[str]:
        return set(self._presentation_topic_parts(value))


    def _presentation_relevance_score(self, topic: str, title: object, summary: object) -> float:
        topic_tokens = self._presentation_topic_tokens(topic)
        topic_roots = self._presentation_topic_roots(topic)
        topic_parts = self._presentation_topic_parts(topic)
        anchor_root = self._presentation_token_root(topic_parts[0]) if topic_parts else ""
        topic_low = self._presentation_fix_text(topic).casefold().strip()
        title_text = self._presentation_fix_text(title).strip()
        summary_text = self._presentation_fix_text(summary).strip()
        full_text = f"{title_text} {summary_text}".casefold()
        title_ratio = difflib.SequenceMatcher(None, topic_low, title_text.casefold()).ratio() if topic_low else 0.0
        title_roots = self._presentation_topic_roots(title_text)
        summary_roots = self._presentation_topic_roots(summary_text)
        root_overlap_title = len(topic_roots & title_roots)
        root_overlap_summary = len(topic_roots & summary_roots)
        anchor_ok = bool(anchor_root and (anchor_root in title_roots or anchor_root in summary_roots))
        if not topic_tokens:
            phrase_bonus = 0.9 if topic_low and topic_low in full_text else 0.0
            return (title_ratio * 1.65) + phrase_bonus + (root_overlap_title * 0.8) + (root_overlap_summary * 0.4)

        title_tokens = self._presentation_topic_tokens(title_text)
        summary_tokens = self._presentation_topic_tokens(summary_text)

        title_overlap = len(topic_tokens & title_tokens)
        summary_overlap = len(topic_tokens & summary_tokens)

        exact_phrase_bonus = 1.25 if topic_low and topic_low in full_text else 0.0
        anchor_bonus = 1.05 if anchor_ok else -0.95

        return (
            (title_overlap * 2.6)
            + (summary_overlap * 1.5)
            + (root_overlap_title * 2.1)
            + (root_overlap_summary * 0.95)
            + exact_phrase_bonus
            + (title_ratio * 1.25)
            + anchor_bonus
        )

    @staticmethod
    def _presentation_is_low_info_summary(value: object) -> bool:
        text = str(value or "").strip().casefold()
        if not text:
            return True
        bad_fragments = (
            "точный ответ не найден",
            "could not find a clear answer",
            "could not find",
            "не удалось получить",
            "failed to fetch",
            "уточните вопрос",
            "уточните запрос",
            "refine the question",
        )
        if any(fragment in text for fragment in bad_fragments):
            return True
        letters = sum(1 for ch in text if ch.isalpha())
        return letters < 24


    def _presentation_clean_bullets(self, bullets: object, max_items: int, max_chars: int = 132) -> list[str]:
        rows: list[str] = []
        seen: set[str] = set()
        if not isinstance(bullets, list):
            return rows
        for raw in bullets:
            line = self._presentation_fix_text(raw).strip(" -•\t\r\n")
            line = re.sub(r"\s+", " ", line).strip()
            if len(line) < 10:
                continue
            if len(line) > int(max_chars):
                line = line[: max(20, int(max_chars) - 1)].rstrip(" ,;:-") + "…"
            key = line.casefold()
            if key in seen:
                continue
            seen.add(key)
            rows.append(line)
            if len(rows) >= max(1, int(max_items)):
                break
        return rows


    @staticmethod
    def _presentation_slide_signature(title: object, bullets: list[str]) -> str:
        head = _normalize_ui_text(title).casefold().strip()
        first = _normalize_ui_text(bullets[0]).casefold().strip() if bullets else ""
        return f"{head}::{first}"


    @staticmethod
    def _presentation_compact_text(value: object, max_len: int = 220) -> str:
        text = _normalize_ui_text(value).casefold()
        text = re.sub(r"[^a-zа-яіїєґ0-9\s]+", " ", text)
        text = re.sub(r"\s+", " ", text).strip()
        if len(text) > int(max_len):
            return text[: int(max_len)].strip()
        return text


    def _presentation_is_near_duplicate(self, candidate: object, existing_rows: list[str], threshold: float = 0.86) -> bool:
        cand = self._presentation_compact_text(candidate)
        if not cand:
            return True
        cand_tokens = set(cand.split())
        for row in existing_rows:
            ref = self._presentation_compact_text(row)
            if not ref:
                continue
            if cand == ref:
                return True
            ratio = difflib.SequenceMatcher(None, cand, ref).ratio()
            if ratio >= float(threshold):
                return True
            if len(cand) >= 28 and len(ref) >= 28 and (cand in ref or ref in cand):
                return True
            ref_tokens = set(ref.split())
            if cand_tokens and ref_tokens:
                inter = len(cand_tokens & ref_tokens)
                union = len(cand_tokens | ref_tokens)
                if union > 0 and (inter / union) >= 0.74:
                    return True
        return False


    @staticmethod
    def _presentation_sentence_chunks(value: object, max_chars: int = 180) -> list[str]:
        text = re.sub(r"\s+", " ", str(value or "").replace("\n", " ")).strip()
        if not text:
            return []

        parts = re.split(r"(?<=[.!?])\s+", text)
        chunks: list[str] = []
        seen: set[str] = set()
        for raw in parts:
            cleaned = re.sub(r"\s+", " ", str(raw or "")).strip(" -•\t\r\n")
            cleaned = cleaned.strip("«»\"' ")
            if len(cleaned) < 14:
                continue
            if len(cleaned) > int(max_chars):
                cleaned = cleaned[: max(10, int(max_chars) - 1)].rstrip(" ,;:-") + "…"
            key = cleaned.casefold()
            if key in seen:
                continue
            seen.add(key)
            chunks.append(cleaned)

        if chunks:
            return chunks

        fallback = text
        if len(fallback) > int(max_chars):
            fallback = fallback[: max(10, int(max_chars) - 1)].rstrip(" ,;:-") + "…"
        return [fallback] if fallback else []


    def _presentation_bullets_from_summary(self, summary: object, limit: int = 4) -> list[str]:
        chunks = self._presentation_sentence_chunks(summary, max_chars=165)
        return self._presentation_clean_bullets(chunks, max_items=max(1, int(limit)), max_chars=158)


    def _presentation_collect_wikipedia_materials(self, topic: str, max_items: int = 6) -> list[dict[str, object]]:
        topic = self._presentation_fix_text(topic, max_len=140) or str(topic or "").strip()
        lang = self._ui_language_family()
        if lang == "en":
            lang_order = ["en", "ru"]
        elif lang == "uk":
            lang_order = ["uk", "ru", "en"]
        else:
            lang_order = ["ru", "en"]

        materials: list[dict[str, object]] = []
        seen_titles: set[str] = set()
        seen_signatures: set[str] = set()
        seen_summaries: list[str] = []
        query_variants = self._presentation_query_variants(topic)
        topic_tokens = self._presentation_topic_tokens(topic)
        topic_roots = self._presentation_topic_roots(topic)
        topic_parts = self._presentation_topic_parts(topic)
        topic_token_count = len(topic_tokens)
        if topic_token_count <= 0:
            min_relevance = 1.25
        elif topic_token_count == 1:
            min_relevance = 1.40
        else:
            min_relevance = 1.15

        query_limit = min(len(query_variants), max(6, min(10, int(max_items) + 2)))
        for q_index, raw_query in enumerate(query_variants[:query_limit]):
            query = self._presentation_fix_text(raw_query, max_len=140).strip()
            if not query:
                continue

            payload_candidates: list[dict[str, object]] = []
            for wiki_lang in lang_order:
                try:
                    wiki_take = 2 if q_index < 5 else 1
                    items = self._fetch_wikipedia_candidates(query, wiki_lang, max_results=wiki_take)
                except Exception:
                    items = []
                if isinstance(items, list):
                    for item in items:
                        if isinstance(item, dict) and str(item.get("summary", "")).strip():
                            payload_candidates.append(item)
            if not payload_candidates:
                try:
                    ddg_item = self._fetch_duckduckgo_answer(query)
                except Exception:
                    ddg_item = None
                if isinstance(ddg_item, dict) and str(ddg_item.get("summary", "")).strip():
                    payload_candidates.append(ddg_item)

            if not payload_candidates:
                continue

            try:
                payload_candidates.sort(key=lambda item: float(item.get("relevance_score", 0.0) or 0.0), reverse=True)
            except Exception:
                pass

            for payload in payload_candidates:
                title = self._presentation_fix_text(payload.get("title", ""), max_len=140).strip() or query
                title_key = title.casefold()
                if title_key in seen_titles:
                    continue

                summary = self._presentation_fix_text(payload.get("summary", ""), max_len=1100).strip()
                if self._presentation_is_low_info_summary(summary):
                    continue
                relevance = self._presentation_relevance_score(topic, title, summary)
                if relevance < min_relevance:
                    continue
                full_text = f"{title} {summary}".casefold()
                title_roots = self._presentation_topic_roots(title)
                title_summary_roots = self._presentation_topic_roots(f"{title} {summary}")
                shared_roots = len(topic_roots & title_summary_roots)
                phrase_hit = bool(topic and topic.casefold() in full_text)
                if len(topic_parts) >= 2:
                    needed_shared = 2
                    if (not phrase_hit) and shared_roots < needed_shared:
                        continue
                elif len(topic_parts) == 1 and topic_roots and shared_roots <= 0:
                    continue

                needs_wind_focus = bool("wind" in topic_roots)
                has_wind_in_title = bool(
                    ("wind" in title_roots)
                    or any(str(root).startswith("ветр") for root in title_roots)
                )
                if needs_wind_focus and (not has_wind_in_title):
                    continue

                needs_bank_security_focus = bool(("bank" in topic_roots) and (("cyber" in topic_roots) or ("secur" in topic_roots)))
                if needs_bank_security_focus:
                    has_bank = bool("bank" in title_summary_roots or "банк" in title_summary_roots)
                    has_security = bool(
                        ("secur" in title_summary_roots)
                        or ("cyber" in title_summary_roots)
                        or ("безоп" in title_summary_roots)
                        or ("кибер" in title_summary_roots)
                    )
                    if not has_security:
                        continue
                    if (not has_bank) and relevance < 9.2:
                        continue

                needs_quantum_compute_focus = bool(("quant" in topic_roots) and (("compu" in topic_roots) or ("компь" in topic_roots)))
                if needs_quantum_compute_focus:
                    has_quant = bool(("quant" in title_summary_roots) or ("квант" in title_summary_roots))
                    has_compute = bool(
                        ("compu" in title_summary_roots)
                        or ("компь" in title_summary_roots)
                        or ("вычис" in title_summary_roots)
                    )
                    if not (has_quant and has_compute):
                        if not (has_quant and relevance >= 11.5):
                            continue

                if self._presentation_is_near_duplicate(summary, seen_summaries, threshold=0.84):
                    continue

                bullets = self._presentation_bullets_from_summary(summary, limit=4)
                if len(bullets) < 3:
                    title_hint = self._presentation_fix_text(title, max_len=120)
                    if title_hint:
                        bullets.append(title_hint)
                bullets = self._presentation_clean_bullets(bullets, max_items=4, max_chars=150)
                if not bullets:
                    continue

                source_url = str(payload.get("source_url", "") or "").strip()
                image_url = str(payload.get("image_url", "") or "").strip()
                raw_bytes = payload.get("image_bytes", b"")
                if isinstance(raw_bytes, (bytes, bytearray)):
                    image_bytes = bytes(raw_bytes)
                else:
                    image_bytes = b""

                wiki_lang = str(payload.get("wiki_lang", "") or "").strip().lower()
                if not image_url and wiki_lang:
                    try:
                        image_url = self._fetch_wikipedia_thumbnail(title, wiki_lang)
                    except Exception:
                        image_url = ""
                if not image_url:
                    try:
                        image_url = self._fetch_wikipedia_thumbnail(title, lang_order[0])
                    except Exception:
                        image_url = ""
                if image_url and not image_bytes:
                    try:
                        image_bytes = self._fetch_image_bytes(image_url, timeout_sec=2.8)
                    except Exception:
                        image_bytes = b""

                signature = self._presentation_slide_signature(title, bullets)
                if signature in seen_signatures:
                    continue

                seen_titles.add(title_key)
                seen_signatures.add(signature)
                seen_summaries.append(summary)
                materials.append(
                    {
                        "title": title,
                        "summary": summary,
                        "bullets": bullets,
                        "source": str(payload.get("source", "Wikipedia") or "Wikipedia"),
                        "source_url": source_url,
                        "image_url": image_url,
                        "image_bytes": image_bytes,
                        "relevance_score": float(relevance),
                        "wiki_lang": wiki_lang,
                    }
                )

                if len(materials) >= max(1, int(max_items)):
                    break
            if len(materials) >= max(1, int(max_items)):
                break

        return materials


    def _presentation_outline_from_materials(self, topic: str, materials: list[dict[str, object]]) -> dict[str, object]:
        topic = self._presentation_fix_text(topic, max_len=140) or str(topic or "").strip()
        fallback = self._presentation_default_outline(topic)
        if not materials:
            return fallback

        lang = self._ui_language_family()
        subtitle = str(fallback.get("subtitle", "") or "")
        source_labels = {
            str(item.get("source", "") or "").strip()
            for item in materials
            if str(item.get("source", "") or "").strip()
        }
        has_non_wiki_source = any("wikipedia" not in label.casefold() for label in source_labels)
        source_caption = (
            _pick_language_text(
                self._settings.get("interface_language", "Русский"),
                "Интернет-источники",
                "Web sources",
                "Інтернет-джерела",
            )
            if has_non_wiki_source
            else "Wikipedia"
        )
        subtitle = f"{subtitle} • {source_caption}" if subtitle else source_caption
        slides: list[dict[str, object]] = []
        ranked_materials = list(materials)
        bullet_memory: list[str] = []
        try:
            ranked_materials.sort(key=lambda item: float(item.get("relevance_score", 0.0) or 0.0), reverse=True)
        except Exception:
            pass

        if lang == "en":
            intro_title = "Topic snapshot"
            insight_title = "Key takeaways"
            sources_title = "Sources"
            source_prefix = "Source"
            source_note_default = "Open links on this slide for detailed sources."
        elif lang == "uk":
            intro_title = "Коротко про тему"
            insight_title = "Ключові висновки"
            sources_title = "Джерела"
            source_prefix = "Джерело"
            source_note_default = "Відкрийте посилання на цьому слайді для детальної перевірки."
        else:
            intro_title = "Кратко о теме"
            insight_title = "Ключевые выводы"
            sources_title = "Источники"
            source_prefix = "Источник"
            source_note_default = "Откройте ссылки на этом слайде для проверки деталей."

        head = ranked_materials[0]
        intro_bullets: list[str] = []
        intro_seen: set[str] = set()
        for item in ranked_materials[:5]:
            row = ""
            bullets_raw = item.get("bullets", [])
            if isinstance(bullets_raw, list) and bullets_raw:
                row = self._presentation_fix_text(bullets_raw[0], max_len=160).strip()
            if not row:
                row = self._presentation_fix_text(item.get("title", ""), max_len=160).strip()
            row = re.sub(r"\s+", " ", row).strip(" -•\t")
            if not row:
                continue
            key = row.casefold()
            if key in intro_seen:
                continue
            intro_seen.add(key)
            if len(row) > 145:
                row = row[:142].rstrip(" ,;:-") + "…"
            intro_bullets.append(row)
            if len(intro_bullets) >= 4:
                break
        if not intro_bullets:
            intro_bullets = self._presentation_clean_bullets(head.get("bullets", []), max_items=4, max_chars=145)
        intro_unique: list[str] = []
        for row in intro_bullets:
            if self._presentation_is_near_duplicate(row, bullet_memory, threshold=0.86):
                continue
            intro_unique.append(row)
            bullet_memory.append(row)
            if len(intro_unique) >= 4:
                break
        intro_bullets = intro_unique or intro_bullets[:2]
        if len(intro_bullets) < 3:
            fallback_slides = fallback.get("slides", [])
            if isinstance(fallback_slides, list):
                for fallback_row in fallback_slides[:3]:
                    if not isinstance(fallback_row, dict):
                        continue
                    fallback_bullets = self._presentation_clean_bullets(fallback_row.get("bullets", []), max_items=4, max_chars=145)
                    for bullet in fallback_bullets:
                        if self._presentation_is_near_duplicate(bullet, intro_bullets, threshold=0.84):
                            continue
                        intro_bullets.append(bullet)
                        if len(intro_bullets) >= 3:
                            break
                    if len(intro_bullets) >= 3:
                        break

        head_source_url = str(head.get("source_url", "") or "").strip()
        head_note = f"{source_prefix}: {head_source_url}" if head_source_url else f"{source_prefix}: Wikipedia"
        slides.append(
            {
                "title": intro_title,
                "bullets": intro_bullets,
                "note": head_note,
                "source_url": head_source_url,
                "image_url": str(head.get("image_url", "") or ""),
                "image_bytes": head.get("image_bytes", b""),
            }
        )

        seen_slide_signatures = {self._presentation_slide_signature(intro_title, intro_bullets)}
        for item in ranked_materials:
            title = self._presentation_fix_text(item.get("title", ""), max_len=140).strip() or topic
            raw_bullets = self._presentation_clean_bullets(item.get("bullets", []), max_items=5, max_chars=145)
            bullets: list[str] = []
            for row in raw_bullets:
                if self._presentation_is_near_duplicate(row, bullet_memory, threshold=0.86):
                    continue
                bullets.append(row)
                bullet_memory.append(row)
                if len(bullets) >= 4:
                    break
            if not bullets:
                continue
            slide_signature = self._presentation_slide_signature(title, bullets)
            if slide_signature in seen_slide_signatures:
                continue
            source_url = str(item.get("source_url", "") or "").strip()
            note = f"{source_prefix}: {source_url}" if source_url else f"{source_prefix}: Wikipedia"
            slides.append(
                {
                    "title": title,
                    "bullets": bullets,
                    "note": note,
                    "source_url": source_url,
                    "image_url": str(item.get("image_url", "") or ""),
                    "image_bytes": item.get("image_bytes", b""),
                }
            )
            seen_slide_signatures.add(slide_signature)
            if len(slides) >= 8:
                break

        fact_rows: list[str] = []
        fact_seen: set[str] = set()
        for item in ranked_materials:
            chunks = self._presentation_sentence_chunks(item.get("summary", ""), max_chars=150)
            for chunk in chunks:
                row = self._presentation_fix_text(chunk, max_len=150).strip()
                key = row.casefold()
                if not row or key in fact_seen:
                    continue
                if self._presentation_is_near_duplicate(row, bullet_memory, threshold=0.84):
                    continue
                fact_seen.add(key)
                fact_rows.append(row)
                bullet_memory.append(row)
                if len(fact_rows) >= 5:
                    break
            if len(fact_rows) >= 5:
                break
        if len(fact_rows) >= 3:
            if lang == "en":
                facts_title = "Facts and context"
            elif lang == "uk":
                facts_title = "Факти та контекст"
            else:
                facts_title = "Факты и контекст"
            sig = self._presentation_slide_signature(facts_title, fact_rows)
            if sig not in seen_slide_signatures:
                slides.append({"title": facts_title, "bullets": fact_rows, "note": f"{source_prefix}: Wikipedia"})
                seen_slide_signatures.add(sig)

        insight_bullets: list[str] = []
        insight_seen: set[str] = set()
        for item in ranked_materials[:6]:
            row = ""
            bullets_raw = item.get("bullets", [])
            if isinstance(bullets_raw, list) and len(bullets_raw) > 1:
                row = self._presentation_fix_text(bullets_raw[1], max_len=150).strip()
            elif isinstance(bullets_raw, list) and bullets_raw:
                row = self._presentation_fix_text(bullets_raw[0], max_len=150).strip()
            if not row:
                continue
            key = row.casefold()
            if key in insight_seen:
                continue
            insight_seen.add(key)
            if self._presentation_is_near_duplicate(row, bullet_memory, threshold=0.84):
                continue
            if len(row) > 150:
                row = row[:147].rstrip(" ,;:-") + "…"
            insight_bullets.append(row)
            bullet_memory.append(row)
            if len(insight_bullets) >= 5:
                break
        if insight_bullets:
            sig = self._presentation_slide_signature(insight_title, insight_bullets)
            if sig not in seen_slide_signatures:
                slides.append({"title": insight_title, "bullets": insight_bullets, "note": f"{source_prefix}: Wikipedia"})
                seen_slide_signatures.add(sig)

        source_rows: list[str] = []
        source_links: list[str] = []
        for idx, item in enumerate(ranked_materials, start=1):
            title = self._presentation_fix_text(item.get("title", ""), max_len=140).strip() or f"{idx}"
            source_url = str(item.get("source_url", "") or "").strip()
            source_row = f"{idx}. {title}"
            if len(source_row) > 146:
                source_row = source_row[:143].rstrip(" ,;:-") + "..."
            source_rows.append(source_row)
            if source_url:
                source_links.append(source_url)
            if len(source_rows) >= 8:
                break
        if source_rows:
            note_lines = source_links[:5] if source_links else [source_note_default]
            slides.append(
                {
                    "title": sources_title,
                    "bullets": source_rows,
                    "note": "\n".join(note_lines),
                    "source_url": source_links[0] if source_links else "",
                }
            )

        if len(slides) < 6:
            fallback_payload = fallback.get("slides", [])
            if isinstance(fallback_payload, list):
                for row in fallback_payload:
                    if not isinstance(row, dict):
                        continue
                    candidate_title = self._presentation_fix_text(row.get("title", ""), max_len=140).strip()
                    candidate_bullets = self._presentation_clean_bullets(row.get("bullets", []), max_items=4, max_chars=145)
                    if not candidate_title or not candidate_bullets:
                        continue
                    sig = self._presentation_slide_signature(candidate_title, candidate_bullets)
                    if sig in seen_slide_signatures:
                        continue
                    slides.insert(
                        max(1, len(slides) - 1),
                        {"title": candidate_title, "bullets": candidate_bullets, "note": f"{source_prefix}: {source_caption}"},
                    )
                    seen_slide_signatures.add(sig)
                    if len(slides) >= 6:
                        break

        return {
            "title": str(fallback.get("title", topic) or topic),
            "subtitle": subtitle,
            "slides": slides,
        }


